-- Poems batch 85
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6a60b1e0-9657-42c7-aa3c-1a07a5998ce3','雜感','顧禧','宋','宋诗','song-poetry','','[]','不與漁樵狎，甯知世事非。',48,'全唐诗/poet.song.106000.json','["不與漁樵狎，甯知世事非。", "功成枯戰骨，髪端誤儒衣。", "風雨槐陰夢，倉黄斗柄微。", "東鄰瓜正熟，把酒裛清輝。"]'),
('e5118de7-cd73-45b7-a108-49f781cb5a6f','偶作','顧禧','宋','宋诗','song-poetry','','[]','日暮悲笳起，孤衾入夢寒。',48,'全唐诗/poet.song.106000.json','["日暮悲笳起，孤衾入夢寒。", "沙飛桐鵲隱，草蔓石鯨殘。", "龍戰知何極，烏栖轉未安。", "幽燕多老將，壯氣滿桑乾。"]'),
('ee6e8a3c-c675-4f69-9016-5b7cd11e53f9','野眺  其一','顧禧','宋','宋诗','song-poetry','','[]','遂愜耽幽興，披襟坐水灣。',48,'全唐诗/poet.song.106000.json','["遂愜耽幽興，披襟坐水灣。", "松枯濤不作，鷗澹夢常閑。", "漏月寬樵徑，吞星避釣環。", "年來悲跼蹐，聊此破愁顔。"]'),
('2686689c-ee35-4d6d-a066-c533bfd5078b','野眺  其二','顧禧','宋','宋诗','song-poetry','','[]','一逕多幽色，孤雲護短扉。',48,'全唐诗/poet.song.106000.json','["一逕多幽色，孤雲護短扉。", "閒階竹影瘦，低岸稻花肥。", "委翠秋林晚，傷弓宿鳥稀。", "何時攜斗酒，掬水弄清暉。"]'),
('dabc2d5e-edcd-4cbd-86e5-d51cf441f894','野眺  其三','顧禧','宋','宋诗','song-poetry','','[]','緩步沿溪曲，幽尋愜賞心。',48,'全唐诗/poet.song.106000.json','["緩步沿溪曲，幽尋愜賞心。", "散烟依瘦竹，開網活枯鱘。", "短袖仍牽樹，秋聲半擣砧。", "農談喧隔岸，不畏世機深。"]'),
('50c2e23d-00f0-4290-be85-6cb2202c3427','野眺  其四','顧禧','宋','宋诗','song-poetry','','[]','亂世功名易，幽人愧素餐。',48,'全唐诗/poet.song.106000.json','["亂世功名易，幽人愧素餐。", "草深迷乳兔，弓燥泣飛鸞。", "燐火排窗入，溪聲带雨寒。", "行吟殊足樂，回首羨彈冠。"]'),
('ac494730-8536-486c-b9a4-a60c33f94af3','林庇民保留宿夜話','顧禧','宋','宋诗','song-poetry','','[]','蹤跡忘疏密，情懷歷晦明。',48,'全唐诗/poet.song.106000.json','["蹤跡忘疏密，情懷歷晦明。", "攜琴時一至，倒屣輒相迎。", "枕發中郎祕，尊餘北海酲。", "浣花多勝侶，風雨話深更。"]'),
('e09fdad0-e748-43bb-92b9-48e97c8498ec','贈蓼庵上人','顧禧','宋','宋诗','song-poetry','','[]','曲徑通禪室，藜牀獨著書。',48,'全唐诗/poet.song.106000.json','["曲徑通禪室，藜牀獨著書。", "玄心棲物外，高論接皇初。", "雨過苔退淡，窗虛梅影疏。", "年年愁作客，爲爾一停車。"]'),
('ffabfd37-719a-46cf-a225-cad3f5da33e3','客湖上','顧禧','宋','宋诗','song-poetry','','[]','對酒拂吳鉤，光隨湖水流。',48,'全唐诗/poet.song.106000.json','["對酒拂吳鉤，光隨湖水流。", "碧尋堤上草，紅落竹邊樓。", "春老鶯啼倦，山空鶴唳收。", "買花錢欲盡，何事再句留。"]'),
('f0196f6e-9732-41dd-8aa1-26156b27ba30','洪善慶興祖偕訪昇上人即景次韻','顧禧','宋','宋诗','song-poetry','','[]','地僻僧栖隱，茆庵曲逕通。',48,'全唐诗/poet.song.106000.json','["地僻僧栖隱，茆庵曲逕通。", "雲浮秋水白，霞奪蓼花紅。", "野鳥當窗下，疏烟入畫中。", "采菱人未散，歸棹且從容。"]'),
('11de06b1-f662-4860-ab2e-e0c956cd2f66','飲譚子欽齋','顧禧','宋','宋诗','song-poetry','','[]','取次梅花放，樽前白雪樓。',48,'全唐诗/poet.song.106000.json','["取次梅花放，樽前白雪樓。", "人非分洛蜀，才豈遜曹劉。", "薑桂存餘辣，芝蘭憶舊遊。", "文章千古事，未許臥南州。"]'),
('7c1a322a-dfc7-4dbc-ab37-d1e4509137f4','九日吳山','顧禧','宋','宋诗','song-poetry','','[]','第一峰頭逢九日，振衣直上莫躊躇。',64,'全唐诗/poet.song.106000.json','["第一峰頭逢九日，振衣直上莫躊躇。", "丹梯苔冷仙人跡，祇樹雲深帝子居。", "圖畫天然看不厭，嘯歌自得意何如。", "茱萸醉插游絲倦，雁影參差夕照餘。"]'),
('8704ef76-1a51-4779-ae64-b91fca0966bf','送任文薦歸閩','顧禧','宋','宋诗','song-poetry','','[]','意氣深投傾蓋時，惜君才大愛君癡。',64,'全唐诗/poet.song.106000.json','["意氣深投傾蓋時，惜君才大愛君癡。", "應知摩詰詩中畫，都是將軍畫裏詩。", "放眼莫嫌吳地窄，探奇偏向禹陵遲。", "片帆千里懸明月，不屢滔滔九曲思。"]'),
('c779eb34-8f1c-4aff-b764-a42799bd5de1','贈行省任古','顧禧','宋','宋诗','song-poetry','','[]','帝廷咨牧擁金甌，南顧應寬萬里憂。',64,'全唐诗/poet.song.106000.json','["帝廷咨牧擁金甌，南顧應寬萬里憂。", "自是書屏多異績，何勞仰屋嘆無籌。", "六橋垂柳縈蒼珮，三竺飛花拂翠裘。", "遙望雲山千里隔，福星欣照□□樓。"]'),
('b9f2f0a5-1c71-4f63-80fc-10efdc7bded2','過徐稚山居','顧禧','宋','宋诗','song-poetry','','[]','曲徑秋高竹影斜，多君此日淡浮華。',64,'全唐诗/poet.song.106000.json','["曲徑秋高竹影斜，多君此日淡浮華。", "笛聲遠落幽人淚，月色清宜孺子家。", "世事盡勞五斗米，我來常醉一園花。", "不須更讀閒情賦，元亮風流自足誇。"]'),
('632b8435-b782-410c-9350-3f17c311cf71','苧邨烟雨','顧禧','宋','宋诗','song-poetry','','[]','湖南幾曲石橋底，細雨濛濛暗碧溪。',64,'全唐诗/poet.song.106000.json','["湖南幾曲石橋底，細雨濛濛暗碧溪。", "欸乃漁歌聲不斷，參差桑樹望中迷。", "花田香散泥初濕，柳圃烟深鶯亂啼。", "此地千年多買犢，耕男誰復怨征鼙。"]'),
('c9f2d8a5-4712-4b98-8385-df3e4413d7fc','寄懷閻安中','顧禧','宋','宋诗','song-poetry','','[]','金門射策盡名賢，誰似江南閻子然。',64,'全唐诗/poet.song.106000.json','["金門射策盡名賢，誰似江南閻子然。", "白虎談經知獨步，蒼松入夢已多年。", "凌雲賦筆雄千古，倒峽詞源傾百川。", "若憶古人愁絕處，西陵花柳日芊眠。"]'),
('8aa9ec3f-cea8-484c-87c7-9690e204e499','林庇民保以詩見贈次韻奉答','顧禧','宋','宋诗','song-poetry','','[]','蕭蕭竹影閒桐陰，有客攜琴慰素心。',64,'全唐诗/poet.song.106000.json','["蕭蕭竹影閒桐陰，有客攜琴慰素心。", "秋老登樓頻作賦，愁深抱膝共高吟。", "招尋叢桂香初散，快讀殘書酒滿斟。", "莫恨龍門策未報，十年聲價重南金。"]'),
('428b055b-a7f9-4612-be1f-284344def457','贈譚子欽惟寅','顧禧','宋','宋诗','song-poetry','','[]','臨風長憶聽濤吟，攜鋏重來感慨深。',64,'全唐诗/poet.song.106000.json','["臨風長憶聽濤吟，攜鋏重來感慨深。", "白首如新交自古，丹砂欲就老偏侵。", "獵微閣上傳佳句，宿影亭前話夙心。", "花萼雖零月正朗，斗中元氣待君斟。"]'),
('d6e19128-6854-4718-9f6c-d32a5b217f57','贈洪善慶興祖和壁閒沈□□韻','顧禧','宋','宋诗','song-poetry','','[]','高臥烟蘿飲上池，姓名獨許古人知。',64,'全唐诗/poet.song.106000.json','["高臥烟蘿飲上池，姓名獨許古人知。", "我來欲補洪家傳，入坐先尋沈約詩。", "舒卷閒雲看不厭，參差玉蝶放偏遲。", "殷勤送客過方井，古道真堪照一時。"]'),
('74ece9b5-9aad-4d2a-888e-631b974d61cb','同人看梅','顧禧','宋','宋诗','song-poetry','','[]','梅花引我入溪深，半繞青松半翠林。',64,'全唐诗/poet.song.106000.json','["梅花引我入溪深，半繞青松半翠林。", "已耐歲寒成好友，還將春色作幽岑。", "蒼烟踏破鞋無迹，明月挑來杖有心。", "贏得清芬盈客袖，莫愁歸路暮雲侵。"]'),
('d99c0bd0-525e-4bd5-a42f-6873aa4585d3','遊翠微山看桃','顧禧','宋','宋诗','song-poetry','','[]','梅花纔落見桃花，欲問桃源路轉賒。',64,'全唐诗/poet.song.106000.json','["梅花纔落見桃花，欲問桃源路轉賒。", "直上翠微開眼界，飽餐赤飯養心芽。", "句留客屐詩中畫，爛漫天真閣外霞。", "面壁老僧曾悟否，山猿已報夕陽斜。"]'),
('44f09197-8a34-471f-858a-cf8b9554bd52','徐稚山林出詩見示因書其後','顧禧','宋','宋诗','song-poetry','','[]','論交常憶少年時，耐久如君倍足思。',64,'全唐诗/poet.song.106000.json','["論交常憶少年時，耐久如君倍足思。", "金馬不移孺子節，石麟肯負誌公期。", "經霜傲菊依幽徑，漾月修篁種曲池。", "六客銜箋爛似錦，莫嫌野鶴故來遲。"]'),
('e3f5ec1d-41aa-4416-86a6-8b4e7250bfcd','偕譚子欽惟寅遊西樵','顧禧','宋','宋诗','song-poetry','','[]','江西美景聞天下，君上湖亭意若何。',64,'全唐诗/poet.song.106000.json','["江西美景聞天下，君上湖亭意若何。", "吞吐晴光千浪暖，卷舒雲氣兩峰多。", "陽春有腳歸花柳，芳草無心戀綺羅。", "力倦翻嫌花路淺，振衣再擬一同過。"]'),
('1d01ddda-c1e6-4067-81cf-6063b80af16e','九日登浮屠','顧禧','宋','宋诗','song-poetry','','[]','浮屠百尺絕花塵，一望霜林暮色勻。',63,'全唐诗/poet.song.106000.json','["浮屠百尺絕花塵，一望霜林暮色勻。", "嘯傲自然能遠俗，步趨何必不人。", "參軍帽落嘲誰解，□□□殘草作茵。", "卻羨東籬陶處士，菊花猶插碧紗巾。"]'),
('d708276b-8a0e-407d-b000-5cae11b17912','獨酌','顧禧','宋','宋诗','song-poetry','','[]','江色侵楓冷，松風入暮幽。',24,'全唐诗/poet.song.106000.json','["江色侵楓冷，松風入暮幽。", "莫愁樽酒盡，明月在高樓。"]'),
('557f60f8-3f96-47bb-916c-06ee6ecd631f','登吳山作','顧禧','宋','宋诗','song-poetry','','[]','紫雁高飛曉霧濃，西風峭削玉芙蓉。',32,'全唐诗/poet.song.106000.json','["紫雁高飛曉霧濃，西風峭削玉芙蓉。", "誰攜謝朓驚人句，更上吳山第一峰。"]'),
('abecb4b3-65fd-48d7-a045-9c1f1fc63dde','偈十三首  其一','釋慧空','宋','宋诗','song-poetry','','[]','山僧纔到雪嶺，打就無底鐵船。',28,'全唐诗/poet.song.106000.json','["山僧纔到雪嶺，打就無底鐵船。", "使人真覺海中，運載情與無情。"]'),
('60e26b26-4f7d-4c6e-9236-298fc811af66','偈十三首  其二','釋慧空','宋','宋诗','song-poetry','','[]','雪峰五月五日，不假神符妙術。',28,'全唐诗/poet.song.106000.json','["雪峰五月五日，不假神符妙術。", "只有頂門一錐，鐵佛也須汗出。"]'),
('8072dacb-e1e8-4237-8ea7-d4d8ff16394c','偈十三首  其三','釋慧空','宋','宋诗','song-poetry','','[]','千五百衆雪山住，無麵軟餅裹露柱。',31,'全唐诗/poet.song.106000.json','["千五百衆雪山住，無麵軟餅裹露柱。", "橫咬竪飽便休，莫倚他門傍他戶。"]'),
('fb400e8c-9bfe-4c30-a89b-af189549ac24','偈十三首  其四','釋慧空','宋','宋诗','song-poetry','','[]','月生一，上下四維無等匹。',36,'全唐诗/poet.song.106000.json','["月生一，上下四維無等匹。", "月生二，須彌拽脫虛空鼻。", "月生三，明正爲南方盡南。"]'),
('930c5b7c-b87a-4530-9663-9eb13f6e6ef0','偈十三首  其五','釋慧空','宋','宋诗','song-poetry','','[]','雪峰山中解夏，三門開放兩邊。',28,'全唐诗/poet.song.106000.json','["雪峰山中解夏，三門開放兩邊。", "去底觀音勢至，來底文殊普賢。"]'),
('a9110b79-9d0a-475f-952b-ecd141d73b18','偈十三首  其六','釋慧空','宋','宋诗','song-poetry','','[]','石霜山中獨虎，生得三腳驢兒。',28,'全唐诗/poet.song.106000.json','["石霜山中獨虎，生得三腳驢兒。", "走過萍實楚江，踢倒湖南長老。"]'),
('0c363ed7-3288-4dff-9472-baf45ad4c35c','偈十三首  其七','釋慧空','宋','宋诗','song-poetry','','[]','寒山舞，拾得笑，豐干一曲無羌調。',32,'全唐诗/poet.song.106000.json','["寒山舞，拾得笑，豐干一曲無羌調。", "囉囉哩，哩哩囉，近是秋林落葉多。"]'),
('486d6198-7f31-4d46-9b1d-855306c6b6a1','偈十三首  其八','釋慧空','宋','宋诗','song-poetry','','[]','法法本來法，無法無非法。',24,'全唐诗/poet.song.106000.json','["法法本來法，無法無非法。", "何於一法中，有法有不法。"]'),
('86970431-f9de-43de-abb0-208617d87b55','偈十三首  其九','釋慧空','宋','宋诗','song-poetry','','[]','低頭不見地，仰面不見天。',24,'全唐诗/poet.song.106000.json','["低頭不見地，仰面不見天。", "欲知白牛處，但看髑髏前。"]'),
('f7f74f53-c6bb-471d-abed-952b2bd3f02e','偈十三首  其一○','釋慧空','宋','宋诗','song-poetry','','[]','一漚未起，古帆未掛。',20,'全唐诗/poet.song.106000.json','["一漚未起，古帆未掛。", "風信不來，無人舉棹。"]'),
('4bf86b53-94f5-411a-95f3-81f5a53abd22','偈十三首  其一一','釋慧空','宋','宋诗','song-poetry','','[]','雪峰禪，無星子，只見陞堂打鼓。',79,'全唐诗/poet.song.106000.json','["雪峰禪，無星子，只見陞堂打鼓。", "賺得大衆上來，近日山中有虎。", "長至令晨，顛言倒語。", "祖師心印，堪作何用。", "無位真人，屎也不直。", "獨步青霄，徒誇好手。", "和泥合水，罕遇同流。"]'),
('8d7ebb5f-e84e-4c3e-8f2b-9c89173f7020','偈十三首  其一二','釋慧空','宋','宋诗','song-poetry','','[]','啐啄之機，暫時話計。',46,'全唐诗/poet.song.106000.json','["啐啄之機，暫時話計。", "清虛之理，不可依憑。", "執之失度，必入邪路。", "東海鯉魚打一棒，陝府鐵牛兩角折。"]'),
('ee0eb2c1-14e7-420f-a88f-163a8cf48da6','頌古  其一','釋慧空','宋','宋诗','song-poetry','','[]','不是風兮不是幡，祖師端的廣南蠻。',32,'全唐诗/poet.song.106000.json','["不是風兮不是幡，祖師端的廣南蠻。", "夜深趁得曹溪渡，失卻番禺兩岸山。"]'),
('5f028cdf-c374-4e91-ae2d-5143a241fa92','頌古  其二','釋慧空','宋','宋诗','song-poetry','','[]','馬師瞎卻亮師眼，一入西山更不返。',32,'全唐诗/poet.song.106000.json','["馬師瞎卻亮師眼，一入西山更不返。", "我有二十二藤條，寄與山中這擔板。"]'),
('519a0081-c127-430d-a80e-b6dc610d2991','頌古  其三','釋慧空','宋','宋诗','song-poetry','','[]','楚王城畔水東流，淮海維揚是九州。',32,'全唐诗/poet.song.106000.json','["楚王城畔水東流，淮海維揚是九州。", "蘆管一聲春夢破，斜陽還在樹梢頭。"]'),
('ec8aea56-58e2-473b-ade4-ef3de3c93e59','頌古  其四','釋慧空','宋','宋诗','song-poetry','','[]','說似一物則不中，箇是南岳讓和尚。',32,'全唐诗/poet.song.106000.json','["說似一物則不中，箇是南岳讓和尚。", "東山早曾與麽來，带累同行俱喫棒。"]'),
('53c0fb3b-7408-4ed2-89ae-27fcbac01468','頌古  其五','釋慧空','宋','宋诗','song-poetry','','[]','新婦騎驢阿家牽，潦倒禪翁雪滿顛。',32,'全唐诗/poet.song.106000.json','["新婦騎驢阿家牽，潦倒禪翁雪滿顛。", "不解爐頭煨死火，客來偏愛出人前。"]'),
('bafbbb2d-7c69-4f8e-8fda-e57007e41865','頌古  其六','釋慧空','宋','宋诗','song-poetry','','[]','大食波斯飲百杯，停杯把挹萬人魁。',32,'全唐诗/poet.song.106000.json','["大食波斯飲百杯，停杯把挹萬人魁。", "送風使過黄牛峽，不問瞿塘灧澦堆。"]'),
('a25ebec0-0c13-4a73-8b09-9f4ae5b5b37b','頌古  其七','釋慧空','宋','宋诗','song-poetry','','[]','德山棒，臨濟喝，寸刃未施先敗闕。',32,'全唐诗/poet.song.106000.json','["德山棒，臨濟喝，寸刃未施先敗闕。", "叢林盡謂是上機，明眼衲僧也大屈。"]'),
('c46d42b4-4d2e-4f0c-b24e-2fb4d2ac010d','頌古  其八','釋慧空','宋','宋诗','song-poetry','','[]','龐公慚愧全無，馬祖慈悲心大。',28,'全唐诗/poet.song.106000.json','["龐公慚愧全無，馬祖慈悲心大。", "直饒吸盡西江，東山未向伊道。"]'),
('b7d2d2ef-eec0-4b2d-8318-dcf35b8fbcbc','頌古  其九','釋慧空','宋','宋诗','song-poetry','','[]','引鼻拽回野鴨，元來卻是家雞。',28,'全唐诗/poet.song.106000.json','["引鼻拽回野鴨，元來卻是家雞。", "不管晦明風雨，纔到五更便啼。"]'),
('237cac92-32d8-4be3-9642-5ebcf4c7e3d6','頌古  其一○','釋慧空','宋','宋诗','song-poetry','','[]','身披粗布伽梨，手把大木槵子。',28,'全唐诗/poet.song.106000.json','["身披粗布伽梨，手把大木槵子。", "天寒坐火爐頭，動是說蛇說虎。"]'),
('ccf3567e-b8c2-4a45-a242-9fc4e2209891','頌古  其一一','釋慧空','宋','宋诗','song-poetry','','[]','我手何似佛手，拈起扇子擗口。',28,'全唐诗/poet.song.106000.json','["我手何似佛手，拈起扇子擗口。", "打落帝釋花冠，卻是寒山掃箒。"]'),
('d6301a4d-c4e9-48ad-ace5-486701c9c60f','頌古  其一二','釋慧空','宋','宋诗','song-poetry','','[]','我腳何似驢腳，車輪頓生八角。',28,'全唐诗/poet.song.106000.json','["我腳何似驢腳，車輪頓生八角。", "三千剎海波澄，一陣西風葉落。"]'),
('b62fdc70-aa84-40eb-8820-efbf236e4f95','頌古  其一三','釋慧空','宋','宋诗','song-poetry','','[]','人人盡有生緣，落花流出桃源。',28,'全唐诗/poet.song.106000.json','["人人盡有生緣，落花流出桃源。", "過後再尋無處，滿簑烟雨漁村。"]'),
('e1d8b977-a6c6-4a01-8e5b-285202c906f5','頌古  其一四','釋慧空','宋','宋诗','song-poetry','','[]','佛手驢腳生緣，三山影落中天。',28,'全唐诗/poet.song.106000.json','["佛手驢腳生緣，三山影落中天。", "武帝多方學道，王喬端坐神仙。"]'),
('a36a08c8-8158-40df-b66b-097d4f5e8f27','頌古  其一五','釋慧空','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一等作野狐，堂堂大丈夫。',24,'全唐诗/poet.song.106000.json','["一等作野狐，堂堂大丈夫。", "徐行青草岸，踏破洞庭湖。"]'),
('5745c702-29e5-472c-a558-f6f736d0b8ba','頌古  其一六','釋慧空','宋','宋诗','song-poetry','','[]','靈雲失腳，玄沙落塹，三十年冰河發焰。',18,'全唐诗/poet.song.106000.json','["靈雲失腳，玄沙落塹，三十年冰河發焰。"]'),
('0dc00d1a-3fda-41f1-b929-fb8facc51790','頌古  其一七','釋慧空','宋','宋诗','song-poetry','','[]','錢塘潮頭來，成都藥市集。',24,'全唐诗/poet.song.106000.json','["錢塘潮頭來，成都藥市集。", "叵尀汝州風，吹落毛僧笠。"]'),
('32b8f488-ca03-4a1f-84d2-cb7f4533fdc1','頌古  其一八','釋慧空','宋','宋诗','song-poetry','','[]','南瞻部洲鉏地，東弗于逮種麥。',28,'全唐诗/poet.song.106000.json','["南瞻部洲鉏地，東弗于逮種麥。", "西瞿耶尼拽磨，北鬰單越喫麵。"]'),
('415d5f1f-b4bf-454a-8389-b1d09477aeac','頌古  其一九','釋慧空','宋','宋诗','song-poetry','','[]','百書不如一歸家，千聞不如一見面。',32,'全唐诗/poet.song.106000.json','["百書不如一歸家，千聞不如一見面。", "既歸歸見復何爲，解道德山無佛殿。"]'),
('271b3e64-90ac-4b70-94d6-c176018ca2f7','頌古  其二○','釋慧空','宋','宋诗','song-poetry','','[]','泥人煅就九轉丹，石女一喫乘飛鸞。',64,'全唐诗/poet.song.106000.json','["泥人煅就九轉丹，石女一喫乘飛鸞。", "天門九重彈指間，再拜天帝除天官。", "瓜期既及風馭還，海變桑田知幾番。", "又尋東山訪平安，去時與偈墨未乾。"]'),
('30c781e7-62d8-4ef8-9e84-f28a69cc279d','頌古  其二一','釋慧空','宋','宋诗','song-poetry','','[]','戳瞎大地衆生眼，奪其一切資生物。',50,'全唐诗/poet.song.106000.json','["戳瞎大地衆生眼，奪其一切資生物。", "盡情推入大火坑，聽從阿耨池中出。", "然後爲念普安慰真言，唵摩尼佛㖃屈聿。"]'),
('b411fdcb-68ff-4ff3-b48c-b9db8d0b385e','看洞山初和尚語','釋慧空','宋','宋诗','song-poetry','','[]','兩頭蚯蚓呈三要，五眼胡孫念八還。',32,'全唐诗/poet.song.106000.json','["兩頭蚯蚓呈三要，五眼胡孫念八還。", "老蚌吞除龍樹月，瞎驢撞出趙州關。"]'),
('3bf9ce6b-6e7a-4da3-bd82-f8a7c84f4ce5','頌草堂老師付頂相贊後圓相','釋慧空','宋','宋诗','song-poetry','','[]','六國朝閶闔，三山插杳冥。',24,'全唐诗/poet.song.106000.json','["六國朝閶闔，三山插杳冥。", "禪流相借問，冬後一陽生。"]'),
('7520c5f5-1958-4824-a0b9-e5c94d2dd0c9','覽妙喜和尚衡陽示衆','釋慧空','宋','宋诗','song-poetry','','[]','海蚌直儱侗，不類海蠡兒。',24,'全唐诗/poet.song.106000.json','["海蚌直儱侗，不類海蠡兒。", "開口便見膽，也好與一槌。"]'),
('158001c8-f43f-4b87-9742-0967737ce60c','雪峰禪師真贊','釋慧空','宋','宋诗','song-poetry','','[]','咸通已前，正與麽㖿。',45,'全唐诗/poet.song.106000.json','["咸通已前，正與麽㖿。", "紹興之後，端的別別別。", "松山撐破秋空月，毬門有路沒遮欄，五月取霜六月雪。"]'),
('709c2d06-2e91-4519-b246-e31088739655','草堂老師真贊','釋慧空','宋','宋诗','song-poetry','','[]','隨隨昔昔，是這箇賊。',44,'全唐诗/poet.song.106000.json','["隨隨昔昔，是這箇賊。", "簸土揚塵，馳南走北。", "一棒打殺，狗也不喫。", "後來不肖兒孫，箇箇一模脫出。"]'),
('cc09b3aa-0d91-4350-b496-d3995914f3e4','造橋道者並諸化土寫求  其一','釋慧空','宋','宋诗','song-poetry','','[]','去一得三，添六成四。',44,'全唐诗/poet.song.106000.json','["去一得三，添六成四。", "有口無舌，有眼無鼻。", "寫得十成，以何爲是。", "掛在大目溪頭，恰似守橋土地。"]'),
('a5a67491-73c9-48cd-9987-c73d72555525','造橋道者並諸化土寫求  其二','釋慧空','宋','宋诗','song-poetry','','[]','這漢一生擔版，垂老出來住院。',56,'全唐诗/poet.song.106000.json','["這漢一生擔版，垂老出來住院。", "清真氣味全消，惡業因緣頓現。", "說禪罔聖欺凡，乞食走州歷縣。", "試看幀上傳來，輥得成甚觜面。"]'),
('1be03673-9fe8-4f59-905b-a585e7cb4191','造橋道者並諸化土寫求  其三','釋慧空','宋','宋诗','song-poetry','','[]','咄這老凍齈，是甚麽面孔。',51,'全唐诗/poet.song.106000.json','["咄這老凍齈，是甚麽面孔。", "似馬頭又圓，謂驢耳不聳。", "有毒鳖鼻蛇，無底破漆桶。", "徧處持來攪聒，十分是箇滅胡種。"]'),
('1c988899-a85e-4e23-b7cb-893b15ab3533','幽巖禪師真贊','釋慧空','宋','宋诗','song-poetry','','[]','一字不著劃，古錦寫回文。',24,'全唐诗/poet.song.106000.json','["一字不著劃，古錦寫回文。", "寒山指拾得，斗柄插雷門。"]'),
('153f8e38-d68b-4d39-9d20-337aadc290cb','圓悟禪師入滅說偈燒香','釋慧空','宋','宋诗','song-poetry','','[]','濯錦江心一漚發，清漲四溟波浪闊。',160,'全唐诗/poet.song.106000.json','["濯錦江心一漚發，清漲四溟波浪闊。", "引得風流小玉歸，無限龍魚遭攪聒。", "紫羅帳裏明月珠，把作栗蒲撩亂榝。", "一方孤迥峭巍巍，十字縱橫活鱍鱍。", "我昔墮渠齏甕中，倔強依前淹不殺。", "而今寰宇幸清平，誰道岷峨在天末。", "昨夜西風撼太虛，石牛驚走泥牛喝。", "一吸滄溟徹底乾，憍梵鉢提長吐舌。", "大悲千眼擘不開，無言童子空忉怛。", "炷香爲壽阿僧祇，紹興五年八月八。"]'),
('3848cff0-1b0d-48bc-8119-dea1119177c6','南華利侍者持昺和尚語至疏山請校入版乃作偈送之謁序于徐大資','釋慧空','宋','宋诗','song-poetry','','[]','曹溪大士出現世，誰其侍者道人利。',96,'全唐诗/poet.song.106000.json','["曹溪大士出現世，誰其侍者道人利。", "雷轟電激槌拂間，涓滴無遺水傳器。", "而今底事難覆藏，蓋是火後莖茅長。", "未言字字負此老，且要浩浩流諸方。", "最初有箇譊訛處，徧示知音著何語。", "東山有語人未知，請問東湖老居士。"]'),
('77ca547d-60c8-46bb-a2e3-b2953006f2d9','送莫內翰五首  其一','釋慧空','宋','宋诗','song-poetry','','[]','驚世文章夢裏花，出塵悟解眼中沙。',32,'全唐诗/poet.song.106000.json','["驚世文章夢裏花，出塵悟解眼中沙。", "怪來不打這鼓笛，親見江西老作家。"]'),
('e3c281d2-f155-4f64-9697-8ae419fcefc4','送莫內翰五首  其二','釋慧空','宋','宋诗','song-poetry','','[]','一槌從使口如鼻，百煉誰知方入圓。',32,'全唐诗/poet.song.106000.json','["一槌從使口如鼻，百煉誰知方入圓。", "莫怪野人高索價，從來佛祖不曾傳。"]'),
('66a71d97-acef-4101-8d46-0196341ba2d7','送莫內翰五首  其三','釋慧空','宋','宋诗','song-poetry','','[]','黄龍室內三關語，趙老青州一布衫。',32,'全唐诗/poet.song.106000.json','["黄龍室內三關語，趙老青州一布衫。", "何事臨分無別說，則川龐老是同參。"]'),
('bbb01680-09c8-41e1-b1a5-7db1f6fb0f71','送莫內翰五首  其四','釋慧空','宋','宋诗','song-poetry','','[]','試問同參參底事，華亭秋晚水如天。',32,'全唐诗/poet.song.106000.json','["試問同參參底事，華亭秋晚水如天。", "離鈎三寸無人會，風起蘆花落釣船。"]'),
('0f0b24e5-48e0-4514-b59e-c754703cdc1c','送莫內翰五首  其五','釋慧空','宋','宋诗','song-poetry','','[]','今者叢林走大聲，不言無眼只無睛。',32,'全唐诗/poet.song.106000.json','["今者叢林走大聲，不言無眼只無睛。", "願公善保千鈞重，莫管他家熱椀鳴。"]'),
('20bc1719-9e25-4c65-8963-5002de35226a','次韻韓伯修學士讀楞嚴見寄','釋慧空','宋','宋诗','song-poetry','','[]','琉璃甕中走卻鱉，驚起波斯一夜尋。',32,'全唐诗/poet.song.106000.json','["琉璃甕中走卻鱉，驚起波斯一夜尋。", "天曉不知何所見，大悲菩薩是觀音。"]'),
('e2b08b75-0653-455d-8ab4-8aa52a68d49f','次游教授韻呈草堂老師  其一','釋慧空','宋','宋诗','song-poetry','','[]','霜髪垂垂老不休，鐵船無底更隨流。',32,'全唐诗/poet.song.106000.json','["霜髪垂垂老不休，鐵船無底更隨流。", "兒孫莫訝得魚少，蓋謂翁翁是直鈎。"]'),
('bff9cbe1-2f60-46d2-a8dd-87cfc9ca4d38','次游教授韻呈草堂老師  其二','釋慧空','宋','宋诗','song-poetry','','[]','北鬰之南瞻部洲，縱觀誰是老人流。',32,'全唐诗/poet.song.106000.json','["北鬰之南瞻部洲，縱觀誰是老人流。", "大千一網平收了，坐看兒童亂下鈎。"]'),
('568d3750-f266-44e3-84fa-e00181c0114d','辭草堂老師歸閩','釋慧空','宋','宋诗','song-poetry','','[]','短筇初把探深深，展盡神機被陸沉。',64,'全唐诗/poet.song.106000.json','["短筇初把探深深，展盡神機被陸沉。", "搦殺未償當日恨，翻身誰識此時心。", "不離左右金爲土，別有生涯土作金。", "既去後來應請問，莫言曾到此山陰。"]'),
('932cc2c4-1636-4263-a9b1-a81948592d96','送夢石歸妙峰德雲庵','釋慧空','宋','宋诗','song-poetry','','[]','紹聖五年戊寅冬，王母吞卻嘉州像。',96,'全唐诗/poet.song.106000.json','["紹聖五年戊寅冬，王母吞卻嘉州像。", "覺來捫腹喜且驚，一朝生出這和尚。", "鋭頭長身碧兩瞳，衆聚說法聲如鐘。", "少年蹈斷象骨路，出處大類飛山翁。", "老而益健難近傍，德山縮手臨濟讓。", "善財盡力無處尋，又是經行別峰上。"]'),
('12a4e288-83c0-4cb2-9837-9ec7305b350c','南詢歌','釋慧空','宋','宋诗','song-poetry','','[]','南詢士，標致殊，發言落落中疏疏。',96,'全唐诗/poet.song.106000.json','["南詢士，標致殊，發言落落中疏疏。", "瘦藤一握鐵相似，孤身萬里雲不如。", "作者前，致一問，分明直得繩床震。", "失腳踏翻樓閣門，通身不掛毗盧印。", "佛祖言，甚熱椀，一劍當頭百非剗。", "大展禪宗定古今，火裏蝍蟟三隻眼。"]'),
('f227e6b5-33a0-4dc8-ac5e-f0d8fa67118c','空王子','釋慧空','宋','宋诗','song-poetry','','[]','空王子之空而靈，拈起鉢飯忘了羹。',72,'全唐诗/poet.song.106000.json','["空王子之空而靈，拈起鉢飯忘了羹。", "一生看經不識字，總十二部爲一句。", "一生說禪不動口，噴嚏也成師子吼。", "阿呵呵，黄面瞿曇爭奈何。", "咄咄咄，是甚衲僧臭皮襪。"]'),
('3d18e1d8-91ad-4db6-acf6-ed624b52e9b9','又用前韻送僧','釋慧空','宋','宋诗','song-poetry','','[]','空王子，出空門，敏於選佛訥於言。',128,'全唐诗/poet.song.106000.json','["空王子，出空門，敏於選佛訥於言。", "老少同科無異學，盡傾阿耨作詞源。", "龍虎榜，輝乾坤，一字元無作麽分。", "汝見是汝爲第一，我見是我作狀元。", "有驚群，有獨脫，可中丹桂和根拔。", "把作枯柴竈裏燒，誰能更著空王褐。", "只如劍，成家活，不犯鋒鋩有生殺。", "莫似章分句解徒，望卻龍門頭枿枿。"]'),
('df8e9de7-4075-418c-adb6-bf2dde32aa6d','禪人求偈','釋慧空','宋','宋诗','song-poetry','','[]','禪家流，悟自己，開眼曹溪十萬里。',128,'全唐诗/poet.song.106000.json','["禪家流，悟自己，開眼曹溪十萬里。", "況行機路守心空，病渴移家陽燄裏。", "渴轉渴，水又非。", "擡頭不覺雁南飛。", "文殊堂裏萬菩薩，大唐國內無禪師。", "或行棒，或行喝，棒喝交馳如電掣。", "不容眨眼入思惟，忽把虛空敲出骨。", "地神惡，天神悅，陝府鐵牛得一橛。", "且等東山睡覺來，大掌連腮咄咄咄。"]'),
('86a3fc7a-7d48-43af-ba04-8bdf8b418ea1','送僧三首  其一','釋慧空','宋','宋诗','song-poetry','','[]','蜀川老覺家潼川，懷中交子是鐵錢。',96,'全唐诗/poet.song.106000.json','["蜀川老覺家潼川，懷中交子是鐵錢。", "三年聽講大慈寺，執卷問之不識字。", "三年參禪大隋山，蓋龜劫火猶顢頇。", "瞿塘忽放鐵船下，不問灧澦堆如馬。", "逆風使過荆湖南，焦荔林中來放憨。", "同風莫倚閩與蜀，飲水更須防蠱毒。"]'),
('23defc8e-b14c-486c-880f-2ba985bfcc89','送僧三首  其二','釋慧空','宋','宋诗','song-poetry','','[]','支提天冠千眷屬，龜山蔡柳兩尊宿。',96,'全唐诗/poet.song.106000.json','["支提天冠千眷屬，龜山蔡柳兩尊宿。", "總在參禪屋角頭，開眼光光互相燭。", "參禪自是雲水儔，四顧坤維有高躅。", "勝妙光中不肯留，六六要明三十六。", "當其行，歌一曲，春草青兮春水綠。", "東山老矣夫何言，縱有言兮不堪讀。"]'),
('619f6eab-eda9-4c86-9e94-cb2fea02dfa7','送僧三首  其三','釋慧空','宋','宋诗','song-poetry','','[]','東山送人只一句，纔擬欽承喝出去。',64,'全唐诗/poet.song.106000.json','["東山送人只一句，纔擬欽承喝出去。", "而今更向紙上求，大似因鷹拏死兔。", "猷禪猷禪知不知，堅坐守之無了時。", "趁取西風霜未落，泐潭百丈在江西。"]'),
('75dc402f-8558-4064-9baf-3ef3b41fd83b','煨芋','釋慧空','宋','宋诗','song-poetry','','[]','後生偷笑東山老，事無是非總曰好。',64,'全唐诗/poet.song.106000.json','["後生偷笑東山老，事無是非總曰好。", "布伽梨裏老病身，山芋頭煨紅軟火。", "日暖婆娑林下行，天寒堆危火邊坐。", "人問祖室今安危，對道我此煨芋好。"]'),
('bd91fe3c-448b-4d9a-99eb-01957cac3c2e','與暠副寺','釋慧空','宋','宋诗','song-poetry','','[]','衲僧之勇惟法戰，鐵作渾身猶百煉。',64,'全唐诗/poet.song.106000.json','["衲僧之勇惟法戰，鐵作渾身猶百煉。", "不知誰是取讎家，直入南方行一轉。", "上門上戶眼如鈴，有麽有麽機如電。", "剔起便行何處尋，聲前句後新羅箭。"]'),
('1c508582-324d-4407-92d1-4dc2cff122da','送二僧之衡陽  其一','釋慧空','宋','宋诗','song-poetry','','[]','閩蜀同風果同風，袈裟拔出鞋袋中。',64,'全唐诗/poet.song.106000.json','["閩蜀同風果同風，袈裟拔出鞋袋中。", "相逢古寺話俄頃，怪我稱鎚落深井。", "不憂佛日居衡陽，不憂無人振頹綱。", "卻憂秋高霜月冷，鐵牛夜度飛猿嶺。"]'),
('5fb50522-e055-4ecd-80cd-213e23a2bda5','送二僧之衡陽  其二','釋慧空','宋','宋诗','song-poetry','','[]','衡陽老子一僧耳，打雨罵風無別伎。',64,'全唐诗/poet.song.106000.json','["衡陽老子一僧耳，打雨罵風無別伎。", "海上禪流未識渠，將謂三頭仍六臂。", "兩川邁往初不然，我喜其行重說偈。", "披秀菴前癩狗兒，要見衡陽只這是。"]'),
('54ca1ade-30f8-40f2-8d62-cb3ea4488882','寄支提禪師','釋慧空','宋','宋诗','song-poetry','','[]','遠聽天冠化寺鐘，孤烟明滅暮山重。',96,'全唐诗/poet.song.106000.json','["遠聽天冠化寺鐘，孤烟明滅暮山重。", "念攜掛壁木上座，問訊長沙岑大蟲。", "大蟲聲威動海宇，老不與世同其波。", "卷藏風月付一室，落日春山狐兔多。", "威而不怒默常吼，寂子觸之遭毒手。", "東山又似不知時，更來許露其家醜。"]'),
('bf7be3a7-2494-4003-96ee-efd3c4e8a8cf','又送出閩','釋慧空','宋','宋诗','song-poetry','','[]','老人入我閩中居，如山有玉淵有珠。',64,'全唐诗/poet.song.106000.json','["老人入我閩中居，如山有玉淵有珠。", "老人一日出山去，崖不自靈淵亦枯。", "我問天冠千眷屬，如何不留老尊宿。", "飛鸞水急海天橫，一道清輝照四明。"]'),
('ae54e5fd-115b-42f0-833c-bd27518781a0','送深書記  其一','釋慧空','宋','宋诗','song-poetry','','[]','東海鯉魚吞卻海，西河師子口門大。',32,'全唐诗/poet.song.106000.json','["東海鯉魚吞卻海，西河師子口門大。", "金剛喚起足行神，還卻趙州行腳債。"]'),
('7b9fb1bc-21a1-4cb5-b4f0-d3f9ed41b73b','送深書記  其二','釋慧空','宋','宋诗','song-poetry','','[]','吹毛不是凡間鐵，百匝千重唯一決。',32,'全唐诗/poet.song.106000.json','["吹毛不是凡間鐵，百匝千重唯一決。", "出頭天外笑呵呵，喜得空生不曾說。"]'),
('5c3a4650-6138-411c-bee8-cc45fc661834','與符侍者','釋慧空','宋','宋诗','song-poetry','','[]','秀峰三聖堂中，符也曾職其事。',70,'全唐诗/poet.song.106000.json','["秀峰三聖堂中，符也曾職其事。", "節制火筯香匙，使得燈籠露柱。", "聖僧頸上下來，天台山中入去。", "通玄不是人間，忽雨忽晴忽霧。", "出門且莫匆匆，道取末後一句。"]'),
('08e5231c-4f93-48a1-86e7-52b2c75e0e3c','謝丹山秀首座竹筇  其一','釋慧空','宋','宋诗','song-poetry','','[]','老身一衲百無營，病骨人驚太瘦生。',32,'全唐诗/poet.song.106000.json','["老身一衲百無營，病骨人驚太瘦生。", "多謝枝筇解扶我，松陰石上聽溪聲。"]'),
('045caf67-2e13-4553-9aaa-2a47cc704861','謝丹山秀首座竹筇  其二','釋慧空','宋','宋诗','song-poetry','','[]','山中久住成老宿，雲水五湖來弟兄。',32,'全唐诗/poet.song.106000.json','["山中久住成老宿，雲水五湖來弟兄。", "放下茶甌答了話，把得拄杖東西行。"]'),
('c8dd8f8d-262b-45c8-87cd-4a2434d50e06','葉居士施直裰求頌','釋慧空','宋','宋诗','song-poetry','','[]','廣南葉順居士，施我褐紬直裰。',56,'全唐诗/poet.song.106000.json','["廣南葉順居士，施我褐紬直裰。", "比之七斤布衫，這個猶難提掇。", "天寒雪落便披，日暖風和即脫。", "脫著畢竟是誰，慚愧觀音菩薩。"]'),
('599c03e4-342b-4969-abae-d5610de52746','送行上人歸塔慧力空印和尚靈骨于西山','釋慧空','宋','宋诗','song-poetry','','[]','古佛大塔廣，量廓虛空界。',96,'全唐诗/poet.song.106000.json','["古佛大塔廣，量廓虛空界。", "凡聖位其中，如光無雜壞。", "出生與入滅，一一得自在。", "衆生迷本心，當處自留礙。", "良哉空印師，火後靈骨在。", "憑誰密安置，有子如行輩。", "山爲碧玉環，水作青羅带。", "巍巍鎮巍巍，永下諸天拜。"]'),
('921d8194-21fc-4fa7-82cf-ef0c539cf68c','與沔上人','釋慧空','宋','宋诗','song-poetry','','[]','參禪無悟處，如何得安樂。',96,'全唐诗/poet.song.106000.json','["參禪無悟處，如何得安樂。", "置之空劫前，即爲空劫縛。", "任運日用中，拶著無不錯。", "懵然百不理，奈此一絡索。", "勇猛積勳修，翻成大過惡。", "端坐審思惟，不如更行腳。", "東山老病漢，聞之爲喜躍。", "願爾發足時，出門便蹈著。"]'),
('75498f19-b38d-4788-bf16-fad5777ae9bc','與虛上人','釋慧空','宋','宋诗','song-poetry','','[]','止渴須是水，止饑須是飯。',48,'全唐诗/poet.song.106000.json','["止渴須是水，止饑須是飯。", "參禪須是悟，成佛不待旦。", "伽陀有底急，休來問老漢。", "既來無奈何，拄杖驀頭攛。"]'),
('605ff050-4315-46b8-b514-caa6a5162d49','與性上人','釋慧空','宋','宋诗','song-poetry','','[]','汝知東山空，胸中無窖子。',84,'全唐诗/poet.song.106000.json','["汝知東山空，胸中無窖子。", "說禪瞎人眼，書偈汙人紙。", "不知禪家流，於空何所取。", "腳要汝自行，死要汝自死。", "道不假他成，佛豈離自己。", "唯有老趙州，平生一則語。", "既是其中人，東山與之舉。"]'),
('fda8afc9-87f9-4dfe-a34c-463b231ba79d','病起','釋慧空','宋','宋诗','song-poetry','','[]','老僧頭風，一月兩發。',90,'全唐诗/poet.song.106000.json','["老僧頭風，一月兩發。", "見粥便嘔，見飯便噦。", "死又不死，活又不活。", "使他諸人，冷地忙殺。", "觀音勢至，候饑候渴。", "文殊普賢，左提右掇。", "纔方起來，便翻著襪。", "不問是非，乃棒乃喝。", "呵呵雲門，君子可入。"]'),
('676b163e-66e0-416e-abf6-29a2bc0b062c','與妙庵主','釋慧空','宋','宋诗','song-poetry','','[]','至道之宗，備在爾躬。',80,'全唐诗/poet.song.106000.json','["至道之宗，備在爾躬。", "求之則遠，守之不通。", "不求不守，奇哉靈叟。", "極離極微，應心應手。", "觸目晴嵐，到處成菴。", "捶呵彌勒，不與同龕。", "石虎擡頭，泥牛入海。", "驀劄相逢，一場風采。"]'),
('6fb62ecd-90b0-4206-98ed-0a9869bd3e79','頌古  其一','釋慧空','宋','宋诗','song-poetry','','[]','梁魏山河本太平，無端容此老狐精。',32,'全唐诗/poet.song.106000.json','["梁魏山河本太平，無端容此老狐精。", "九年皮髓分張盡，隻履空棺更誑人。"]'),
('b9a552e9-f543-4f02-aaed-7b2b0898a9a8','頌古  其二','釋慧空','宋','宋诗','song-poetry','','[]','宗師一等把宗綱，魯祖垂慈太著忙。',32,'全唐诗/poet.song.106000.json','["宗師一等把宗綱，魯祖垂慈太著忙。", "璞玉渾金雖定價，往來多是不相當。"]'),
('d7e00fb5-8765-4005-9d59-7dc70ff36a2e','頌古  其三','釋慧空','宋','宋诗','song-poetry','','[]','廬陵米價忽相酬，巨宋山河四百州。',32,'全唐诗/poet.song.106000.json','["廬陵米價忽相酬，巨宋山河四百州。", "青草渡頭韓幹馬，綠楊陰裏戴嵩牛。"]'),
('4bf64f98-d449-461b-9f5e-1ddd9972d17a','頌古  其四','釋慧空','宋','宋诗','song-poetry','','[]','藏身北斗道彌昌，三腳蝦蟆著錦襠。',32,'全唐诗/poet.song.106000.json','["藏身北斗道彌昌，三腳蝦蟆著錦襠。", "多少病貓餐死鼠，日中擡首眼無光。"]'),
('b9aa8557-c2eb-475e-a8bc-991f8e3718db','頌古  其五','釋慧空','宋','宋诗','song-poetry','','[]','杖林山下竹筋鞭，六月行人口吐烟。',32,'全唐诗/poet.song.106000.json','["杖林山下竹筋鞭，六月行人口吐烟。", "曾在祝融峰頂見，十分月出在平田。"]'),
('eb9198f2-513f-4ce5-ab76-190a233e4b98','頌古  其六','釋慧空','宋','宋诗','song-poetry','','[]','杖林山下竹筋鞭，生長由來古佛先。',32,'全唐诗/poet.song.106000.json','["杖林山下竹筋鞭，生長由來古佛先。", "一擊眼睛纔定動，又隨烟雨過秦川。"]'),
('b152f7fc-9c19-483f-a916-649db33debe9','頌古  其七','釋慧空','宋','宋诗','song-poetry','','[]','趙州老倒一禪和，勘破臺山箇老婆。',32,'全唐诗/poet.song.106000.json','["趙州老倒一禪和，勘破臺山箇老婆。", "笑倒石門庵內客，一條濟水過新羅。"]'),
('6115ffed-6b00-4bb1-9390-c045d200a910','頌古  其八','釋慧空','宋','宋诗','song-poetry','','[]','野鴨羽翼能幾長，馬師眼孔些子大。',32,'全唐诗/poet.song.106000.json','["野鴨羽翼能幾長，馬師眼孔些子大。", "從他飛去擬何之，須待拽回遭笑怪。"]'),
('6ea8ce98-0381-46fc-a950-d8bf259bb863','頌古  其九','釋慧空','宋','宋诗','song-poetry','','[]','不是風兮不是幡，胡僧兩耳带金環。',32,'全唐诗/poet.song.106000.json','["不是風兮不是幡，胡僧兩耳带金環。", "分明有語無人會，又上高樓看遠山。"]'),
('0fda7b1e-2151-41c5-aa86-c5c5c5faa3be','頌古  其一○','釋慧空','宋','宋诗','song-poetry','','[]','不是幡兮不是風，毒蛇臥在酒杯中。',32,'全唐诗/poet.song.106000.json','["不是幡兮不是風，毒蛇臥在酒杯中。", "寒山撫掌豐干笑，萬里鴻溝屬沛公。"]'),
('50b45940-1bdd-485e-9a97-59dcf35dc9db','頌古  其一一','釋慧空','宋','宋诗','song-poetry','','[]','不是風幡不是心，曹溪一路盡平沈。',32,'全唐诗/poet.song.106000.json','["不是風幡不是心，曹溪一路盡平沈。", "俊鷹豈肯籬邊立，直透青霄萬萬尋。"]'),
('c8223d5e-94c8-4042-ac28-e0364db1f3ed','頌古  其一二','釋慧空','宋','宋诗','song-poetry','','[]','十智同真驗作家，可中毫忽不容差。',32,'全唐诗/poet.song.106000.json','["十智同真驗作家，可中毫忽不容差。", "若無師子翻身句，現在徒將面自誇。"]'),
('269c51e3-c3f7-4d3e-8a9d-0115b91590e5','頌古  其一三','釋慧空','宋','宋诗','song-poetry','','[]','古人悟處今人眼，善巧休爲眼畫眉。',32,'全唐诗/poet.song.106000.json','["古人悟處今人眼，善巧休爲眼畫眉。", "不見馬頭人廝撲，一拳打倒隻臨時。"]'),
('c73808aa-e419-492c-84c8-5c3d78d4697a','頌古  其一四','釋慧空','宋','宋诗','song-poetry','','[]','盲人端的有眼，鐵牛通身無骨。',28,'全唐诗/poet.song.106000.json','["盲人端的有眼，鐵牛通身無骨。", "不信問取桃花，便見靈雲敗闕。"]'),
('94c578d6-3e8c-40e6-9389-40f3e7d0fb2c','頌古  其一五','釋慧空','宋','宋诗','song-poetry','','[]','桃花春暖盡情開，一見無疑頗俊哉。',32,'全唐诗/poet.song.106000.json','["桃花春暖盡情開，一見無疑頗俊哉。", "不是釣魚船上客，無人把手上高臺。"]'),
('d252b6b8-b7c4-40cb-b907-cd401c4a1f56','頌古  其一六','釋慧空','宋','宋诗','song-poetry','','[]','西來密意庭前柏，有語無語徒分拆。',32,'全唐诗/poet.song.106000.json','["西來密意庭前柏，有語無語徒分拆。", "若是道人但舉來，只麽守株無了日。"]'),
('424196f6-ad0d-4666-8861-d932120c7249','頌古  其一七','釋慧空','宋','宋诗','song-poetry','','[]','咄哉王老師，赤窮身也賣。',24,'全唐诗/poet.song.106000.json','["咄哉王老師，赤窮身也賣。", "喫些油糍歸，至今被人怪。"]'),
('fbb40918-1662-489f-a752-d7927ffc671e','頌古  其一八','釋慧空','宋','宋诗','song-poetry','','[]','六國平來一瞬中，心王不動八方通。',32,'全唐诗/poet.song.106000.json','["六國平來一瞬中，心王不動八方通。", "從前汗馬無人見，只要重論蓋代功。"]'),
('2d7da14a-18e3-472b-965f-0a2d8b71a613','泐潭暹上人出示延福頌古三首索鄙語因用其韻贈之  其一','釋慧空','宋','宋诗','song-poetry','','[]','馬駒踏殺天下人，炙地熏天氣轉腥。',32,'全唐诗/poet.song.106000.json','["馬駒踏殺天下人，炙地熏天氣轉腥。", "百歲翁翁開口笑，江西從此足人行。"]'),
('44e43efe-1d87-4e8b-9425-6bdb9865e9dc','泐潭暹上人出示延福頌古三首索鄙語因用其韻贈之  其二','釋慧空','宋','宋诗','song-poetry','','[]','引鼻牽回野鴨兒，升堂卷席便高飛。',32,'全唐诗/poet.song.106000.json','["引鼻牽回野鴨兒，升堂卷席便高飛。", "後來要識吾宗旨，試看而今是甚時。"]'),
('4e93967f-1f05-4944-9010-0fe23791e62a','泐潭暹上人出示延福頌古三首索鄙語因用其韻贈之  其三','釋慧空','宋','宋诗','song-poetry','','[]','千年滯貨無人顧，拈起從教著價看。',32,'全唐诗/poet.song.106000.json','["千年滯貨無人顧，拈起從教著價看。", "一口直饒酬得過，泐潭山更過西山。"]'),
('491c3d25-b7f3-4323-9384-a3607aa0db94','覽趙州語','釋慧空','宋','宋诗','song-poetry','','[]','趙州借得空生口，便自縱橫師子吼。',64,'全唐诗/poet.song.106000.json','["趙州借得空生口，便自縱橫師子吼。", "問其佛性狗子無，問其甲子蘇州有。", "而今此口還空生，古佛依前成漏逗。", "掀翻海嶽覓知音，箇箇看來日中斗。"]'),
('d62b3b72-ab12-4c24-9f07-aaff35dcf705','大士講經','釋慧空','宋','宋诗','song-poetry','','[]','兩口明明一無舌，同死同生爲吾決。',32,'全唐诗/poet.song.106000.json','["兩口明明一無舌，同死同生爲吾決。", "那吒頂上喫蒺蔾，金剛腳下流出血。"]'),
('18b8dfa4-4b1f-4b32-96e4-e64eeb32751f','石門庵偶作','釋慧空','宋','宋诗','song-poetry','','[]','百鍊黄金鑄鐵牛，十分高價與人酬。',32,'全唐诗/poet.song.106000.json','["百鍊黄金鑄鐵牛，十分高價與人酬。", "臺前不有花含笑，應是東山一夏休。"]'),
('ed2bcb10-6736-4b3e-8e2e-75de0d55daa1','冬至','釋慧空','宋','宋诗','song-poetry','','[]','冬後一陽生，東君曾未睹。',48,'全唐诗/poet.song.106000.json','["冬後一陽生，東君曾未睹。", "百草總不知，梅花先漏泄。", "鐘聲出遠林，雁陣橫殘月。", "更擬問如何，弄巧翻成拙。"]'),
('202493fe-fc29-45b5-a0d3-1363f685a7ac','巨風行  其一','釋慧空','宋','宋诗','song-poetry','','[]','海山一雨三日風，折木舉屋如飛蓬。',32,'全唐诗/poet.song.106000.json','["海山一雨三日風，折木舉屋如飛蓬。", "路人驚竄居人泣，平地乃是洪濤中。"]'),
('5915c904-ec0c-401b-8c61-c91ba97c6954','巨風行  其二','釋慧空','宋','宋诗','song-poetry','','[]','有生何處得安穩，方寸是爲風火本。',32,'全唐诗/poet.song.106000.json','["有生何處得安穩，方寸是爲風火本。", "看來出爾方寸間，雨霽風休海天遠。"]'),
('c9e848f5-00e9-4d36-8f87-03323703cd17','擬月','釋慧空','宋','宋诗','song-poetry','','[]','圓時缺處何曾有，缺處圓時自儼然。',32,'全唐诗/poet.song.106000.json','["圓時缺處何曾有，缺處圓時自儼然。", "舉世盡隨圓缺走，幾人透出未生前。"]'),
('b4f077d4-9d5e-4fca-9385-fd11f4810efe','擬山居','釋慧空','宋','宋诗','song-poetry','','[]','古人縛屋山頭住，十年不行山下路。',64,'全唐诗/poet.song.106000.json','["古人縛屋山頭住，十年不行山下路。", "終朝兩眼掛枯松，不憂無米但覓句。", "滿屋風聲合雨聲，半壁山雲雜山霧。", "於中只麽過此生，猶勝時人三五步。"]'),
('ef0a6228-1d03-4b41-9d19-2ff0ea5d96bf','食荀','釋慧空','宋','宋诗','song-poetry','','[]','機泉擣秔炊明璣，竹根燒筍然竹枝。',112,'全唐诗/poet.song.106000.json','["機泉擣秔炊明璣，竹根燒筍然竹枝。", "錦綳稚子犢獻角，玉版阿師囊穎錐。", "同槃苦覺風味好，對客不知寒涕垂。", "古來山林例窮餓，藜莧誑腹蕨充饑。", "我今一飽萬想滅，老馬釋羈牛脫縻。", "南山蒼蒼入箕踞，涼月冏冏生談犀。", "公無說與市朝予，啄腐吞腥渠得知。"]'),
('a03dff1b-62b3-4ffb-bd05-4bf0f8af2803','與夢石分歲','釋慧空','宋','宋诗','song-poetry','','[]','歲盡人人有可分，翁今分歲亦隨群。',64,'全唐诗/poet.song.106000.json','["歲盡人人有可分，翁今分歲亦隨群。", "餅翻溪上團團月，鱠縷簷間細細雲。", "漱壑醴泉春萬斛，堆槃珠柳雪千斤。", "兩翁一飽風顛在，倦僕饑僮總未聞。"]'),
('6ec8f0fe-250e-4ffa-a715-1dad9ee1c37b','無規矩','釋慧空','宋','宋诗','song-poetry','','[]','赫日光中強作主，忽然霹靂聲中死。',64,'全唐诗/poet.song.106000.json','["赫日光中強作主，忽然霹靂聲中死。", "仰觀不見太虛空，俯視分明無寸土。", "跨瞎驢，追猛虎，百戰場中有文武。", "老來信手斫方圓，從教人笑無規矩。"]'),
('3175ba03-6462-4095-8963-0c949d85eb7f','春日示衆','釋慧空','宋','宋诗','song-poetry','','[]','青帝一微笑，恩光遍剎塵。',48,'全唐诗/poet.song.106000.json','["青帝一微笑，恩光遍剎塵。", "如何百草上，剛有未明人。", "人人當節令，合故竟開新。", "東山拄杖子，也自黑粼皴。"]'),
('9afdb750-a759-4662-a5fe-d8809ee01ccc','和直指春日未衆  其一','釋慧空','宋','宋诗','song-poetry','','[]','庵前烏龜久不見，一夜雷雨忽然出。',32,'全唐诗/poet.song.106000.json','["庵前烏龜久不見，一夜雷雨忽然出。", "東山老漢眼𪾾癡，近前問訊定光佛。"]'),
('83225f61-3df6-4200-8e22-4ca32545f577','和直指春日未衆  其二','釋慧空','宋','宋诗','song-poetry','','[]','直指示衆重說偈，瞿曇捨身得其半。',32,'全唐诗/poet.song.106000.json','["直指示衆重說偈，瞿曇捨身得其半。", "東山和出一字無，擘破面門君自看。"]'),
('fad9b62c-68f2-41ac-8972-c5b72b41b8e4','覽印無在語','釋慧空','宋','宋诗','song-poetry','','[]','老胡遺下一則語，匝地普天無不舉。',60,'全唐诗/poet.song.106000.json','["老胡遺下一則語，匝地普天無不舉。", "傾湫倒嶽是家常，物義不傷多莽鹵。", "螗螂莫笑夏蜩癡，甘草酷似黄連苦。", "黄連苦，南泉不打鹽官鼓。"]'),
('03e68bfc-bc0c-4775-ac67-df69c93c2734','松齋直指因喫粽與兄弟論鐵酸豏金剛圈栗棘蓬話作三偈見寄合爲一偈酬之','釋慧空','宋','宋诗','song-poetry','','[]','直指喫粽被粽賺，吐出多年鐵酸豏。',96,'全唐诗/poet.song.106000.json','["直指喫粽被粽賺，吐出多年鐵酸豏。", "俊鷹纔見插天飛，餓狗牀根爭咂啖。", "忽然變作蒲與圈，鷹也迷蹤狗也奔。", "百年滯貨無人要，千里持來訪我門。", "象牙不出老鼠口，富貴或生窮相手。", "倒把春風二月花，滿勸松齋一杯酒。"]'),
('e8c00e44-40e1-47ae-bf8c-b2c5d5114a9f','別劉師美  其一','釋慧空','宋','宋诗','song-poetry','','[]','世故熏人易變初，誰能變處即如如。',32,'全唐诗/poet.song.106000.json','["世故熏人易變初，誰能變處即如如。", "相看有道遽難說，且可還家深讀書。"]'),
('82ec5e39-1d09-4c51-bbb4-335f48e9ba3a','別劉師美  其二','釋慧空','宋','宋诗','song-poetry','','[]','十年倦客思深隱，江北江南千萬峰。',32,'全唐诗/poet.song.106000.json','["十年倦客思深隱，江北江南千萬峰。", "今後故人應念我，有書何處覓行蹤。"]'),
('1a9fc2df-dd5e-4368-a557-aac7af91a76a','某得銀杏不食種之庵前見者曰是三十年乃生公老矣能待之乎某不答作曰','釋慧空','宋','宋诗','song-poetry','','[]','蟠桃一實三千年，銀杏著子三十載。',64,'全唐诗/poet.song.106000.json','["蟠桃一實三千年，銀杏著子三十載。", "老僧只作旦暮看，汝莫匆匆宜少待。", "階前始芽今出屋，便是攜籃走僮僕。", "伴我東園看菜歸，與汝煎茶剝柔玉。"]'),
('97f1a1de-727c-493d-8be5-c9bd2957026a','尤溪補陀巖','釋慧空','宋','宋诗','song-poetry','','[]','巖下溪聲傾法雨，巖頭雲樹聳華冠。',32,'全唐诗/poet.song.106000.json','["巖下溪聲傾法雨，巖頭雲樹聳華冠。", "游人不入普門境，只作青山綠水看。"]'),
('7a38f0ea-0686-4e35-bb99-d1a848929667','通海井','釋慧空','宋','宋诗','song-poetry','','[]','疾風駕海生春潮，巖根石井澹不搖。',64,'全唐诗/poet.song.106000.json','["疾風駕海生春潮，巖根石井澹不搖。", "是中何曾得通理，而以名字懸巖腰。", "道人眼空君勿怪，大小混融無雜壞。", "呼僮探井濡硯時，是君硯中有滄海。"]'),
('aba8defb-8937-4235-bd30-53991cb97216','靜香軒','釋慧空','宋','宋诗','song-poetry','','[]','種竹竹既立，藝蘭蘭亦芳。',48,'全唐诗/poet.song.106000.json','["種竹竹既立，藝蘭蘭亦芳。", "爐熏安用許，靜極自生香。", "十客九常在，古人今不忘。", "如何杜陵老，獨喜贊公房。"]'),
('9dee2794-987e-4377-902d-f421aaa4fce6','聽雨亭','釋慧空','宋','宋诗','song-poetry','','[]','我行台雁之中途，一年兩憩安公廬。',96,'全唐诗/poet.song.106000.json','["我行台雁之中途，一年兩憩安公廬。", "不知昔人去此遠，但見水石清而虛。", "向來頗讀有則語，懸水瀟瀟日夜舉。", "道人似欲暗投明，故立此亭名聽雨。", "客如鏡清老更癡，入流截流誰得知。", "願公竹扉且常啟，我或發興來無時。"]'),
('d2f6b927-dcde-403b-95dc-c64020baeb81','東庵泉銘','釋慧空','宋','宋诗','song-poetry','','[]','脩竹盈門，寒泉迸石。',40,'全唐诗/poet.song.106000.json','["脩竹盈門，寒泉迸石。", "此老何爲，居之終日。", "泉知說法，竹亦能禪。", "洞山五位，臨濟三玄。"]'),
('d582732d-055f-4d1e-95f3-640d0349d3bb','四威儀  其一','釋慧空','宋','宋诗','song-poetry','','[]','行，忘其麤操得人憎。',20,'全唐诗/poet.song.106000.json','["行，忘其麤操得人憎。", "一舉足，趯倒佛前燈。"]'),
('b368a849-eb4e-4c53-bcb5-f3e44c29c9f2','四威儀  其二','釋慧空','宋','宋诗','song-poetry','','[]','住，對火浩歌敲火筋。',20,'全唐诗/poet.song.106000.json','["住，對火浩歌敲火筋。", "有客來，爐中出煨芋。"]'),
('0f1b59b9-543a-4b4b-bbb2-0658eb06ae3b','四威儀  其三','釋慧空','宋','宋诗','song-poetry','','[]','坐，入夏嚫錢無一箇。',20,'全唐诗/poet.song.106000.json','["坐，入夏嚫錢無一箇。", "催免丁，縣裏公人到。"]'),
('0601ed46-2566-43a3-a824-084b9f3a1201','四威儀  其四','釋慧空','宋','宋诗','song-poetry','','[]','臥，合眼乾坤都蓋過。',20,'全唐诗/poet.song.106000.json','["臥，合眼乾坤都蓋過。", "沒人知，晨雞剛說破。"]'),
('c64e4404-ca59-4962-9ff9-6e15ec1362f0','四威儀  其五','釋慧空','宋','宋诗','song-poetry','','[]','行，兩袖清風一瘦藤。',20,'全唐诗/poet.song.106000.json','["行，兩袖清風一瘦藤。", "人見玩，南寺打齋僧。"]'),
('e4813ec3-070a-4612-960a-eab5bf5ca4e2','四威儀  其六','釋慧空','宋','宋诗','song-poetry','','[]','住，五合黄陳半瓢醋。',20,'全唐诗/poet.song.106000.json','["住，五合黄陳半瓢醋。", "見客來，般般皆要做。"]'),
('f9e1bccd-1109-4a3c-b9d5-30c117d6dd80','四威儀  其七','釋慧空','宋','宋诗','song-poetry','','[]','坐，鼻孔婪巉眼睛大。',20,'全唐诗/poet.song.106000.json','["坐，鼻孔婪巉眼睛大。", "也有人，一見橫趨過。"]'),
('dad8b8cd-346f-44c9-af59-f9a39836128c','四威儀  其八','釋慧空','宋','宋诗','song-poetry','','[]','臥，鼻息雷鳴撼鄰座。',20,'全唐诗/poet.song.106000.json','["臥，鼻息雷鳴撼鄰座。", "忽翻身，鐵蛇橫大道。"]'),
('326e12ac-025f-4e8b-abc2-d78dbf746f6d','幽巖頭陀求化','釋慧空','宋','宋诗','song-poetry','','[]','火後幽巖山，中有四在句。',48,'全唐诗/poet.song.106000.json','["火後幽巖山，中有四在句。", "院在要人興，鐘在要人鑄。", "道在要人行，佛在要人做。", "頭陀寒拾流，四句盡分付。"]'),
('0f4b794d-02bb-4644-b85c-4bd3387dacea','與郛郎作骨董羹四首  其一','釋慧空','宋','宋诗','song-poetry','','[]','詩人例窮無可佳，借蔬貸粟東西家。',64,'全唐诗/poet.song.106000.json','["詩人例窮無可佳，借蔬貸粟東西家。", "胸中一字不療餒，奈此滿篋皆雲霞。", "郛郎之貧亦相似，眼高視世如空花。", "兩翁相值且相煦，薄糝藜羹終勝茶。"]'),
('777476e5-a3b3-45d7-afc3-fb0046cfdf5a','與郛郎作骨董羹四首  其二','釋慧空','宋','宋诗','song-poetry','','[]','詩人說盡山中佳，一原春色秦人家。',64,'全唐诗/poet.song.106000.json','["詩人說盡山中佳，一原春色秦人家。", "松自宮商竹自羽，空明樓觀溪明霞。", "微言到耳萬世事，香氣熏人百種花。", "同欄立盡聽吾語，蟹眼湯成催客茶。"]'),
('43ee9a79-1726-462e-9e9b-400b7aaaf980','與郛郎作骨董羹四首  其三','釋慧空','宋','宋诗','song-poetry','','[]','寒士百葅食藉佳，敢比八珍五侯家。',64,'全唐诗/poet.song.106000.json','["寒士百葅食藉佳，敢比八珍五侯家。", "分甘長貧體生粟，誰能一飽面發霞。", "自羹青松燒蘆菔，更雜石耳相天花。", "願留佳士宿清晝，細引鑪香深炷茶。"]'),
('f2916d51-6c6f-4796-90c9-a137a6201621','與郛郎作骨董羹四首  其四','釋慧空','宋','宋诗','song-poetry','','[]','上天既雨晴亦佳，黄雲滿壠金滿家。',64,'全唐诗/poet.song.106000.json','["上天既雨晴亦佳，黄雲滿壠金滿家。", "政須與子加餐飯，何苦預人三咽霞。", "今年明年吾自老，十日五日梅當花。", "豈無詩力禦強敵，已作睡魔聞釅茶。"]'),
('c2abed8c-1b70-4aa2-9dfc-489f27cf7a8a','四景  其一','釋慧空','宋','宋诗','song-poetry','','[]','沙寒雪後天，鳬雁將儔侶。',24,'全唐诗/poet.song.106000.json','["沙寒雪後天，鳬雁將儔侶。", "獨怪蓑笠翁，維舟一歸去。"]'),
('36e8f27a-8091-4787-aea4-a64663291a96','四景  其二','釋慧空','宋','宋诗','song-poetry','','[]','野闊烟迷樹，江清水學天。',24,'全唐诗/poet.song.106000.json','["野闊烟迷樹，江清水學天。", "白鷗蓋具眼，終日老人邊。"]'),
('a9671d7c-d652-44ef-aec7-5f6afba99ef0','四景  其三','釋慧空','宋','宋诗','song-poetry','','[]','急雨近欲黑，斜暉遠更明。',24,'全唐诗/poet.song.106000.json','["急雨近欲黑，斜暉遠更明。", "倚樓誰氏子，興與大江橫。"]'),
('ebf42ca8-79d3-495c-ab0f-db18194b07e7','四景  其四','釋慧空','宋','宋诗','song-poetry','','[]','快霽初無象，豁然千里間。',24,'全唐诗/poet.song.106000.json','["快霽初無象，豁然千里間。", "十年歸客眼，一點沃洲山。"]'),
('e2048723-aa81-49d4-879d-2212d7e5592c','贈吳晦叔雪峰造金剛','釋慧空','宋','宋诗','song-poetry','','[]','執金剛神安法界，塑之年深亦復壞。',48,'全唐诗/poet.song.106000.json','["執金剛神安法界，塑之年深亦復壞。", "居士有力如金剛，一念成就金剛王。", "魔塵不飛佛日光，門外人趨選佛場。"]'),
('ba0b6316-beba-458b-92b8-33fb3bf21c07','送湖州覺化主','釋慧空','宋','宋诗','song-poetry','','[]','佛子汝知世界海，有等世界多寶藏。',128,'全唐诗/poet.song.106000.json','["佛子汝知世界海，有等世界多寶藏。", "於中凡聖情非情，靡不皆依此寶住。", "或取而有爲慳貪，或捨而亡爲孤露。", "有亡取捨紛其懷，是皆未知真寶所。", "佛子汝宜入世間，開示人人令自悟。", "求心不有法本無，令此寶藏自然至。", "善諸一身寶不增，散之萬有寶猶故。", "以此奉供天人師，佛子是名真供養。"]'),
('6e77d4c3-de36-4e95-b7cb-22164a0d03a7','和無在木蛇歌','釋慧空','宋','宋诗','song-poetry','','[]','小小蛇兒大大身，曾吞衆象空巴陵。',142,'全唐诗/poet.song.106000.json','["小小蛇兒大大身，曾吞衆象空巴陵。", "歸蟠故山骨欲槁，混入草木人更徵。", "瞎屢生，甚手腳，不善提持休捉摸。", "枯木形骸似等閑，觸著傷人毒無藥。", "壽昌師，憐老病，遠遠遣來相問訊。", "擬欲庵頭伴老夫，預憂十月霜風勁。", "著把火，津送渠，依舊令教侍坐隅。", "重告之曰，蛇乎蛇乎，當如雲門應機忽突出，莫學嚴陽到老安其廬。"]'),
('f55a4439-79c9-440b-a16a-493d1f49877e','勸德上人莫作言語','釋慧空','宋','宋诗','song-poetry','','[]','凡物得其時則鳴，鳴之大者唯雷霆。',96,'全唐诗/poet.song.106000.json','["凡物得其時則鳴，鳴之大者唯雷霆。", "使雷常鳴不以節，人忘修省孰震驚。", "往時耆年深此旨，十度發言九度已。", "更有寶雲多口師，每見僧來面壁耳。", "豈似而今文字禪，駢頭竝駕爭後先。", "願公藏此千鈞重，等閑不射射必中。"]'),
('dce09b9e-16de-43b9-9c38-7aa79ccc3a56','草堂老師與靖名庵曰頓','釋慧空','宋','宋诗','song-poetry','','[]','縮腳水上橫行，掉臂空中直過。',28,'全唐诗/poet.song.106000.json','["縮腳水上橫行，掉臂空中直過。", "無端此箇老人，特地與伊注破。"]'),
('c36428d4-0e40-4959-b3da-b276a52bc1e8','送清知客','釋慧空','宋','宋诗','song-poetry','','[]','從生至老只這漢，歷歷孤明沒形段。',64,'全唐诗/poet.song.106000.json','["從生至老只這漢，歷歷孤明沒形段。", "雖無形段卻淆訛，要是紅爐千萬煅。", "如今何處是紅爐，兩浙江南試行看。", "空生老矣渾不知，栽松只在寒巖畔。"]'),
('7e54b30f-fabd-45c3-9c5c-e26750ab60a7','送僧歸凈衆','釋慧空','宋','宋诗','song-poetry','','[]','君不見昔日貴湖拋保福，苧溪溪畔曾叮囑。',134,'全唐诗/poet.song.106000.json','["君不見昔日貴湖拋保福，苧溪溪畔曾叮囑。", "汝歸東海我歸山，鳥道行人難措足。", "又不見無隱當年隱石師，獨傍巖阿燒栗皮。", "塵埃擾擾未歸客，四壁生涯說向誰。", "我今不向石師住，貴湖亦非吾住處。", "溪邊流水自西東，巖畔栗皮任堆聚。", "信腳來到五華峰，峰頭重整舊家風。", "爲報漳泉諸道友，吉山元是福山翁。"]'),
('5a5a0c14-90ce-4658-b2d6-9b508dfb3d39','頓庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','萬行不修，僧祇不歷。',20,'全唐诗/poet.song.106000.json','["萬行不修，僧祇不歷。", "千佛數中，位居第一。"]'),
('290bdc04-d44f-40ad-b06c-6b60daaf3636','頓庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','龍女獻珠成佛，善財彈指入門。',28,'全唐诗/poet.song.106000.json','["龍女獻珠成佛，善財彈指入門。", "若到頓庵門下，一時且作兒孫。"]'),
('2002ee4b-5845-41ca-b083-440d37e5e38a','無心道人梁長道以偈見寄次韻','釋慧空','宋','宋诗','song-poetry','','[]','法從本有何曾有，心自元無不用無。',32,'全唐诗/poet.song.106000.json','["法從本有何曾有，心自元無不用無。", "試問大雄山下虎，何如千里踏人駒。"]'),
('f6f7916b-30d5-4c9d-ae3b-c52fae3b9553','和慧知微雪韻','釋慧空','宋','宋诗','song-poetry','','[]','覆蓋乾坤似有功，洞然明白卻無蹤。',32,'全唐诗/poet.song.106000.json','["覆蓋乾坤似有功，洞然明白卻無蹤。", "其如未識無蹤意，屑玉霏霏落眼中。"]'),
('9665f6d0-adfe-456e-887e-3b8a4b74c794','慧知微以布衫送壽昌可師有偈答之戲成四首  其一','釋慧空','宋','宋诗','song-poetry','','[]','一物全無盡力擔，相逢江北又江南。',32,'全唐诗/poet.song.106000.json','["一物全無盡力擔，相逢江北又江南。", "向來貼肉那堪語，更著渠儂一布衫。"]'),
('71944d3a-1361-47c7-baa5-697bcf1f4895','慧知微以布衫送壽昌可師有偈答之戲成四首  其二','釋慧空','宋','宋诗','song-poetry','','[]','著時人顯衫還隱，不著人亡衫卻存。',32,'全唐诗/poet.song.106000.json','["著時人顯衫還隱，不著人亡衫卻存。", "隱顯存亡是何物，黄金鑄出鐵崑崙。"]'),
('acb7d6d8-c249-4ea0-82a7-44d81796e50e','慧知微以布衫送壽昌可師有偈答之戲成四首  其三','釋慧空','宋','宋诗','song-poetry','','[]','寸絲不掛魚游網，萬善嚴身月入雲。',32,'全唐诗/poet.song.106000.json','["寸絲不掛魚游網，萬善嚴身月入雲。", "若是壽昌端的處，明年一領更煩君。"]'),
('19ee9c06-4163-40a9-a7b8-b9f69f8ba948','慧知微以布衫送壽昌可師有偈答之戲成四首  其四','釋慧空','宋','宋诗','song-poetry','','[]','普賢高繫象王袴，妙德長拖師子衫。',32,'全唐诗/poet.song.106000.json','["普賢高繫象王袴，妙德長拖師子衫。", "遣向壽昌爲侍者，一人不肯一人甘。"]'),
('42a96e10-7c7b-45a4-86cb-f34b186995be','送可師歸西山兼簡法華無證','釋慧空','宋','宋诗','song-poetry','','[]','半世幾離合，翛然無住身。',48,'全唐诗/poet.song.106000.json','["半世幾離合，翛然無住身。", "又爲一去客，元是再來人。", "野宿風鳴雪，江行梅破春。", "兩翁如問我，爲話鬢毛新。"]'),
('2cd849c3-96cb-407d-83d3-d10e09567519','雪堂仍舊老師和予送可師新字韻見招復作五首寄之兼呈無證  其一','釋慧空','宋','宋诗','song-poetry','','[]','夢歷百城路，笑翻牀上身。',48,'全唐诗/poet.song.106000.json','["夢歷百城路，笑翻牀上身。", "惟應箇些子，所以見吾人。", "玉藴西山重，花開南浦春。", "異時冰雪裏，仍舊一枝新。"]'),
('35d4ba53-b3bf-44b8-b59c-53fd297a076a','雪堂仍舊老師和予送可師新字韻見招復作五首寄之兼呈無證  其二','釋慧空','宋','宋诗','song-poetry','','[]','不觸波瀾手，而彰名句身。',48,'全唐诗/poet.song.106000.json','["不觸波瀾手，而彰名句身。", "向來天上寺，得此眼中人。", "一別湘湖路，三回嶺海春。", "何時清夜坐，聽我話韶新。"]'),
('e5ca4b56-646f-42c4-bcc1-1effb1d1a908','雪堂仍舊老師和予送可師新字韻見招復作五首寄之兼呈無證  其三','釋慧空','宋','宋诗','song-poetry','','[]','干戈平定日，湖海倦游身。',48,'全唐诗/poet.song.106000.json','["干戈平定日，湖海倦游身。", "況得君爲社，招呼我輩人。", "初無家似燕，宜有喜如春。", "懸想西山下，雨餘鐘鼓新。"]'),
('bedd2a47-905d-4335-b449-fa6e8181cfc1','雪堂仍舊老師和予送可師新字韻見招復作五首寄之兼呈無證  其四','釋慧空','宋','宋诗','song-poetry','','[]','妙湛清虛理，芭蕉立井身。',48,'全唐诗/poet.song.106000.json','["妙湛清虛理，芭蕉立井身。", "惟君俱得地，獨我不如人。", "書辱寒溫問，茶分安樂春。", "殷勤拜佳賜，自汲井花新。"]'),
('97b72d07-6024-44ee-9edc-62d6b4f6686e','雪堂仍舊老師和予送可師新字韻見招復作五首寄之兼呈無證  其五','釋慧空','宋','宋诗','song-poetry','','[]','木蛇頭带角，古路獨橫身。',48,'全唐诗/poet.song.106000.json','["木蛇頭带角，古路獨橫身。", "大有傍觀者，初無踏著人。", "病來思自養，此去或同春。", "送老須何物，窗明貝葉新。"]'),
('4be7226e-a1d1-45f1-a221-f954a6a1cb92','送人化修上  其一','釋慧空','宋','宋诗','song-poetry','','[]','爾祖傳家唯此鉢，中雖無物不憂貧。',32,'全唐诗/poet.song.106000.json','["爾祖傳家唯此鉢，中雖無物不憂貧。", "持從鬧市門頭過，倒廩傾囷自有人。"]'),
('38581c55-0893-4080-b60c-5a192ffa978b','送人化修上  其二','釋慧空','宋','宋诗','song-poetry','','[]','盡謂黄龍山裏龍，彌年翻去碧潭空。',32,'全唐诗/poet.song.106000.json','["盡謂黄龍山裏龍，彌年翻去碧潭空。", "君行爲報居人道，遐邇雖殊一雨同。"]'),
('9ff429d2-2096-41b7-80fc-54d57daf16a0','送化士','釋慧空','宋','宋诗','song-poetry','','[]','洞山身如椰子大，不畜粒米與莖菜。',96,'全唐诗/poet.song.106000.json','["洞山身如椰子大，不畜粒米與莖菜。", "無人烟處門打開，接待方來也奇怪。", "吉山從作山中主，只用十方菩薩子。", "二時鐘鼓不曾虧，是汝持來還供汝。", "兩翁同中具生殺，明眼高流試提撥。", "可中見得無少差，是謂能持吉山鉢。"]'),
('5ec91d61-1014-4b08-8484-d819d3c88ac0','送茶化士  其一','釋慧空','宋','宋诗','song-poetry','','[]','建溪深與吉山鄰，勝氣潛通不在陳。',32,'全唐诗/poet.song.106000.json','["建溪深與吉山鄰，勝氣潛通不在陳。", "但看吉山茶椀裏，雪花時現建溪春。"]'),
('bcc2ec34-c59a-4ff9-8181-388b633d8b58','送茶化士  其二','釋慧空','宋','宋诗','song-poetry','','[]','五湖雲水訪山家，不問親疏盡與茶。',32,'全唐诗/poet.song.106000.json','["五湖雲水訪山家，不問親疏盡與茶。", "若省此茶來處者，出門風擺綠楊斜。"]'),
('2cd9b9aa-3596-43fb-bf3d-f6139dac831e','送茶化士  其三','釋慧空','宋','宋诗','song-poetry','','[]','正味森嚴來處異，叢林多用顯家風。',64,'全唐诗/poet.song.106000.json','["正味森嚴來處異，叢林多用顯家風。", "趙州一味客心盡，風穴三巡主意濃。", "要使人人開睡眼，且煩小小現神通。", "郝源北苑大雲際，盡入吉山茶椀中。"]'),
('cb8e5391-b467-4974-b8dd-1d9afcbe21ef','送宗上人遊方','釋慧空','宋','宋诗','song-poetry','','[]','華峰壁立爲初友，雁宕深奇爲指南。',32,'全唐诗/poet.song.106000.json','["華峰壁立爲初友，雁宕深奇爲指南。", "臨濟兒孫上封老，見今說法在靈巖。"]'),
('84577bd9-c664-4ffa-985c-7e315de6ba27','送璉兄之雲門','釋慧空','宋','宋诗','song-poetry','','[]','人言學禪如學射，誤得同流走天下。',64,'全唐诗/poet.song.106000.json','["人言學禪如學射，誤得同流走天下。", "夢中射落蟭螟窠，開眼看來無縫罅。", "無縫罅兮不爲差，萬煅鑪中尋尾靶。", "翻身築著老雲門，從古風顛稱普化。"]'),
('084a4d42-32ed-4347-bdcd-7c2906fd126c','送澤化士兼簡雲門延福二老  其一','釋慧空','宋','宋诗','song-poetry','','[]','青蛇在握心方壯，赤驥追風路不遙。',32,'全唐诗/poet.song.106000.json','["青蛇在握心方壯，赤驥追風路不遙。", "透得雲門鐵關過，海濤聲撼洛陽橋。"]'),
('36f680a4-1873-4510-833c-23ec2c9282f5','送澤化士兼簡雲門延福二老  其二','釋慧空','宋','宋诗','song-poetry','','[]','吉山何啻百彌盧，袖裏攜來一物無。',32,'全唐诗/poet.song.106000.json','["吉山何啻百彌盧，袖裏攜來一物無。", "前路逢人即拈出，不知誰是赤鬚胡。"]'),
('c0bb0256-eec7-42ce-a65f-44a59b5738cd','送澤化士兼簡雲門延福二老  其三','釋慧空','宋','宋诗','song-poetry','','[]','過了雲門更好看，前頭孤峻有姜山。',32,'全唐诗/poet.song.106000.json','["過了雲門更好看，前頭孤峻有姜山。", "三關一箭收功後，南海波斯念八還。"]'),
('54fc430f-3668-472e-a4a1-f9a91e9ba7c1','送巾扇街坊','釋慧空','宋','宋诗','song-poetry','','[]','華巾未解心中結，阿難有理難伸說。',64,'全唐诗/poet.song.106000.json','["華巾未解心中結，阿難有理難伸說。", "犀牛扇破索牛兒，鹽官爲物心偏切。", "上人幸是手眼親，獨用雙拈此時節。", "一條秋水凈無痕，八面清風消惱熱。"]'),
('6adf0ab7-f51f-4ac8-b5be-b5f4bca4aaaa','送知殿  其一','釋慧空','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西天胡子沒髭鬚，南北禪和苦覓渠。',32,'全唐诗/poet.song.106000.json','["西天胡子沒髭鬚，南北禪和苦覓渠。", "合眼相逢開眼笑，君山點破洞庭湖。"]'),
('f4cfe0ff-5ce2-43ad-b657-2863b434d331','送知殿  其二','釋慧空','宋','宋诗','song-poetry','','[]','人人盡有光明，只恐點時不到。',28,'全唐诗/poet.song.106000.json','["人人盡有光明，只恐點時不到。", "試攜投子油瓶，一一與伊按過。"]'),
('2b9cdf22-1c92-4471-913e-f0fda1f1d127','送知殿  其三','釋慧空','宋','宋诗','song-poetry','','[]','諸佛光中衆生，衆生光中諸佛。',28,'全唐诗/poet.song.106000.json','["諸佛光中衆生，衆生光中諸佛。", "若明生佛一如，便見重重涉入。"]'),
('10f87c30-e78b-4640-a686-219b2d1e11a4','送知殿  其四','釋慧空','宋','宋诗','song-poetry','','[]','脩廊下夜沈沈，古殿中香冉冉。',28,'全唐诗/poet.song.106000.json','["脩廊下夜沈沈，古殿中香冉冉。", "要參過去燈明，只在如今一點。"]'),
('2532f11e-4363-4802-a2d4-b11e5946ea8f','送知殿  其五','釋慧空','宋','宋诗','song-poetry','','[]','黑月夜中無別，行人下足即疑。',28,'全唐诗/poet.song.106000.json','["黑月夜中無別，行人下足即疑。", "須得之燈發現，令渠是處光輝。"]'),
('cb26ee34-143c-42dc-b71c-ce682b158ce9','送街坊','釋慧空','宋','宋诗','song-poetry','','[]','道在未能速說，鉢空且要人持。',28,'全唐诗/poet.song.106000.json','["道在未能速說，鉢空且要人持。", "驀地街頭築著，方知此老慈悲。"]'),
('a4836e30-0dc3-4d72-8adc-10f8323f0cd0','送疏山化主','釋慧空','宋','宋诗','song-poetry','','[]','疏山開山矮師叔，手中木蛇稱最毒。',64,'全唐诗/poet.song.106000.json','["疏山開山矮師叔，手中木蛇稱最毒。", "近江無水山無柴，我昔到時無不足。", "休論苦瓠與甜瓜，是聖是凡同一家。", "但看開山好基業，與伊隨分著些些。"]'),
('fb76027f-af7d-471e-b12f-3096491cba39','次韻知微無外石門相會','釋慧空','宋','宋诗','song-poetry','','[]','鐵牛插翅快於鶻，石虎擡頭驚倒人。',32,'全唐诗/poet.song.106000.json','["鐵牛插翅快於鶻，石虎擡頭驚倒人。", "笑把方山輕捩轉，幾多游子失關津。"]'),
('d905cd22-6521-4c16-bfaa-a188134e86e1','送照上人','釋慧空','宋','宋诗','song-poetry','','[]','五華崷崒白雲中，送盡行人是此峰。',32,'全唐诗/poet.song.106000.json','["五華崷崒白雲中，送盡行人是此峰。", "若問此峰何面目，但言瓶錫住經冬。"]'),
('4241c330-0f0c-488e-9f86-2eeea0ec1039','送復上人之雪竇','釋慧空','宋','宋诗','song-poetry','','[]','復也雖少年，其志亦猛烈。',48,'全唐诗/poet.song.106000.json','["復也雖少年，其志亦猛烈。", "發足指乳峰，赤手探虎穴。", "直須得虎歸，不可只麽說。", "送之披秀前，歲暮千峰雪。"]'),
('0f3e04ca-d5d2-4fcd-a22b-5cfdddcee224','送超侍者','釋慧空','宋','宋诗','song-poetry','','["\u897f\u6e56"]','空生衆中居，似欠人偈債。',60,'全唐诗/poet.song.106000.json','["空生衆中居，似欠人偈債。", "超禪歸臨安，亦來相惱害。", "布袋連底翻，一還無復載。", "閉門卷新經，後來且莫怪。", "去去稱何言，西湖蓮子大。"]'),
('d502ae22-6cee-427a-81fe-8abc00828269','疏山作餬餅草堂老師出語云色香味觸具四塵且道餬餅具幾塵是時衆皆無語老師末後云大刀三十口以頌系其後','釋慧空','宋','宋诗','song-poetry','','[]','一處打開，五處捏就。',20,'全唐诗/poet.song.106000.json','["一處打開，五處捏就。", "中下之流，槌聲斷後。"]'),
('60069b7a-62f4-4c47-a849-5b448f244c32','送化士','釋慧空','宋','宋诗','song-poetry','','[]','一偈普送諸人，諸人同乘一偈。',56,'全唐诗/poet.song.106000.json','["一偈普送諸人，諸人同乘一偈。", "持遍萬戶千門，箇箇不落第二。", "有則直是當陽，無則極難回避。", "有無二彼俱收，丹山與汝巴鼻。"]'),
('2c6ad52f-3f25-4b88-b5b5-24d729c40c42','和彥忱舍弟與保壽靈空老二首  其一','釋慧空','宋','宋诗','song-poetry','','[]','家山雖好未安住，鄰寺有僧時訪尋。',32,'全唐诗/poet.song.106000.json','["家山雖好未安住，鄰寺有僧時訪尋。", "拈出毛頭生死海，打翻歸去笑吟吟。"]'),
('7b291a79-7b61-4b1c-b1e1-ded11e87e172','和彥忱舍弟與保壽靈空老二首  其二','釋慧空','宋','宋诗','song-poetry','','[]','鼻孔當陽曾嗟卻，眼睛在眼費追尋。',32,'全唐诗/poet.song.106000.json','["鼻孔當陽曾嗟卻，眼睛在眼費追尋。", "一朝眼在鼻孔上，和得靈空雪子吟。"]'),
('d3ff2ed7-b578-4d0f-8f22-d48aedc50363','送白兄歸豫章','釋慧空','宋','宋诗','song-poetry','','[]','我今懶說偈，汝亦莫言別。',72,'全唐诗/poet.song.106000.json','["我今懶說偈，汝亦莫言別。", "莫歸剛要歸，不說又著說。", "土宿騎黄牛，旌陽鑄生鐵。", "老胡道未行，當門齒先折。", "三年留客歸，一等是饒舌。", "努力慎長途，春寒天欲雪。"]'),
('20eb1a85-f313-42a7-9423-b7731f6df404','送智道者','釋慧空','宋','宋诗','song-poetry','','[]','宛陵道者菩薩，化遍東吳今到此。',63,'全唐诗/poet.song.106000.json','["宛陵道者菩薩，化遍東吳今到此。", "干戈叢裏月行空，憂苦海中蓮出水。", "知空曾見老衡陽，冷火枯牀同夜雨。", "大有衡陽跳竈兒，珍重此行俱訪取。"]'),
('9ad8ae25-0b16-4845-a740-5ad0cfdeef23','送堯愷二上人','釋慧空','宋','宋诗','song-poetry','','[]','四山如壁不可去，當處如火不可住。',83,'全唐诗/poet.song.106000.json','["四山如壁不可去，當處如火不可住。", "上人既是要游方，可中須得超方句。", "珍重便行萬八千，通霄有路恒沙數。", "不落平常試道者。", "道道若道未得，此去秦溪有直指。", "老子若能見之，必爲汝道。"]'),
('80001a2c-086f-4fd6-930f-55832420a4eb','與洪兄','釋慧空','宋','宋诗','song-poetry','','[]','無傷機器微，我此法門大。',48,'全唐诗/poet.song.106000.json','["無傷機器微，我此法門大。", "萬殊紛目前，一衲俱蓋過。", "天外出頭來，衆中交腳坐。", "佛祖是伊成，未言遭一唾。"]'),
('8173a55c-4bd1-4532-83ae-086f864c3aab','和東禪以李侍郎庵招  其一','釋慧空','宋','宋诗','song-poetry','','[]','大隱何曾棄簪組，醉鄉有路入無何。',32,'全唐诗/poet.song.106000.json','["大隱何曾棄簪組，醉鄉有路入無何。", "百年快活自不徹，誰肯尋人到薜蘿。"]'),
('3c1ed68d-d604-4a9e-8466-1a67b666e774','和東禪以李侍郎庵招  其二','釋慧空','宋','宋诗','song-poetry','','[]','敢將不出以爲高，朽索其如六馬何。',32,'全唐诗/poet.song.106000.json','["敢將不出以爲高，朽索其如六馬何。", "賴有舀溪長柄杓，不妨霜月在松蘿。"]'),
('7a9ff84c-0b26-46b4-b930-8f4c2e7ed072','送麥頭','釋慧空','宋','宋诗','song-poetry','','[]','淵明非達士，乞食拙言詞。',48,'全唐诗/poet.song.106000.json','["淵明非達士，乞食拙言詞。", "誰知我輩人，佳處正在茲。", "所化果何物，持來復是誰。", "山前小麥熟，行矣今其時。"]'),
('2cf8b464-b122-4649-b182-2a02c5a396d9','乞鹽','釋慧空','宋','宋诗','song-poetry','','[]','水中鹽味舌頭眼，不爲無形便謂無。',32,'全唐诗/poet.song.106000.json','["水中鹽味舌頭眼，不爲無形便謂無。", "試向秦溪溪上問，口中大有赤鬚胡。"]'),
('1a410442-a37c-4044-8027-33f5bc13378c','與諸友','釋慧空','宋','宋诗','song-poetry','','[]','龍亡大澤蚖蛇出，火炎崑山玉石焚。',64,'全唐诗/poet.song.106000.json','["龍亡大澤蚖蛇出，火炎崑山玉石焚。", "百種交前今盡見，一時零落古無聞。", "家居海角荔枝塢，書斷江南鴻雁群。", "記得風前二三月，客亭長短我隨君。"]'),
('44328a2a-d122-491d-87a1-0c2ef2c7e948','送空兄  其一','釋慧空','宋','宋诗','song-poetry','','[]','空不議宗宗乃通，宗不識空空乃同。',32,'全唐诗/poet.song.106000.json','["空不議宗宗乃通，宗不識空空乃同。", "同風更得通風句，只這空宗是祖翁。"]'),
('ae326df0-3b16-495f-8603-dac22bed0bfc','送空兄  其二','釋慧空','宋','宋诗','song-poetry','','[]','衲僧杖子天然別，千里萬里一條鐵。',32,'全唐诗/poet.song.106000.json','["衲僧杖子天然別，千里萬里一條鐵。", "點著閩山即便回，敢保老兄猶未徹。"]'),
('f4a23d84-0dd5-4576-b813-a44a096c4f43','過靈石賦頑庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','道人楊歧五世孫，曾持鈯斧開雲門。',129,'全唐诗/poet.song.106000.json','["道人楊歧五世孫，曾持鈯斧開雲門。", "屬時多艱衆且去，百折午摧君獨存。", "住庵了卻行腳債，隨緣混入衆生界。", "和泥合水二頃田，接待方來一莖菜。", "我初北歸先過君，彼此老大言無文。", "長年聽法庵外石，永日不藏巖上雲。", "莫嫌家風四立君地，應用河沙體堅密。", "客來有以頑自疑，五問道人三不知。"]'),
('e1213a9e-210a-4c39-a588-be6882c143ee','過靈石賦頑庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','學頑未到頑之孫，再拜頑庵求入門。',128,'全唐诗/poet.song.106000.json','["學頑未到頑之孫，再拜頑庵求入門。", "當時此老有何說，火後莖茅今尚存。", "人貧信是思舊債，一飯重尋香積界。", "堂上未瞻癡絕翁，溪頭已見隨流菜。", "惟頑顯頑分不分，以水投水無留文。", "地爐火暖坐自睡，金博朝參寒起雲。", "與君相個君莫逆，向來不疏今不密。", "明朝山住雲自飛，後會有無俱不知。"]'),
('96e6554b-e089-490d-b3fa-0f23f600826b','亂後入黄龍途中示道伴','釋慧空','宋','宋诗','song-poetry','','[]','羯胡如鬼馬如風，雪刃縱橫到處空。',32,'全唐诗/poet.song.106000.json','["羯胡如鬼馬如風，雪刃縱橫到處空。", "生死路頭君自看，活人全在死人中。"]'),
('c82f5f47-331c-4782-823a-3356ddc21370','送川覺','釋慧空','宋','宋诗','song-poetry','','[]','鯉魚山，赤梢鯉。',56,'全唐诗/poet.song.106000.json','["鯉魚山，赤梢鯉。", "辰錦砂，未爲比。", "吸盡九脈泉，透出三峽水。", "上得百尺竿，墮在齏甕裏。", "桃花浪急禹門高，雷動不驚爭奈何。"]'),
('ad7f9d02-19bb-493f-a2ac-b00f8629f9e8','送人歸臨漳兼簡湛首座','釋慧空','宋','宋诗','song-poetry','','[]','白雲埋藏丘壑裏，天風無端忽吹起。',64,'全唐诗/poet.song.106000.json','["白雲埋藏丘壑裏，天風無端忽吹起。", "雁山聳秀我杖頭，漳水澄清君腳底。", "一南一北恰同途，雖曰同途不相似。", "到家爲我到龍山，問訊山中湛老子。"]'),
('b9b22053-f015-4175-af70-eed22db55c7f','別一老還鄉','釋慧空','宋','宋诗','song-poetry','','[]','遠去羌峰最上層，齊開八目带力行。',32,'全唐诗/poet.song.106000.json','["遠去羌峰最上層，齊開八目带力行。", "更深誰向傍邊立，樹上安身兩弟兄。"]'),
('e1d04fd6-0d0d-4842-9d5d-e538ae273e4d','送人往臨漳  其一','釋慧空','宋','宋诗','song-poetry','','[]','通身紅爛不堪歸，只爲無人識得伊。',32,'全唐诗/poet.song.106000.json','["通身紅爛不堪歸，只爲無人識得伊。", "覓得休糧聖方子，刺桐花下笛橫吹。"]'),
('5d3e158c-f0e1-4f99-8a82-7b195466ccb3','送人往臨漳  其二','釋慧空','宋','宋诗','song-poetry','','[]','休處言休便好休，家山春色滿揚州。',32,'全唐诗/poet.song.106000.json','["休處言休便好休，家山春色滿揚州。", "何須更說通身句，歷歷東風百草頭。"]'),
('832f6aba-7fe5-455a-9360-439553028e92','與修漏頭陀  其一','釋慧空','宋','宋诗','song-poetry','','[]','上頭一竅最淆訛，多少郇公不奈何。',32,'全唐诗/poet.song.106000.json','["上頭一竅最淆訛，多少郇公不奈何。", "每見諸方多指注，誰知笑殺此頭陀。"]'),
('d61072e0-b168-41ae-b709-bbc6a41f6fbd','與修漏頭陀  其二','釋慧空','宋','宋诗','song-poetry','','[]','是處叢林走一遭，敲磚打瓦不辭勞。',32,'全唐诗/poet.song.106000.json','["是處叢林走一遭，敲磚打瓦不辭勞。", "忽然踏著通天竅，始覺從前立處高。"]'),
('d2088b2a-691c-485e-bd5d-11883aed0877','送十二歲童兒','釋慧空','宋','宋诗','song-poetry','','[]','男兒十二有如此，不減當年人姓甘。',64,'全唐诗/poet.song.106000.json','["男兒十二有如此，不減當年人姓甘。", "避寇春風更春雨，舉家江北又江南。", "藜羹脫粟依僧飯，斷簡殘編近佛龕。", "我亦從來識英物，夜深應與阿戎談。"]'),
('7f343209-92d3-4d3f-a88f-12084ec2ae61','和壽山木魚韻','釋慧空','宋','宋诗','song-poetry','','[]','透出波瀾外，橫身任探尋。',48,'全唐诗/poet.song.106000.json','["透出波瀾外，橫身任探尋。", "只知打我腹，不覺痛他心。", "香積晨炊熟，秋廊夜月深。", "重重報君道，千眼是觀音。"]'),
('06aa91fb-5ad5-4868-b948-70139264f358','和直指答方仲姚','釋慧空','宋','宋诗','song-poetry','','[]','海燕坐間談實相，泥人夢裏獲真如。',32,'全唐诗/poet.song.106000.json','["海燕坐間談實相，泥人夢裏獲真如。", "空中種黍長年飽，陸地栽蓮永不枯。"]'),
('6f3bbea8-6f86-48b4-926e-62fd7e982bee','與香山虛頭陀','釋慧空','宋','宋诗','song-poetry','','[]','庵中有主從君住，無主外來俱得路。',128,'全唐诗/poet.song.106000.json','["庵中有主從君住，無主外來俱得路。", "雲烟眯目山礙膺，榛莽欺人溪澗怒。", "看他本色住庵人，捏聚大千無一塵。", "自見泥牛鬬入海，不記住來經幾春。", "頭陀頭陀休趁鬨，一世初無一炊夢。", "口邊白醭未暇揩，誰能更乞諸方頌。", "持來拋放烈焰中，歸種香山芋與菘。", "驀地钁頭輕築著，林間石虎吼天風。"]'),
('8d3084df-b8a9-4c8b-a641-0e5296ee5e26','和澹庵見留','釋慧空','宋','宋诗','song-poetry','','[]','未暇住爲巖穴主，尚堪行作水雲僧。',64,'全唐诗/poet.song.106000.json','["未暇住爲巖穴主，尚堪行作水雲僧。", "賓頭諾詎諸尊者，久在峰頭望我能。", "把住如何卻放行，明頭暗合暗頭明。", "豐干冷坐寒山笑，二月青田春水生。"]'),
('10b89657-b7d6-4b8a-964f-0f7270694c89','留度藏主','釋慧空','宋','宋诗','song-poetry','','[]','可行即行今未可，得住且住時已寒。',32,'全唐诗/poet.song.106000.json','["可行即行今未可，得住且住時已寒。", "霜芥滿園禾又熟，胡家曲子萬年歡。"]'),
('72cb3838-2835-4653-9c4d-71a3c2855666','與照上人','釋慧空','宋','宋诗','song-poetry','','[]','照時遠近俱到，用時毫髪無遺。',56,'全唐诗/poet.song.106000.json','["照時遠近俱到，用時毫髪無遺。", "直得二途不涉，方能照用同時。", "趯倒趙州略彴，拈起馬師簸箕。", "任待通身是眼，當陽未免膠𥻿。"]'),
('73aad27a-e5db-4f91-a6d0-4f151aad73ba','與建州介瀨溪翁道人','釋慧空','宋','宋诗','song-poetry','','[]','翁翁介瀨溪頭住，我亦曾從溪上過。',64,'全唐诗/poet.song.106000.json','["翁翁介瀨溪頭住，我亦曾從溪上過。", "一鉢飯香留不住，信根道眼兩無差。", "菩提種子男兼女，清浄家風菜與茶。", "大佛所傳無別法，只今猶有老僧伽。"]'),
('b05d04a6-95f3-4a52-8b92-fd04c6c5c62d','送靈石修造','釋慧空','宋','宋诗','song-poetry','','[]','靈石有殿不知年，日炙風吹太可憐。',64,'全唐诗/poet.song.106000.json','["靈石有殿不知年，日炙風吹太可憐。", "今日諸郎爭著力，要令突兀在人前。", "人前莫作土木見，八面渾無刀斧痕。", "似此殿成安底佛，釋迦彌勒是他孫。"]'),
('3ec4c424-f8ad-47ee-83d2-2053eee10b36','建州梅仙壇','釋慧空','宋','宋诗','song-poetry','','[]','漢室中微竹生馬，先生一尉何卑下。',96,'全唐诗/poet.song.106000.json','["漢室中微竹生馬，先生一尉何卑下。", "天門九重呼不聞，避時乃作居山者。", "朅來山間藥道成，雲軺高舉風馭輕。", "大溪之南古壇在，空山落日秋蟬鳴。", "我寓其鄰喜清曠，時來送眼風烟上。", "遺丹存亡今不知，癡人且啗壇中泥。"]'),
('633d1123-8c59-4525-bb25-083b1d5a0b77','送僧上徑山兼簡妙喜老人  其一','釋慧空','宋','宋诗','song-poetry','','[]','大士昨來聞出世，阿師今日又登途。',32,'全唐诗/poet.song.106000.json','["大士昨來聞出世，阿師今日又登途。", "杖頭倘有閑田地，寄我山頭一紙書。"]'),
('5b12ea17-ee68-4e9b-9a78-0697e2136346','送僧上徑山兼簡妙喜老人  其二','釋慧空','宋','宋诗','song-poetry','','[]','半幅全封一字無，莫嫌者也及之乎。',32,'全唐诗/poet.song.106000.json','["半幅全封一字無，莫嫌者也及之乎。", "還將昔日芭蕉語，寫作王公十道符。"]'),
('508ae36d-de26-4b98-a7e1-ee38c8612d00','和支提秀和尚','釋慧空','宋','宋诗','song-poetry','','[]','尊宿老河東，叢林之眼目。',96,'全唐诗/poet.song.106000.json','["尊宿老河東，叢林之眼目。", "靈明劍倚天，秀潤山含玉。", "憶昨台雁行，再拜初接足。", "森嚴聽法徒，天冠千眷屬。", "不以空也愚，斯事力見篤。", "別來化城鐘，屢度新豐曲。", "一字妙無傳，四方牢記錄。", "安得從之游，寒泉薦秋菊。"]'),
('a6b4bd0f-601f-4476-b038-502a5d586677','合三韻酬夢石二首  其一','釋慧空','宋','宋诗','song-poetry','','[]','老人說法山答鐘，不以一重去一重。',96,'全唐诗/poet.song.106000.json','["老人說法山答鐘，不以一重去一重。", "後生望道未之見，鏤冰琢雪徒彫蟲。", "門前蟻合忽雷吼，蟲臂墮階爭出手。", "三文撈波年代深，化成老婆黑而醜。", "東山擊節夢石歌，空花之影陽焰波。", "不知真僞爭幾何，高燒榾𣔻春寒多。"]'),
('bb26ae1b-f768-4386-84ee-a369cfd3d139','合三韻酬夢石二首  其二','釋慧空','宋','宋诗','song-poetry','','[]','淡齏薄粥歠兩鍾，粗疏惡布著兩重。',96,'全唐诗/poet.song.106000.json','["淡齏薄粥歠兩鍾，粗疏惡布著兩重。", "大開摩醯頂門眼，莫作師子身中蟲。", "石頭未必能真吼，臨濟只是栽松手。", "焚其禪版增其光，受其鈯斧彰其醜。", "夢石擊節東山歌，亘天烈焰橫清波。", "小僧再拜問如何，三十山藤未是多。"]'),
('1dcff1fb-27ca-45ad-a466-de4ae9b7b09c','胡相士求偈三年予不說今秋復此與之','釋慧空','宋','宋诗','song-poetry','','[]','道人無心寧有相，以相求之無乃妄。',144,'全唐诗/poet.song.106000.json','["道人無心寧有相，以相求之無乃妄。", "更言壽夭吉與凶，空裏覓痕鏡中像。", "胡君得處初不然，無相之中以相言。", "聖凡良賤皆一目，但有絲毫俱現前。", "說既無私聽無忤，禍福死生皆夢事。", "我惟以此入世間，猶如化人觀幻士。", "孫陽於馬師曠琴，未可與之同日語。", "老僧大笑客出門，秋雲駕雨過前村。", "去去不須談此老，三年一偈真賺我。"]'),
('fd3868e0-1210-4bbf-b55f-32844b205ee3','謝顔庵主拄杖','釋慧空','宋','宋诗','song-poetry','','[]','拄杖一枝，蒼龍出水。',20,'全唐诗/poet.song.106000.json','["拄杖一枝，蒼龍出水。", "大流激湍，衆峰齊峙。"]'),
('cd99a24f-7ce1-44fe-bf7a-febaeab7db1e','回澤老','釋慧空','宋','宋诗','song-poetry','','[]','昔人住庵，水流菜葉。',20,'全唐诗/poet.song.106000.json','["昔人住庵，水流菜葉。", "識者非之，況紙上墨。"]'),
('a96896bb-59b6-4344-aff6-bdc616c9f4cb','和靈空見贈  其一','釋慧空','宋','宋诗','song-poetry','','[]','跨海鐵牛真有力，依山土豹敢言威。',32,'全唐诗/poet.song.106000.json','["跨海鐵牛真有力，依山土豹敢言威。", "春風二月江南路，相別相逢眼似眉。"]'),
('2b0326c3-858c-43e0-9e62-378b05166e7b','和靈空見贈  其二','釋慧空','宋','宋诗','song-poetry','','[]','怒雷剨地衡信，皎日行天保壽書。',31,'全唐诗/poet.song.106000.json','["怒雷剨地衡信，皎日行天保壽書。", "從此華山山腳下，又添潘閬倒騎驢。"]'),
('0ec3df2e-4a30-491f-8904-de45ef642a6e','送泉州積善專使','釋慧空','宋','宋诗','song-poetry','','[]','積善山中僧，有膽如天大。',48,'全唐诗/poet.song.106000.json','["積善山中僧，有膽如天大。", "敢持居士書，來覓空上座。", "跨門不肯休，著了方知道。", "歸語晉江人，大蟲裹紙帽。"]'),
('f549ee8d-fd69-4f4b-8fbf-1c62ff0aa626','送泉州使臣','釋慧空','宋','宋诗','song-poetry','','[]','只這佛國土，遍滿十方空。',48,'全唐诗/poet.song.106000.json','["只這佛國土，遍滿十方空。", "毘耶金粟老，說法在其中。", "徹骨慈悲棒，當機激箭鋒。", "空生打退鼓，不敢現神通。"]'),
('2361cc69-f071-44e3-8a01-e96b7a876380','送潮州定兄','釋慧空','宋','宋诗','song-poetry','','[]','臨漳拜起，秀峰出氣。',46,'全唐诗/poet.song.106000.json','["臨漳拜起，秀峰出氣。", "潮落海門，月生雲際。", "定則不二，二則不定。", "鰐魚潭底黑如烟，輕輕窺着傷人命。"]'),
('3674091a-dcf8-4120-b170-7e8357099b24','送樞兄之梅州','釋慧空','宋','宋诗','song-poetry','','[]','住庵人，老雷堆。',64,'全唐诗/poet.song.106000.json','["住庵人，老雷堆。", "行腳土，心孔開。", "忍寒莫守雪山雪，有口快嚼梅州梅。", "梅州老人我知識，入門不用先安排。", "橫膝黑蛇三尺鐵，崖崩石裂當一擊。"]'),
('e26c57cf-224c-484b-986a-e8c67274ec1f','謝曾運使惠詩並石爐二首  其一','釋慧空','宋','宋诗','song-poetry','','[]','公詩妙天下，當與天下共。',48,'全唐诗/poet.song.106000.json','["公詩妙天下，當與天下共。", "我欲私藏之，奈此知者衆。", "乃持海一滴，施作無盡供。", "莫生文字見，句句是日用。"]'),
('34064c69-9994-43d8-96c6-92059fa06e8d','謝曾運使惠詩並石爐二首  其二','釋慧空','宋','宋诗','song-poetry','','[]','凈名丈室中，熏爐亦冰雪。',48,'全唐诗/poet.song.106000.json','["凈名丈室中，熏爐亦冰雪。", "持供雪山僧，蘆花與秋月。", "客有問法來，跨門或未瞥。", "爇爾懷中香，聽此石友說。"]'),
('f16cfeef-0843-45d1-8ddd-aeb3b9dea251','和徐侍郎兼呈鄭漁仲  其一','釋慧空','宋','宋诗','song-poetry','','[]','徐卿天上石麒麟，天遣來清地下塵。',32,'全唐诗/poet.song.106000.json','["徐卿天上石麒麟，天遣來清地下塵。", "一掃明珠三百斛，盡情乞與世間人。"]'),
('63235690-20e6-4b94-bb4b-eb239b815102','和徐侍郎兼呈鄭漁仲  其二','釋慧空','宋','宋诗','song-poetry','','[]','夢裏分攜二十年，君忘名字我忘緣。',32,'全唐诗/poet.song.106000.json','["夢裏分攜二十年，君忘名字我忘緣。", "蹇驢風帽溪頭見，疑是襄陽孟浩然。"]'),
('e331ebfc-5865-4cf9-a477-e5e2e5a29902','和徐侍郎兼呈鄭漁仲  其三','釋慧空','宋','宋诗','song-poetry','','[]','忽憶曾來蜑子船，烟波萬頃對安眠。',32,'全唐诗/poet.song.106000.json','["忽憶曾來蜑子船，烟波萬頃對安眠。", "向來親切渾拋卻，卻聽傍人名字傳。"]'),
('0fd83653-1686-4240-b595-d7535104f28e','和徐侍郎兼呈鄭漁仲  其四','釋慧空','宋','宋诗','song-poetry','','[]','慣穿八索九流手，參透男婚女嫁禪。',32,'全唐诗/poet.song.106000.json','["慣穿八索九流手，參透男婚女嫁禪。", "驀地來尋僧印可，趙州當日見南泉。"]'),
('a5a880a8-5b94-43be-b1cd-7f5bdedcbef4','和徐侍郎兼呈鄭漁仲  其五','釋慧空','宋','宋诗','song-poetry','','[]','歌辭信口端師子，干木隨身鄧隱峰。',32,'全唐诗/poet.song.106000.json','["歌辭信口端師子，干木隨身鄧隱峰。", "兩箇風顛爭幾許，一天霜月似相容。"]'),
('afaa4cbb-892f-4602-a3a8-990c9c4bc6c4','和徐侍郎兼呈鄭漁仲  其六','釋慧空','宋','宋诗','song-poetry','','[]','眼看鴻雁入冥冥，忽起尋山杖屨輕。',32,'全唐诗/poet.song.106000.json','["眼看鴻雁入冥冥，忽起尋山杖屨輕。", "不謂莆陽鄭夫子，一書猶解問空生。"]'),
('79ea49d6-828e-4860-9b06-f10bd6e4a357','和曾運使  其一','釋慧空','宋','宋诗','song-poetry','','[]','心法兩忘諸說到，文章百鍊古風回。',32,'全唐诗/poet.song.106000.json','["心法兩忘諸說到，文章百鍊古風回。", "方驚吸盡西江口，又出江西一派來。"]'),
('bd3a6923-927b-4966-a4ec-ab9c2684dd2f','和曾運使  其二','釋慧空','宋','宋诗','song-poetry','','[]','而今派下皆龍象，肯著風顛老萬回。',32,'全唐诗/poet.song.106000.json','["而今派下皆龍象，肯著風顛老萬回。", "大士不知何所取，真成千里賺人來。"]'),
('6d45a701-9fe7-4428-8150-78f84128335e','和曾運使  其三','釋慧空','宋','宋诗','song-poetry','','[]','我夢玉山架茅竹，清溪濺濺路回回。',32,'全唐诗/poet.song.106000.json','["我夢玉山架茅竹，清溪濺濺路回回。", "丘山便是龐公宅，老倒扶筇日日來。"]'),
('de118103-fea7-4e1f-aff7-4674269f4ece','和曾運使  其四','釋慧空','宋','宋诗','song-poetry','','[]','幻師拈起一枝草，無限春光應手回。',32,'全唐诗/poet.song.106000.json','["幻師拈起一枝草，無限春光應手回。", "認得春光與拈草，分明開眼被瞞來。"]'),
('a600fc61-ba2c-42ee-b975-eec2b9df4503','和曾運使  其五','釋慧空','宋','宋诗','song-poetry','','[]','諸佛衆生同說法，一惟直截一迂回。',32,'全唐诗/poet.song.106000.json','["諸佛衆生同說法，一惟直截一迂回。", "江南春水天相似，白鳥有盟歸去來。"]'),
('577dc95b-993e-4ba0-9ad4-d7032b8bd822','和曾運使  其六','釋慧空','宋','宋诗','song-poetry','','[]','詩壇拜將思工部，我已佯狂類萬回。',32,'全唐诗/poet.song.106000.json','["詩壇拜將思工部，我已佯狂類萬回。", "賴有江西老尊宿，揭天棒喝待方來。"]'),
('dc620af3-d24a-422d-85cf-339947187688','送隆首座','釋慧空','宋','宋诗','song-poetry','','[]','行腳人，何疏豁。',88,'全唐诗/poet.song.106000.json','["行腳人，何疏豁。", "芒草鞋，布直裰。", "打開包袋一物無，拈起瘦藤天地闊。", "遇寺入，逢飯抹。", "不學些子律儀，只是一生快活。", "見爾曲彔牀頭老漢，六十三，七十八，不消一撮。", "背卻法堂脫皮襪，阿刺刺。"]'),
('4b8ac073-6f61-40ea-b59d-7b891480970c','送支提化士','釋慧空','宋','宋诗','song-poetry','','[]','天寒忽憶大支寺，迢遞晚鍾烟際山。',32,'全唐诗/poet.song.106000.json','["天寒忽憶大支寺，迢遞晚鍾烟際山。", "安得腰纏十萬貫，亦隨君去飯天冠。"]'),
('78b0e600-e1ee-47f9-88fd-ca0c4c6e4c11','與法界才庵主  其一','釋慧空','宋','宋诗','song-poetry','','[]','不動莖茅法界庵，庵中無物不同參。',32,'全唐诗/poet.song.106000.json','["不動莖茅法界庵，庵中無物不同參。", "一條白棒胡牀角，穿卻從前五十三。"]'),
('17e2c621-28c9-49d0-bf5b-31adcce8f64d','與法界才庵主  其二','釋慧空','宋','宋诗','song-poetry','','[]','三腳驢兒腳踏天，恒河諸佛若爲宣。',32,'全唐诗/poet.song.106000.json','["三腳驢兒腳踏天，恒河諸佛若爲宣。", "閻浮夜半人驚起，把得芒繩下鐵鞭。"]'),
('2fdd44bf-d6fa-43df-b367-32f4fbf93b6e','題圓融庵藏書塢輞川圖  其一','釋慧空','宋','宋诗','song-poetry','','[]','千尺蒼崖貫日虹，忽驚懸水坐生風。',32,'全唐诗/poet.song.106000.json','["千尺蒼崖貫日虹，忽驚懸水坐生風。", "不知摩詰展神力，摶得他方置此中。"]'),
('684ec90f-5df6-4500-a3bb-014566ba2df2','題圓融庵藏書塢輞川圖  其二','釋慧空','宋','宋诗','song-poetry','','[]','橫澗老蛟松夭矯，埋雲古洞石嵌空。',32,'全唐诗/poet.song.106000.json','["橫澗老蛟松夭矯，埋雲古洞石嵌空。", "芒鞋竹杖如堪畫，乞與寒巖作主翁。"]'),
('fb945e39-e58d-4e6d-af8c-6a7859286a24','別圓融庵主','釋慧空','宋','宋诗','song-poetry','','[]','青田東望山如藍，過嶺獨喜雲腴甘。',96,'全唐诗/poet.song.106000.json','["青田東望山如藍，過嶺獨喜雲腴甘。", "叢林荒寒不入眼，耆舊只今多住庵。", "汾陽昭對矮師叔，甘露有源梅子熟。", "長年風月但平分，一日空來鼎三足。", "屋頭高梧忽秋聲，老去彼此雲無情。", "歸山自畜長柄杓，珍重庵頭折腳鐺。"]'),
('6b457ca8-01ff-4b4c-b1ef-50894a4faa38','悼惠知微','釋慧空','宋','宋诗','song-poetry','','[]','崇寧乙酉此時節，情與無情同出生。',80,'全唐诗/poet.song.106000.json','["崇寧乙酉此時節，情與無情同出生。", "紹興甲子時不移，情與無情同入滅。", "一生一滅無欠餘，末上露些端的別。", "通身手眼不奈何，謂是西歸謗吾友。", "乞與諸方拄杖頭，黑黑明明三八九。"]'),
('7d2a96ea-e29d-4c61-84b3-ebfc8ba1bb13','送僧之育王','釋慧空','宋','宋诗','song-poetry','','[]','一庵臥病死無異，放髪齊眉老更顛。',32,'全唐诗/poet.song.106000.json','["一庵臥病死無異，放髪齊眉老更顛。", "相送無信茶一椀，江山岸下浙東船。"]'),
('dd326b57-8a49-4416-afab-7461dd140b7c','劉世美宅新架詩禮堂萊衣閣來薰臺游息軒養心齋以五偈贈之  其一','釋慧空','宋','宋诗','song-poetry','','[]','蚤聞彭城子，詩禮爲專門。',24,'全唐诗/poet.song.106000.json','["蚤聞彭城子，詩禮爲專門。", "只今青雲上，粲然見諸昆。"]'),
('d4bdd385-4b6c-4e6a-a63b-0b634dc39af3','劉世美宅新架詩禮堂萊衣閣來薰臺游息軒養心齋以五偈贈之  其二','釋慧空','宋','宋诗','song-poetry','','[]','我願天下士，奉親皆若此。',24,'全唐诗/poet.song.106000.json','["我願天下士，奉親皆若此。", "家家父母前，人人老萊子。"]'),
('0bbf5c6f-cb68-49a2-99ca-696b8a824aea','劉世美宅新架詩禮堂萊衣閣來薰臺游息軒養心齋以五偈贈之  其三','釋慧空','宋','宋诗','song-poetry','','[]','客有跛其足，莫登主人臺。',24,'全唐诗/poet.song.106000.json','["客有跛其足，莫登主人臺。", "願爲南來風，長滿主人懷。"]'),
('133f9556-6d51-4ffb-9aab-9f6a5c64e846','劉世美宅新架詩禮堂萊衣閣來薰臺游息軒養心齋以五偈贈之  其四','釋慧空','宋','宋诗','song-poetry','','[]','窗下羲皇人，酒中桃源路。',24,'全唐诗/poet.song.106000.json','["窗下羲皇人，酒中桃源路。", "客非伶與潛，我醉卿且去。"]'),
('4e96a626-db32-4f11-b963-1e9e33c8429f','劉世美宅新架詩禮堂萊衣閣來薰臺游息軒養心齋以五偈贈之  其五','釋慧空','宋','宋诗','song-poetry','','[]','心惑由多技，養之先欲正。',24,'全唐诗/poet.song.106000.json','["心惑由多技，養之先欲正。", "紛然萬化塗，廓爾大圓鏡。"]'),
('b96fb4da-bba9-4d29-af7d-322e39bd00bb','庵前蜂去數日復返因作  其一','釋慧空','宋','宋诗','song-poetry','','[]','向聞刮責抽單去，今見時難領衆歸。',32,'全唐诗/poet.song.106000.json','["向聞刮責抽單去，今見時難領衆歸。", "歲晚蕭條單位在，汝饑猶可主人饑。"]'),
('58892653-16b3-4c68-8905-1f7d2d8202f3','庵前蜂去數日復返因作  其二','釋慧空','宋','宋诗','song-poetry','','[]','蜜巖所統衆如雲，客至還開甘露門。',32,'全唐诗/poet.song.106000.json','["蜜巖所統衆如雲，客至還開甘露門。", "三扣蜜流人不薦，卻言蜂子解人言。"]'),
('7bcdc470-ceb5-4c04-9e75-a0c61ba9bd84','庵前蜂去數日復返因作  其三','釋慧空','宋','宋诗','song-poetry','','[]','無多鼓吹惱比鄰，且看梅梢欲放春。',32,'全唐诗/poet.song.106000.json','["無多鼓吹惱比鄰，且看梅梢欲放春。", "爾輩只如前日樂，老僧何似去年貧。"]'),
('c64e4134-c2dc-4028-a415-684770f3f5c0','蒙庵自東山寄龍眠畫寒山拾得圖來令作頌寒山著屐把帚作舞拾得腰筒拍手而笑豐干騎虎搔癢眎之戲書其後云','釋慧空','宋','宋诗','song-poetry','','[]','二子相逢舞笑時，此翁癢發似因之。',64,'全唐诗/poet.song.106000.json','["二子相逢舞笑時，此翁癢發似因之。", "坐間一虎低頭覷，覷著三人總是伊。", "龍眠畫出意不淺，空也言之恐未然。", "更向蒙庵問端的，榴花洞口笑掀天。"]'),
('2360d585-fc75-43c8-a65a-7795ae41828c','和鈍庵雪頌','釋慧空','宋','宋诗','song-poetry','','[]','試看而今是甚時，文殊無地得遊嬉。',32,'全唐诗/poet.song.106000.json','["試看而今是甚時，文殊無地得遊嬉。", "衲僧眼目難瞞處，把定乾坤未許伊。"]'),
('2bea3fc1-49b4-4a4a-aa4f-cb71be6beb81','和鈍庵見留  其一','釋慧空','宋','宋诗','song-poetry','','[]','我來臨汝問黄龍，君已空中定鳥蹤。',32,'全唐诗/poet.song.106000.json','["我來臨汝問黄龍，君已空中定鳥蹤。", "從此和君不唧𠺕，至令同飯五華峰。"]'),
('bd2130f1-25a0-4284-95b3-72819dcafd02','和鈍庵見留  其二','釋慧空','宋','宋诗','song-poetry','','[]','雖是同居元自住，若言自住又交參。',32,'全唐诗/poet.song.106000.json','["雖是同居元自住，若言自住又交參。", "十成有轉移身句，倒跨須彌一二三。"]'),
('f941d020-849c-487b-abdd-111cd851a9fe','和鈍庵見留  其三','釋慧空','宋','宋诗','song-poetry','','[]','作伴才消木上座，同流初未許寒山。',32,'全唐诗/poet.song.106000.json','["作伴才消木上座，同流初未許寒山。", "而今卻向天台去，擊動寒巖莫與閑。"]'),
('4cf91ac3-405d-4d18-8962-4eb660f5190d','用靖兄韻送義兄','釋慧空','宋','宋诗','song-poetry','','[]','妙德熏天富，空生徹骨窮。',48,'全唐诗/poet.song.106000.json','["妙德熏天富，空生徹骨窮。", "同將一點雪，煅出太虛空。", "少待鵾鵬化，聊資九萬風。", "殷勤問行李，一箭過遼東。"]'),
('483bfc20-e297-427e-91ca-e95c632c0a2a','和訥庵送秀上人之湖湘','釋慧空','宋','宋诗','song-poetry','','[]','君山清絕吾未廬，坐想寒水連汀蒲。',96,'全唐诗/poet.song.106000.json','["君山清絕吾未廬，坐想寒水連汀蒲。", "公今因行得掉臂，扁舟獨載如輕鳬。", "凭高乞與眼界大，重磨古鏡開平湖。", "潛龍無聲霜月冷，白鳥出沒叢蘆枯。", "烟渺明邊奯公渡，岳陽句裏蕭湘圖。", "作詩模寫但彷彿，佳處付公聊自娛。"]'),
('32270414-a03d-4bbc-b2f3-61f9efd1f4c5','用詢山堂韻寄澹庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','泥牛石女本同宗，一箇惟聰一箇聾。',32,'全唐诗/poet.song.106000.json','["泥牛石女本同宗，一箇惟聰一箇聾。", "問著威音已前事，總言裴楷號精通。"]'),
('b3023a85-88b8-4111-aa82-4c1c7f80d679','用詢山堂韻寄澹庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','休論他家種性邪，惠崇蘆雁趙昌花。',32,'全唐诗/poet.song.106000.json','["休論他家種性邪，惠崇蘆雁趙昌花。", "不知真假爭多少，且盡杯中苦澀茶。"]'),
('c1cfaac4-7581-4aeb-a6ec-12482360a934','謝盧居士法衣  其一','釋慧空','宋','宋诗','song-poetry','','[]','雞足山中藏不得，黄梅夜半負將歸。',32,'全唐诗/poet.song.106000.json','["雞足山中藏不得，黄梅夜半負將歸。", "而今盧老重拈出，便是山僧肩上衣。"]'),
('137fa429-e2ef-40de-94de-e7e1d98186df','謝盧居士法衣  其二','釋慧空','宋','宋诗','song-poetry','','[]','長者施法衣，山僧肩上搭。',24,'全唐诗/poet.song.106000.json','["長者施法衣，山僧肩上搭。", "有口今嬾開，只憑衣說法。"]'),
('a30e20fb-8435-4c1d-bf28-3a0788ca5f9f','與隱上人','釋慧空','宋','宋诗','song-poetry','','[]','一庵老兮藏百拙，隱不隱兮吾何說。',47,'全唐诗/poet.song.106000.json','["一庵老兮藏百拙，隱不隱兮吾何說。", "空心曾食梅州梅，赤腳踏雪山雪。", "歸去來兮何似生，一朝雲突遼天鶻。"]'),
('857b39bb-429d-41bd-abb5-2d1f4bd46673','與正信庵吳居士','釋慧空','宋','宋诗','song-poetry','','[]','心外有佛不名信，自心是佛亦非信。',32,'全唐诗/poet.song.106000.json','["心外有佛不名信，自心是佛亦非信。", "信盡心亡佛亦非，那吒手把金剛印。"]'),
('2432963c-c691-4696-adb7-0873954e09a3','與純堯二上人','釋慧空','宋','宋诗','song-poetry','','[]','東山不會禪，只解拈飯椀。',48,'全唐诗/poet.song.106000.json','["東山不會禪，只解拈飯椀。", "方來英俊流，苦苦攻渠短。", "袖中出幅紙，當面換渠眼。", "不是東山癡，且要客心滿。"]'),
('2abde02a-c560-4d2c-8310-09cbe27b1851','送覺允之東禪','釋慧空','宋','宋诗','song-poetry','','[]','了了了，覺覺覺，萬里岷峨何處著。',64,'全唐诗/poet.song.106000.json','["了了了，覺覺覺，萬里岷峨何處著。", "全身夢入蠱毒鄉，滴水石沾隨飲啄。", "覺覺覺，了了了，金雞一拍扶桑曉。", "眼開還是覺城東，急打翻身箇筋斗。"]'),
('01ec1786-5cec-4786-bbc4-d74b4056ef2b','戊辰夏熱澹庵爲設招涼感而有作','釋慧空','宋','宋诗','song-poetry','','[]','丹山之松有如此，獵獵蒼髯自風雨。',96,'全唐诗/poet.song.106000.json','["丹山之松有如此，獵獵蒼髯自風雨。", "是中便是無煩天，咫尺人間困蒸煮。", "憐我窗軒苦未深，解枝減翠分清陰。", "我初則喜久乃愧，秀潤未赴人之心。", "欲爾直爲臨濟樹，一道陰涼天下住。", "我寧獨受焦灼休，無以枝葉爲我憂。"]'),
('62a93831-bafb-4093-b3fe-a9b0dc0d8411','送雪竇化士','釋慧空','宋','宋诗','song-poetry','','[]','雪竇性化士，得得訪空生。',48,'全唐诗/poet.song.106000.json','["雪竇性化士，得得訪空生。", "粗茶喫一椀，淡話說兩聲。", "貧無錢註疏，懶作偈送行。", "只有霜空月，相隨到四明。"]'),
('57491ffa-9ae0-4c15-b205-1acddb61b10b','送僧行腳','釋慧空','宋','宋诗','song-poetry','','[]','兩兩三三獨自行，風前大好水雲僧。',32,'全唐诗/poet.song.106000.json','["兩兩三三獨自行，風前大好水雲僧。", "神光萬里杖頭眼，出入飛猿似不曾。"]'),
('ac7b30ea-c78e-4251-9c71-c16a624b1033','送岸上座出隊','釋慧空','宋','宋诗','song-poetry','','[]','道人自嫌不安住，四年三走黄塵路。',64,'全唐诗/poet.song.106000.json','["道人自嫌不安住，四年三走黄塵路。", "那知擾擾黄塵中，暗去明來皆當處。", "觀音鬧市開普門，彌勒魚行弘六度。", "道人笑我勿多談，出門烟雨遙山渡。"]'),
('0d667b1d-bba0-4dfe-8ea8-4af0b0dab3c2','送延福專使  其一','釋慧空','宋','宋诗','song-poetry','','[]','金身荷去萬鈞重，千里持來一物無。',32,'全唐诗/poet.song.106000.json','["金身荷去萬鈞重，千里持來一物無。", "且喜重關俱透徹，浩歌歸路倒騎驢。"]'),
('342b129c-13f9-482a-b312-dcc9fb82f894','送延福專使  其二','釋慧空','宋','宋诗','song-poetry','','[]','剪剪江風雪應時，雪中春在老梅枝。',32,'全唐诗/poet.song.106000.json','["剪剪江風雪應時，雪中春在老梅枝。", "朝來折作江南信，戲蝶遊蜂總未知。"]'),
('13f988e0-f308-4a93-b538-88005a7e1bef','送鍋頭','釋慧空','宋','宋诗','song-poetry','','[]','白雲生處疏山寺，無水無柴世得知。',32,'全唐诗/poet.song.106000.json','["白雲生處疏山寺，無水無柴世得知。", "若問道人今日事，木蛇鑽破鐵鍋兒。"]'),
('833d4100-b093-493c-8d20-f018f702184c','和草堂送通直歲歸龍舒','釋慧空','宋','宋诗','song-poetry','','[]','箇是群中穴鼻牛，去無所犯住無留。',32,'全唐诗/poet.song.106000.json','["箇是群中穴鼻牛，去無所犯住無留。", "須彌南畔封疆闊，水草縱橫得自由。"]'),
('dabf7010-af10-4a27-88b6-775abfefe0a0','送實兄入閩  其一','釋慧空','宋','宋诗','song-poetry','','[]','病夫不釣龍江月，倒指于今已十秋。',32,'全唐诗/poet.song.106000.json','["病夫不釣龍江月，倒指于今已十秋。", "君過合沙煩問訊，蘆花深處舊漁舟。"]'),
('36887586-9ba6-4348-aab5-12d3cb459b77','送實兄入閩  其二','釋慧空','宋','宋诗','song-poetry','','[]','鉢飯元無那免乞，家山既有要須還。',32,'全唐诗/poet.song.106000.json','["鉢飯元無那免乞，家山既有要須還。", "莫愁劍水急於箭，入得飛猿總不難。"]'),
('86522a6b-325e-48ef-b1f4-70a83d1ae852','贈齡首座主庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','三關透罷復何言，一派銀河落九天。',32,'全唐诗/poet.song.106000.json','["三關透罷復何言，一派銀河落九天。", "摩竭魚吞南海浪，扶桑人種陝西田。"]'),
('bb421219-ed49-4266-8a24-412345312e71','贈齡首座主庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','旴水盡頭居士宅，白雲深處法王家。',32,'全唐诗/poet.song.106000.json','["旴水盡頭居士宅，白雲深處法王家。", "誰知長就無根樹，便有人尋臘月花。"]'),
('c0b4e64c-7d32-4bb9-aaef-02a635ff05b7','贈齡首座主庵  其三','釋慧空','宋','宋诗','song-poetry','','[]','南方浩浩正談禪，誰問君家博飯田。',32,'全唐诗/poet.song.106000.json','["南方浩浩正談禪，誰問君家博飯田。", "待我寒衣都補了，袖茶來訪钁頭邊。"]'),
('a473bfff-652c-43f6-aebe-0a6193d6102f','贈齡首座主庵  其四','釋慧空','宋','宋诗','song-poetry','','[]','飛猿關外路縱橫，雲水多年取次行。',32,'全唐诗/poet.song.106000.json','["飛猿關外路縱橫，雲水多年取次行。", "今日有人親坐斷，往來公驗要分明。"]'),
('d1b464c6-be72-470b-8bf3-b7a96ba01b44','贈齡首座主庵  其五','釋慧空','宋','宋诗','song-poetry','','[]','說圓不覺拖泥水，立悟分明落二三。',32,'全唐诗/poet.song.106000.json','["說圓不覺拖泥水，立悟分明落二三。", "要得不移毫髪許，寶雲山裏寶雲庵。"]'),
('d8e1fb47-03f7-4624-b313-afbd6089df5f','與海上人','釋慧空','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','信步南來謂行腳，袖手群居頭似杓。',64,'全唐诗/poet.song.106000.json','["信步南來謂行腳，袖手群居頭似杓。", "自視初無一線長，君獨喜之無乃錯。", "偶北布衲翻轉披，驚起黄龍跌折角。", "海兮海兮知不知，西山走入滕王閣。"]'),
('df432802-45d8-4c6d-bfe9-70b8dfafd489','送永兄遊浙  其一','釋慧空','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','峨嵋山腳蓬蒿箭，射中虛空成兩片。',32,'全唐诗/poet.song.106000.json','["峨嵋山腳蓬蒿箭，射中虛空成兩片。", "驚起當年陳老師，通身是眼何曾見。"]'),
('652f148d-0b25-4ffb-ab61-8c06c01bd1cd','送永兄遊浙  其二','釋慧空','宋','宋诗','song-poetry','','[]','湖南穿過來江南，無師不道無禪參。',32,'全唐诗/poet.song.106000.json','["湖南穿過來江南，無師不道無禪參。", "雲門坐臥了一夏，澗水松風共對談。"]'),
('26c5a4f3-dbc6-4512-a842-cd669d618354','送永兄遊浙  其三','釋慧空','宋','宋诗','song-poetry','','[]','秋來射入吳中去，寄語吳人好相遇。',32,'全唐诗/poet.song.106000.json','["秋來射入吳中去，寄語吳人好相遇。", "承言便是過新羅，孤負東山出門句。"]'),
('db0f7fd2-a64e-4744-9dc6-ef93d211690f','與南雄明上人','釋慧空','宋','宋诗','song-poetry','','[]','馬祖接得大雄峰，一喝當機三日聾。',158,'全唐诗/poet.song.106000.json','["馬祖接得大雄峰，一喝當機三日聾。", "近來叢林無此作，多是活埋文字中。", "君不見鬻薪客，特石墜腰供七百。", "一字不能人爲書，繼續衣盂是伊得。", "又不見周金剛，滿車載疏遊南方。", "紙燈忽滅眼睛出，白棒一揮吾道昌。", "玄中人，甚眼目，指金成鍮石作玉。", "聖凡命在渠手中，凜凜威風誰敢觸。", "直得如斯未稱渠，爾曹何苦猶貪書。", "是間縱得不爲貴，天外出頭方丈夫。"]'),
('ffece752-de43-4090-b3e5-3bb92dd0e118','西平石蛇蛇庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','一段風光出當家，真成象骨與金沙。',32,'全唐诗/poet.song.106000.json','["一段風光出當家，真成象骨與金沙。", "遊人擬路庵前石，照顧南山鼈鼻蛇。"]'),
('5a4c1bb2-a194-48dc-b61e-315a2bfab807','西平石蛇蛇庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','頭枕南山尾北山，風雪陡頓落人間。',32,'全唐诗/poet.song.106000.json','["頭枕南山尾北山，風雪陡頓落人間。", "五臺拍手峨嵋笑，此外都盧是赤斑。"]'),
('ec47d248-06ff-43d4-b71e-f3314938ecea','送天衣化士','釋慧空','宋','宋诗','song-poetry','','[]','化人生裏家常鉢，細大投之總不遺。',32,'全唐诗/poet.song.106000.json','["化人生裏家常鉢，細大投之總不遺。", "今我助緣維一偈，且煩持以供天衣。"]'),
('fb5c1f00-327c-4eb4-a966-6f135710d835','送化士  其一','釋慧空','宋','宋诗','song-poetry','','[]','千差路上尋人，沒底盂中取足。',28,'全唐诗/poet.song.106000.json','["千差路上尋人，沒底盂中取足。", "雖非格外風規，且是瞿曇目錄。"]'),
('83206365-bf08-4c68-b06b-af385cc53e81','送化士  其二','釋慧空','宋','宋诗','song-poetry','','[]','諸方多是雙行，疏山純用一著。',28,'全唐诗/poet.song.106000.json','["諸方多是雙行，疏山純用一著。", "乞食且要及時，佛法不怕爛卻。"]'),
('067925fc-4a36-4cdf-a356-d0da6a8a7527','送化士  其三','釋慧空','宋','宋诗','song-poetry','','[]','門外斜風細雨，窗間禪版蒲團。',28,'全唐诗/poet.song.106000.json','["門外斜風細雨，窗間禪版蒲團。", "不有高人猛利，那容老者安閑。"]'),
('57f74584-beb2-4085-b874-d88fe9a29feb','送化士  其四','釋慧空','宋','宋诗','song-poetry','','[]','達幻方能應物，忘心乃可循門。',28,'全唐诗/poet.song.106000.json','["達幻方能應物，忘心乃可循門。", "在昔我嘗用此，而今持以贈君。"]'),
('da477adb-e25c-4dea-9931-8d9f3ed5e228','送化士  其五','釋慧空','宋','宋诗','song-poetry','','[]','直爲江西老宿，便忘世路間關。',28,'全唐诗/poet.song.106000.json','["直爲江西老宿，便忘世路間關。", "千里一辭閩嶺，四年三到疏山。"]'),
('c4102b9c-0a73-4721-9e02-ae19042ad84d','送化士  其六','釋慧空','宋','宋诗','song-poetry','','[]','飯在千門萬戶，僧離古寺名山。',28,'全唐诗/poet.song.106000.json','["飯在千門萬戶，僧離古寺名山。", "七佛已前儀式，一時頓覺追還。"]'),
('f51e083e-4bdd-4603-bb80-d121553085f8','送化士  其七','釋慧空','宋','宋诗','song-poetry','','[]','達士相逢即出，衲僧似有如無。',28,'全唐诗/poet.song.106000.json','["達士相逢即出，衲僧似有如無。", "上門上戶討得，堆山積嶽破除。"]'),
('2c029fed-220b-469e-ae21-fbc171389f5e','送化士  其八','釋慧空','宋','宋诗','song-poetry','','[]','調心不易安心易，離世非難應世難。',32,'全唐诗/poet.song.106000.json','["調心不易安心易，離世非難應世難。", "要識諸君三昧力，莫辭同隊到人間。"]'),
('a97902f2-61ff-4731-b122-9acce922538b','送化士  其九','釋慧空','宋','宋诗','song-poetry','','[]','人間岐路事何如，小大榮枯有萬殊。',32,'全唐诗/poet.song.106000.json','["人間岐路事何如，小大榮枯有萬殊。", "但願家傳無底鉢，盡情收拾不論渠。"]'),
('bf77b754-3b9c-4aec-a369-d9ab9b3202dc','送化士  其一○','釋慧空','宋','宋诗','song-poetry','','[]','秘在形山元是礙，散於人世亦非真。',32,'全唐诗/poet.song.106000.json','["秘在形山元是礙，散於人世亦非真。", "還從是礙非真處，收取歸來要見人。"]'),
('9e893ed6-0c9f-45fc-a20c-de085e6e5f59','送化士  其一一','釋慧空','宋','宋诗','song-poetry','','[]','收得歸來一破顔，兩肩荷負幾多般。',32,'全唐诗/poet.song.106000.json','["收得歸來一破顔，兩肩荷負幾多般。", "當堂放下元無物，打鼓從教普請看。"]'),
('0fe2fdc7-2651-4e78-a464-3bf9c3bf47c5','送化士  其一二','釋慧空','宋','宋诗','song-poetry','','[]','堂中宴坐山含月，塵裏分身珠走盤。',32,'全唐诗/poet.song.106000.json','["堂中宴坐山含月，塵裏分身珠走盤。", "但得此心無住著，世間那有路行難。"]'),
('a8ca5a5d-4a43-4108-bb45-9cafde2f34c9','送化士  其一三','釋慧空','宋','宋诗','song-poetry','','[]','此鉢傳從諸佛，大緣今在汝身。',28,'全唐诗/poet.song.106000.json','["此鉢傳從諸佛，大緣今在汝身。", "盡力盡心持去，上門上戶尋人。"]'),
('7702720c-024c-47ca-a842-e039d1328b18','送化士  其一四','釋慧空','宋','宋诗','song-poetry','','[]','迫促空生說偈，頓送普化上街。',28,'全唐诗/poet.song.106000.json','["迫促空生說偈，頓送普化上街。", "三日兩日要供，十日五日要齋。"]'),
('6bf3ec71-7ce9-422a-9a88-561396a7d51f','送化主  其一','釋慧空','宋','宋诗','song-poetry','','[]','空生曾乞臨江市，日與雲居打飯錢。',32,'全唐诗/poet.song.106000.json','["空生曾乞臨江市，日與雲居打飯錢。", "老入華峰無用處，君今行乞記當年。"]'),
('4b7d5137-3734-4858-83e4-84f79f8c8e92','送化主  其二','釋慧空','宋','宋诗','song-poetry','','[]','吉山真心成抑逼，僧至參禪令乞食。',32,'全唐诗/poet.song.106000.json','["吉山真心成抑逼，僧至參禪令乞食。", "誤他多少禪家流，入不得處爭著力。"]'),
('433a6e48-6431-42c1-a3f4-0d144c5bad76','送化主  其三','釋慧空','宋','宋诗','song-poetry','','[]','明知曰空具足器，向裏得時無不是。',32,'全唐诗/poet.song.106000.json','["明知曰空具足器，向裏得時無不是。", "及至歸來放下時，笑倒南山老鼈鼻。"]'),
('73c553db-1234-472a-9884-e47bad0d0a83','送化主  其四','釋慧空','宋','宋诗','song-poetry','','[]','袖裏深藏大吉山，逢人拈出好生觀。',32,'全唐诗/poet.song.106000.json','["袖裏深藏大吉山，逢人拈出好生觀。", "不嫌貧富僧兼俗，價數高低試著看。"]'),
('81a09eb9-7dc0-49f9-94d1-54d57029f5fd','送化主  其五','釋慧空','宋','宋诗','song-poetry','','[]','昔人遣化曾垂示，三步五步一蹙鼻。',88,'全唐诗/poet.song.106000.json','["昔人遣化曾垂示，三步五步一蹙鼻。", "從緣入得即不無，七佛之儀殊未備。", "今日吉山分化人，豈在途中方瞥地。", "千差一印靡有遺，萬善同歸寧自利。", "不自利，非利他，家家門啟通霄路，處處蓮開火裏花。"]'),
('ebfcfd9b-8ed6-4d60-9827-613b8e6b1a99','送化主  其六','釋慧空','宋','宋诗','song-poetry','','[]','堆堆危危是什麽，生鐵饅頭千萬箇。',64,'全唐诗/poet.song.106000.json','["堆堆危危是什麽，生鐵饅頭千萬箇。", "無心椀裏盛將來，有眼禪人俱咬破。", "吉山安衆飯亦無，終是不教渠忍餓。", "煩君普告信心人，一句當陽莫嗟過。"]'),
('ebb44a1b-b0ef-4ac1-af3e-c39dc0004b41','送化主  其七','釋慧空','宋','宋诗','song-poetry','','[]','空生曾乞臨江市，恰似君今無別理。',64,'全唐诗/poet.song.106000.json','["空生曾乞臨江市，恰似君今無別理。", "只將千聖不曾傳，到處逢人水投水。", "持來滿滿復是誰，把得便行何擬擬。", "雖然末後有牢關，踏著歸來不相似。"]'),
('57fff1de-b83d-46ff-b42c-6f7909b6d88c','送化主  其八','釋慧空','宋','宋诗','song-poetry','','[]','一偈普送諸禪客，萬化門中等慈力。',64,'全唐诗/poet.song.106000.json','["一偈普送諸禪客，萬化門中等慈力。", "門門對現沒遮攔，箭箭離弦俱中的。", "因記芭蕉曾遣化，未出門時先話霸。", "而今更不論親疏，收功盡在華峰下。"]'),
('6d51a302-bae6-4ba7-b5a6-80a8d0bf38f3','送化主  其九','釋慧空','宋','宋诗','song-poetry','','[]','少年入衆先行乞，最初一步須牢實。',96,'全唐诗/poet.song.106000.json','["少年入衆先行乞，最初一步須牢實。", "多見時流昧此心，施受之間兩無益。", "信心人，一粒米，重似丘山曾不止。", "持來豈是得便宜，未了分明著他底。", "賢禪賢禪宜努力，諸佛衆生從此出。", "逆行順行忽相當，戶戶門門成大吉。"]'),
('9f323462-5d7e-4f03-bdda-19ec8544b3ec','送泐潭化主往泉南','釋慧空','宋','宋诗','song-poetry','','[]','馬駒霜蹄疾如電，過處千人萬人見。',96,'全唐诗/poet.song.106000.json','["馬駒霜蹄疾如電，過處千人萬人見。", "於中有個見得親，也似不虛行一轉。", "古來佛國號漳泉，此去逢人呈舊面。", "不須更揀親與疏，是有是無都一串。", "看看激起南海波，流入西江爲瀚漫。", "江西老宿問空生，但道而今成老健。"]'),
('47f18343-fdac-4dae-9be7-227192f68fef','送通功二化士造大際藏經','釋慧空','宋','宋诗','song-poetry','','[]','大經本無文，唐梵錯翻譯。',72,'全唐诗/poet.song.106000.json','["大經本無文，唐梵錯翻譯。", "瞿曇宣一字，至今猶未畢。", "歷世癡聖人，出頭競分析。", "要使其光明，轉見黑似漆。", "若入衲僧手，自是不費力。", "拈出大際山，般若波羅蜜。"]'),
('63539d85-5e5e-4347-9a1b-46015c1afada','送茶頭幷化士  其一','釋慧空','宋','宋诗','song-poetry','','[]','四海建溪茶，古今人所重。',84,'全唐诗/poet.song.106000.json','["四海建溪茶，古今人所重。", "惟有禪家流，端的得受用。", "風穴出送行，香嚴用原夢。", "古佛老趙州，到與不到共。", "今者披秀翁，又作如是供。", "階也分化權，空生與之頌。", "但得出處真，一用一切用。"]'),
('7cd4c074-fd39-46af-8110-e7aec0191e23','送茶頭幷化士  其二','釋慧空','宋','宋诗','song-poetry','','[]','物以甘柔趨所嗜，茶獨森嚴正其味。',80,'全唐诗/poet.song.106000.json','["物以甘柔趨所嗜，茶獨森嚴正其味。", "老僧得之其夢圓，張喉引喙欲談禪。", "小僧得之忘百慮，挑囊直入茶山去。", "僧無老少俱喜茶，問訊武夷僊子家。", "待我明年春睡醒，借爾郝源作茶鼎。"]'),
('3136dce0-6beb-41b0-954e-e9d93f91f9a0','送茶頭幷化士  其三','釋慧空','宋','宋诗','song-poetry','','[]','三昧酒，喫便醉，坐禪時，只瞌睡。',128,'全唐诗/poet.song.106000.json','["三昧酒，喫便醉，坐禪時，只瞌睡。", "輕輕未可悚動渠，送上茶山渠自會。", "見張三，逢李四，把得便行果靈利。", "一枝春信有來由，六出飛花不相類。", "到秀峰，真得地，四方老衲如雲至。", "跨著三門酌一杯，換卻眼睛拈卻鼻。", "鐵面老禪今健否，家居道舊想安然。", "飯香苦憶伊蒲饌，井冽還思甘露泉。"]'),
('ccd8e427-610b-4a44-9254-9a648f2cf9e7','送茶頭幷化士  其四','釋慧空','宋','宋诗','song-poetry','','[]','真鬬九湯雲起雪，貢餘徑寸玉無瑕。',32,'全唐诗/poet.song.106000.json','["真鬬九湯雲起雪，貢餘徑寸玉無瑕。", "春寒不念山中事，歲歲封題記我家。"]'),
('5dfe3ace-a9c9-445c-9f6f-3f64ef9e1ca9','送茶頭幷化士  其五','釋慧空','宋','宋诗','song-poetry','','[]','瓦盆雷動千山曉，橫嶺香傳兩袖風。',32,'全唐诗/poet.song.106000.json','["瓦盆雷動千山曉，橫嶺香傳兩袖風。", "添得老禪精彩好，江西一吸兔甌中。"]'),
('2a4fae91-3cb8-4cf9-bae0-77f914b692f7','送茶頭幷化士  其六','釋慧空','宋','宋诗','song-poetry','','[]','今我老無崖險句，送人行不折楊花。',32,'全唐诗/poet.song.106000.json','["今我老無崖險句，送人行不折楊花。", "前頭有問又須道，黄面禪和喫釅茶。"]'),
('f148b189-88ec-4ecb-a9e3-25bba49cdf21','送茶頭幷化士  其七','釋慧空','宋','宋诗','song-poetry','','[]','衲僧手眼親，把得是日用。',48,'全唐诗/poet.song.106000.json','["衲僧手眼親，把得是日用。", "左乞建溪茶，右化連江洪。", "快拈兩條蛇，併作一手弄。", "行看臘雪消，便是春雷動。"]'),
('6426e63c-bca1-4897-8fe2-2721666cd180','送茶頭幷化士  其八','釋慧空','宋','宋诗','song-poetry','','[]','披秀三句二偈，與寵爲茶佛事。',98,'全唐诗/poet.song.106000.json','["披秀三句二偈，與寵爲茶佛事。", "法味法樂法財，資神資生資惠。", "使於施受之間，而無虛得虛棄。", "我亦未證其中，乃就其中出氣。", "截卻嬌梵舌根，捩轉衲僧巴鼻。", "來者滿與一甌，看伊東倒西醉。", "既醉各各起來，門外曉山橫翠。"]'),
('59b922c0-f0a5-40d0-883f-ba205b7055e2','送茶頭幷化士  其九','釋慧空','宋','宋诗','song-poetry','','[]','當陽一印妙無文，慚愧東山有子孫。',32,'全唐诗/poet.song.106000.json','["當陽一印妙無文，慚愧東山有子孫。", "是聖是凡齊印定，不妨持鉢扣人門。"]'),
('5a96ebfc-5efe-4f0d-a422-cb2ef5eef854','送茶頭幷化士  其一○','釋慧空','宋','宋诗','song-poetry','','[]','至辱莫若乞，至樂在無求。',48,'全唐诗/poet.song.106000.json','["至辱莫若乞，至樂在無求。", "苟得無求旨，雖乞吾何羞。", "道人白雲居，心與白雲儔。", "明朝出山去，迫夏歸來不。"]'),
('115bfdbf-e010-4762-9c81-bf77b89a165c','送茶頭幷化士  其一一','釋慧空','宋','宋诗','song-poetry','','[]','盡大地是吾檀越，梅花杏花先後發。',48,'全唐诗/poet.song.106000.json','["盡大地是吾檀越，梅花杏花先後發。", "綠楊陰下問長安，門門有路皆通達。", "祖師禪，活鱍鱍，長秔米飯抄滿鉢。"]'),
('38d58c25-5bd1-4714-947d-4fe4543c4f31','送茶頭幷化士  其一二','釋慧空','宋','宋诗','song-poetry','','[]','佛子平居觀世間，皆謂圓融無雜壞。',128,'全唐诗/poet.song.106000.json','["佛子平居觀世間，皆謂圓融無雜壞。", "使其應入如所觀，與奪交馳還窒閡。", "我嘗行乞今示汝，要得圓成先擊碎。", "一毛不立等剎塵，八面俱來無向背。", "如探有無於懷中，如問可不於自己。", "有無可不非外來，是中欲誰爲慍喜。", "佛子當持此法門，入此界中而示現。", "丹山紅鑪爲汝開，歲晚歸來金百鍊。"]'),
('d3cf2f26-a378-4691-8df6-6c18b1547642','送茶頭幷化士  其一三','釋慧空','宋','宋诗','song-poetry','','[]','道人隨處展家風，酒肆魚行有路通。',32,'全唐诗/poet.song.106000.json','["道人隨處展家風，酒肆魚行有路通。", "但得堂中鹽米辦，吉山佛法自興隆。"]'),
('4245bc42-cc8a-4f65-81d5-9fcc6c9691c5','送茶頭幷化士  其一四','釋慧空','宋','宋诗','song-poetry','','[]','佛與衆生舊有緣，入廛一句更爲宣。',32,'全唐诗/poet.song.106000.json','["佛與衆生舊有緣，入廛一句更爲宣。", "眼前不用生貪戀，三界無安若火煎。"]'),
('750d58c6-d8d9-4841-ba6f-3094c212781a','送茶頭幷化士  其一五','釋慧空','宋','宋诗','song-poetry','','[]','達人不見塵中隘，爲有而今這一解。',64,'全唐诗/poet.song.106000.json','["達人不見塵中隘，爲有而今這一解。", "長柄笊籬入手來，倒用橫拈風雨快。", "南街打倒北街頭，東園乞得西園菜。", "阿呵呵，也奇怪，他家自有通人愛。"]'),
('34acd584-b8d0-42d6-b547-44a4ed586e30','送印侍者廣化開山歌','釋慧空','宋','宋诗','song-poetry','','[]','君不見東山老人僧中月，法惟直指初無說。',131,'全唐诗/poet.song.106000.json','["君不見東山老人僧中月，法惟直指初無說。", "有衆如雲來不休，有飯如山供不徹。", "印道人，善時節，不持應器循門乞。", "只募同心一萬人，請將大地爲檀越。", "或寬平，或曲折，與我福田衣不別。", "二彼雖無施受心，萬斛千倉從此出。", "若見聞，宜猛烈。", "莫守從前慳吝穴。", "些兒信種落其中，遍界靈苗齊秀發。"]'),
('c0937062-a9fa-46d7-9d74-f9662064dae5','送光侍者充街坊','釋慧空','宋','宋诗','song-poetry','','[]','養子不著順摩捋，喝要耳聾棒要殺。',64,'全唐诗/poet.song.106000.json','["養子不著順摩捋，喝要耳聾棒要殺。", "摩捋得成用不行，棒殺教伊應手活。", "東山妙得養子方，所以用時俱爪抹。", "我是謝郎先早歸，打就鐵船相觸撥。"]'),
('17f41382-d261-4779-a635-ba6772cc71dd','送願兄化永嘉  其一','釋慧空','宋','宋诗','song-poetry','','[]','秦谿在處皆招提，我此東山爲最上。',128,'全唐诗/poet.song.106000.json','["秦谿在處皆招提，我此東山爲最上。", "非謂豐庖麗堂宇，於中坐此真導師。", "如火周空擬則焚，如鼓塗毒聞則死。", "癡禪眇劣渠得知，但以情疑實相法。", "我觀此會比丘衆，一一從其法化生。", "混而不雜如千光，用而無畏如師子。", "汝宜於此辦肯心，此心一辦一切辦。", "善哉遍界塵勞門，悉是東山大智海。"]'),
('feeea590-6db7-4adb-b466-c70519931bd7','送願兄化永嘉  其二','釋慧空','宋','宋诗','song-poetry','','[]','脩途初發步，步步要相似。',48,'全唐诗/poet.song.106000.json','["脩途初發步，步步要相似。", "後步纔到時，豈離最初故。", "乃翁衆導師，況是爲之子。", "欲取步驟同，努力無忽此。"]'),
('6525636a-44b5-427e-bf28-4cd75301da47','送廣州化士  其一','釋慧空','宋','宋诗','song-poetry','','[]','禪參閩嶺雪峰寺，飯在南方檀越家。',32,'全唐诗/poet.song.106000.json','["禪參閩嶺雪峰寺，飯在南方檀越家。", "歲歲僧歸飯滿鉢，普熏何獨是毗耶。"]'),
('98a63fea-a331-4458-8e65-9e3ada807e36','送廣州化士  其二','釋慧空','宋','宋诗','song-poetry','','[]','雪嶺留香衆，南方上善人。',48,'全唐诗/poet.song.106000.json','["雪嶺留香衆，南方上善人。", "先佛肅恭法，佛子今此行。", "古佛有儀式，衲僧不放過。", "一座雪峰山，千門萬戶到。"]'),
('b94262fd-a5ed-40c7-a37f-a9c1d2a7e18d','次直指老人韻送璠化士兼呈丘中大  其一','釋慧空','宋','宋诗','song-poetry','','[]','寶所龍蛇爭守護，自非其人手難措。',32,'全唐诗/poet.song.106000.json','["寶所龍蛇爭守護，自非其人手難措。", "若於箇裏到一回，堪與東山稱化士。"]'),
('46cf9fc0-1473-419a-91d1-70b0ab82f015','次直指老人韻送璠化士兼呈丘中大  其二','釋慧空','宋','宋诗','song-poetry','','[]','上方香飯遠吹風，墮我雲堂一鉢空。',32,'全唐诗/poet.song.106000.json','["上方香飯遠吹風，墮我雲堂一鉢空。", "要使人人無食想，卻煩小小現神通。"]'),
('6368dcb3-94ad-45f4-b7c7-e23c57d3bb14','次直指老人韻送璠化士兼呈丘中大  其三','釋慧空','宋','宋诗','song-poetry','','[]','南庵居士今摩詰，久稔聲光未扣門。',32,'全唐诗/poet.song.106000.json','["南庵居士今摩詰，久稔聲光未扣門。", "忽睹曼殊說三偈，坐令身在對談邊。"]'),
('a7cecbc7-cdae-4e24-acb9-cd7f95809ba7','送化主造大目谿橋','釋慧空','宋','宋诗','song-poetry','','[]','擘開太華手，生鐵鑄就漢。',48,'全唐诗/poet.song.106000.json','["擘開太華手，生鐵鑄就漢。", "拈起白玉虹，跨著谿兩岸。", "東西南北人，步步無間斷。", "直造大歇堂，一生事成辦。"]'),
('a1132fcd-4c1f-45fd-962d-24795d9db4f2','與聚道者造白林橋  其一','釋慧空','宋','宋诗','song-poetry','','[]','白林山中一句子，大谿爲舌日夜說。',32,'全唐诗/poet.song.106000.json','["白林山中一句子，大谿爲舌日夜說。", "路人擾擾如不聞，聚等諸人今始瞥。"]'),
('ba77a0a0-4797-416a-af8d-921d436adad8','與聚道者造白林橋  其二','釋慧空','宋','宋诗','song-poetry','','[]','橫身谿上略相酬，不住中間徹兩頭。',32,'全唐诗/poet.song.106000.json','["橫身谿上略相酬，不住中間徹兩頭。", "行人掉臂上頭過，誰信如今有趙州。"]'),
('3c5b0599-dd46-4e66-aa23-ac9f86b317b6','與珍道者造東山寺前石橋','釋慧空','宋','宋诗','song-poetry','','[]','灌谿劈箭雖云急，截流過者腳不濕。',64,'全唐诗/poet.song.106000.json','["灌谿劈箭雖云急，截流過者腳不濕。", "東山一水人不驚，擬動腳時灘下立。", "如何咫尺東山門，在眼可望不可及。", "珍公老手但問渠，自有方便令人入。"]'),
('9b923136-4ab7-49f1-be2d-471d6a1374c5','送圓上人歸雲居','釋慧空','宋','宋诗','song-poetry','','[]','康廬諸峰歐阜殊，寺稱天上衆五湖。',96,'全唐诗/poet.song.106000.json','["康廬諸峰歐阜殊，寺稱天上衆五湖。", "古來相傳應真輩，多入此衆潛安居。", "有爲白癩聊戲劇，鄰坐惡之思割席。", "一朝忽怪單位空，遺下瘡痂渺無跡。", "東山若是與同時，捶折其脛寧容之。", "圓今病痛又相似，放過從教天下疑。"]'),
('1635792d-b384-4c51-a966-51541b2d8b95','送正維那歸華亭','釋慧空','宋','宋诗','song-poetry','','[]','無絲線子拽不斷，正要幷州快剪刀。',64,'全唐诗/poet.song.106000.json','["無絲線子拽不斷，正要幷州快剪刀。", "爾既有之還不用，山僧贏得笑呵呵。", "只將一笑贈君行，無限青山送又迎。", "到得華亭人不識，柳陰終日釣舟橫。"]'),
('c1ec2be2-bc4f-4da5-87a2-642e89c54020','與腖兒','釋慧空','宋','宋诗','song-poetry','','[]','雲水四方人，同居九十日。',48,'全唐诗/poet.song.106000.json','["雲水四方人，同居九十日。", "大光明藏中，各各不相識。", "月兔曉東生，日烏夜西出。", "善現問瞿曇，般若波羅蜜。"]'),
('45331bfa-7dca-4124-a897-d55fb023bc62','與朋寧二士','釋慧空','宋','宋诗','song-poetry','','[]','東山東遊形弔影，閉門作夏山房冷。',64,'全唐诗/poet.song.106000.json','["東山東遊形弔影，閉門作夏山房冷。", "兩士能來共寂寥，人謂同風吾未省。", "窗間一笑巖穴驚，窗外數峰清晝永。", "不知祖道今安危，自撥寒灰出燒餅。"]'),
('4098e9fd-5b11-49e7-9d16-430b983e2f97','送妙侍者遊方','釋慧空','宋','宋诗','song-poetry','','[]','秋雨秋風如解事，忽送新涼到庭戶。',160,'全唐诗/poet.song.106000.json','["秋雨秋風如解事，忽送新涼到庭戶。", "道人明日先我行，少立斯須聽吾語。", "龍蛇共路古猶今，魔佛同源水非乳。", "滿世誰能辨正邪，入門且可分賓主。", "句中有眼汝驗渠，棒下無私渠驗汝。", "好手雖然不犯鋒，橫身卻在鋒鋩裏。", "象王蹴蹋驢群空，師子嚬呻狐類死。", "道人一等是精靈，大顯無功合如此。", "愧當十偈非賞音，喜見獨行無伴侶。", "相逢休問來何從，佛壽之孫佛心子。"]'),
('e2f9f14f-c5dd-48fe-8955-89b223f03899','送僧遊天台  其一','釋慧空','宋','宋诗','song-poetry','','[]','天台五百尊者，喫盡秀峰酸豏。',70,'全唐诗/poet.song.106000.json','["天台五百尊者，喫盡秀峰酸豏。", "更引秀峰禪和，盡向橋頭脫賺。", "初開盞裏茶花，次散空中燈焰。", "分明不是好心，到者以何爲驗。", "若是具眼高流，一見不勞再勘。"]'),
('0ca3c731-d78f-403b-9efa-659c94126c33','送僧遊天台  其二','釋慧空','宋','宋诗','song-poetry','','[]','天台五百尊者，受盡秀峰供養。',70,'全唐诗/poet.song.106000.json','["天台五百尊者，受盡秀峰供養。", "更引秀峰禪和，費他草鞋拄杖。", "初說石梁橫空，次誇聖燈明亮。", "元來不是好心，只要遞相欺誑。", "煩公勘破歸來，領過不消一狀。"]'),
('e160690c-d31c-46c8-b87b-42d9223b8231','和趙超然  其一','釋慧空','宋','宋诗','song-poetry','','[]','鈍根阿師初樂小，同一法中人怪笑。',124,'全唐诗/poet.song.106000.json','["鈍根阿師初樂小，同一法中人怪笑。", "白雲堆裏強安身，掣電機前爭失照。", "業風吹下到天亭，無著力處盡力爭。", "一朝力盡卻自笑，放下蛇頭擺手行。", "超然居士今龐老，此日相逢猶草草。", "不知船子下揚州，更指梅花開恰好。", "開恰好，慚愧東君解傾倒。", "一枝倒把贈公行，擬行把住道道道。"]'),
('177c9ac2-6860-43a8-89fc-c2b2afa3c82a','和趙超然  其二','釋慧空','宋','宋诗','song-poetry','','[]','山僧當年活計小，冷地不知人怪笑。',124,'全唐诗/poet.song.106000.json','["山僧當年活計小，冷地不知人怪笑。", "白雲堆裏強安身，石火光中多失照。", "業風吹不到天亭，無著力處盡力爭。", "千歲靈龜退靈殻，而今步步火中行。", "超然居士今龐老，一笑相逢重撥草。", "全機透出上頭關，平屐家風且安好。", "且安好，走過市橋曾撻倒。", "回頭築著老丹霞，咄這冤家何不道。"]'),
('19b4c17d-9905-40e8-b7d3-731af6a27c93','喜溫首座至  其一','釋慧空','宋','宋诗','song-poetry','','[]','我昔識此老，謂之定上座。',72,'全唐诗/poet.song.106000.json','["我昔識此老，謂之定上座。", "是時朋輩中，箇箇道與麽。", "一別二十年，相逢皆老大。", "把手兩風顛，傍觀盡驚倒。", "翻思往者言，幸爾欺得過。", "若是在今日，管取遭一唾。"]'),
('2b7a6a0a-fa7f-4089-af64-e0234840a584','喜溫首座至  其二','釋慧空','宋','宋诗','song-poetry','','[]','兩翁相對好機緣，點在人人本命年。',64,'全唐诗/poet.song.106000.json','["兩翁相對好機緣，點在人人本命年。", "方外笑譚無忌諱，夢中歧路說迍邅。", "自從打破秦時鏡，總是花開臘月蓮。", "或問兩翁年幾許，尋常兒喚首羅天。"]'),
('76067463-5615-44c9-bbab-481713803ae9','與撮藥曹道','釋慧空','宋','宋诗','song-poetry','','[]','當陽拈出大家看，來處分明去處端。',32,'全唐诗/poet.song.106000.json','["當陽拈出大家看，來處分明去處端。", "總是諸人自遮護，先生豪髪不相瞞。"]'),
('9493fed0-fcf7-45d4-888b-962b9844b52c','與開道者','釋慧空','宋','宋诗','song-poetry','','[]','大悲院裏羅齋出，十字街頭覓水程。',32,'全唐诗/poet.song.106000.json','["大悲院裏羅齋出，十字街頭覓水程。", "肩上袈裟無一截，草鞋落地作金聲。"]'),
('49a0ae2f-77e8-480e-a977-fcadf22b6d59','與明州茂上人','釋慧空','宋','宋诗','song-poetry','','[]','十五已前不得去，寒木一尋生鐵鑄。',64,'全唐诗/poet.song.106000.json','["十五已前不得去，寒木一尋生鐵鑄。", "十五已後不得住，鍼筒鼻孔俱分付。", "正當十五天然別，誰管春寒與秋熱。", "拈起笠子爲焰光，遍在湖南幷兩浙。"]'),
('5dc3f640-32dc-4635-afc3-1085468aae27','送川全之雲門','釋慧空','宋','宋诗','song-poetry','','[]','入嶺踏著披秀，恰似倒食甘蔗。',126,'全唐诗/poet.song.106000.json','["入嶺踏著披秀，恰似倒食甘蔗。", "前頭節節不同，未可只麽掉下。", "雪峰玄沙黄蘗，鼓山東禪西禪。", "是處波騰嶽立，隨方五位三玄。", "一一從頭咬嚼，要令首尾完全。", "雲門盡頭一節，苦硬如咬生鐵。", "一咬咬著舌頭，洛陽橋成兩截。", "普賢隱身無地，文殊倒退三千。", "有問蔗作何味，附子出在西川。"]'),
('5d61a23f-a508-47a0-b445-c9ce22399c68','送德上人歸故山','釋慧空','宋','宋诗','song-poetry','','[]','泯泯衆人中，不與一人共。',84,'全唐诗/poet.song.106000.json','["泯泯衆人中，不與一人共。", "闃爾居閑房，儼若臨千衆。", "是謂有恒人，一心無二用。", "東山早嘗學，身行而口誦。", "久之如善射，縱橫無不中。", "魔外作姻親，蛇虎爲伯仲。", "離歌無可言，出此以爲送。"]'),
('be7d3b24-22db-48f1-93d5-e37774078b2f','送珍兄之黄蘗','釋慧空','宋','宋诗','song-poetry','','[]','老倒空生，言無旨的。',40,'全唐诗/poet.song.106000.json','["老倒空生，言無旨的。", "索瓶指泥，覓偈與墼。", "俊流把得，劈面便擲。", "如其不然，分付黄蘗。"]'),
('eaadc5b7-5b02-4d45-82e7-298e614d485f','和披秀韻與般陽明上人','釋慧空','宋','宋诗','song-poetry','','[]','衲僧一口劍，莫問何年鑄。',120,'全唐诗/poet.song.106000.json','["衲僧一口劍，莫問何年鑄。", "既有殺人威，亦有活人句。", "說夢老瞿曇，至今未曾悟。", "爲之子孫者，果以何爲據。", "聚頭化城中，自謂得安住。", "拋卻金剛王，記持死漢語。", "臘月三十日，一字不堪睹。", "若驚吾劍在，便解子與午。", "忽掛忽爲輪，可見不可取。", "提出長橋蛟，卻是南山虎。"]'),
('36dfa38f-b9ae-4cd0-9aba-c14907c03c35','與璨上人','釋慧空','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','參尋惟上士，駿逸諒無儔。',48,'全唐诗/poet.song.106000.json','["參尋惟上士，駿逸諒無儔。", "去住一言下，東西拄杖頭。", "主賓能互換，鍼芥更相投。", "忽竪頂門眼，西江水倒流。"]'),
('3971a2f7-4f0c-4799-a208-a9ebf35430bc','與勇上人','釋慧空','宋','宋诗','song-poetry','','[]','虎丘之虎老且死，道人勇者乃其子。',64,'全唐诗/poet.song.107000.json','["虎丘之虎老且死，道人勇者乃其子。", "以其有子父不亡，偈地風聲猶在耳。", "東山於其父子間，爲之道舊爲鄉里。", "要爾全機起乃翁，據虎頭而收虎尾。"]'),
('54323ebb-7ccd-4a2c-b2e8-3b0608003ae3','與眉州遠上人','釋慧空','宋','宋诗','song-poetry','','[]','左握峨眉右五臺，新羅喫粥七閩齋。',32,'全唐诗/poet.song.107000.json','["左握峨眉右五臺，新羅喫粥七閩齋。", "朝來不省何方去，背卻三門著草鞋。"]'),
('ef920874-f983-493b-b960-0db3dd1c610e','與通上人','釋慧空','宋','宋诗','song-poetry','','[]','行腳莫歸鄉，枝筇一條鐵。',48,'全唐诗/poet.song.107000.json','["行腳莫歸鄉，枝筇一條鐵。", "庵居不說禪，直以身爲舌。", "莫歸剛要歸，不說又著說。", "張翁把研槌，鍋中釣出鼈。"]'),
('16c41df6-261b-4438-babd-65ac04cb1d09','示僧  其一','釋慧空','宋','宋诗','song-poetry','','[]','推行出睦州擔版漢，是聖是凡齊贊嘆。',33,'全唐诗/poet.song.107000.json','["推行出睦州擔版漢，是聖是凡齊贊嘆。", "十方世界絕冤親，不用藏身更吞炭。"]'),
('7a329834-a8c9-4668-90f7-ddf6053bb684','示僧  其二','釋慧空','宋','宋诗','song-poetry','','[]','趙州狗子無佛性，咬人更不存性命。',32,'全唐诗/poet.song.107000.json','["趙州狗子無佛性，咬人更不存性命。", "大悲千手不能遮，跋陀那龍側耳聽。"]'),
('9f61bc0f-90bc-4374-a43e-886e44dc923e','示僧  其三','釋慧空','宋','宋诗','song-poetry','','[]','有問西來祖意，但與衲僧巴鼻。',28,'全唐诗/poet.song.107000.json','["有問西來祖意，但與衲僧巴鼻。", "香林坐久成勞，東山睡多損氣。"]'),
('044384d4-6f43-484e-b5aa-983b0da1e148','示僧  其四','釋慧空','宋','宋诗','song-poetry','','[]','一箇端坐喫不足，二箇同槃則有餘。',32,'全唐诗/poet.song.107000.json','["一箇端坐喫不足，二箇同槃則有餘。", "缺齒老胡曾未會，洞傳今古在吾徒。"]'),
('8317c55f-f8f7-42b2-b2bc-a2bcb16757d9','示僧  其五','釋慧空','宋','宋诗','song-poetry','','[]','普化傳真，七錯八錯。',46,'全唐诗/poet.song.107000.json','["普化傳真，七錯八錯。", "後人不明，隨邪逐惡。", "若是真鍮，黄金不博。", "今人長愛李將軍，一箭離弦雙鵰落。"]'),
('e6f6bbc9-f7f9-47a5-aa0f-f9335428bf85','送廣南僧','釋慧空','宋','宋诗','song-poetry','','[]','神光三拜，菩提達磨。',56,'全唐诗/poet.song.107000.json','["神光三拜，菩提達磨。", "老安平生，一破竈墮。", "東山病漢，石箇什麽。", "信筆寫出，不勘自破。", "丹山雛鳳九苞文，海壇犬子似驢大。"]'),
('bec9df90-8822-49d9-8a90-56b7934a90f2','送白上人還豐巖','釋慧空','宋','宋诗','song-poetry','','[]','我初不識丹霞師，邇來偶識丹霞子。',96,'全唐诗/poet.song.107000.json','["我初不識丹霞師，邇來偶識丹霞子。", "卻因其子識其師，雲水相懸渺千里。", "空生不往豐巖中，丹霞不到西庵裏。", "如何說箇相識來，理契即鄰休寐語。", "風前把出贈行人，虛空稽首須彌舞。", "千載冰巖一日春，懸水落崖聲似雨。"]'),
('1ee0087c-21ac-4d7d-8276-9e01cf0a84e4','送定勳二上人','釋慧空','宋','宋诗','song-poetry','','[]','定禪快爲師子吼，勳禪瑩凈玉無垢。',96,'全唐诗/poet.song.107000.json','["定禪快爲師子吼，勳禪瑩凈玉無垢。", "兩禪同居淵不分，一日用之左右手。", "超方獨脫王老師，向何壁立今何慈。", "杓柄短長鍋大小，揭而示之無可疑。", "末後更有一句子，未省兩禪著何語。", "東山有句不敢書，恐著替渠出山去。"]'),
('cee80136-b5ed-4fa3-a3ca-170786ef1eb4','和慈覺炊字韻幷送蘭蕙  其一','釋慧空','宋','宋诗','song-poetry','','[]','竹屋孤烟未斷炊，鷗盟歲晚不應違。',32,'全唐诗/poet.song.107000.json','["竹屋孤烟未斷炊，鷗盟歲晚不應違。", "五湖雲水座中客，一沼芰荷身上衣。"]'),
('f982787e-eba0-48d3-80c2-96efdd43d2c9','和慈覺炊字韻幷送蘭蕙  其二','釋慧空','宋','宋诗','song-poetry','','[]','蕙弟蘭兄本一山，莫如白下望長干。',32,'全唐诗/poet.song.107000.json','["蕙弟蘭兄本一山，莫如白下望長干。", "人間草木非其對，留與芝翁到老看。"]'),
('7d3b4508-c5a5-453e-8b3d-43676b677301','招南泉','釋慧空','宋','宋诗','song-poetry','','[]','一飯之微亦報緣，蒲團紙帳在吾年。',64,'全唐诗/poet.song.107000.json','["一飯之微亦報緣，蒲團紙帳在吾年。", "道惟簡易人惟儉，遯乃嘉肥進乃邅。", "問訊江頭白石佛，願回足下紫金蓮。", "當年手種庭前柏，歲晚青青欲入天。"]'),
('8da1c30e-c22f-4786-8e2e-e861048560ac','素上人爲普賢辦供過溪上需偈予曰與普賢有素不可無詞乃作五偈遺之歸山呈似道人一笑  其一','釋慧空','宋','宋诗','song-poetry','','[]','普賢願海君能續，火聚刀山勿厭登。',32,'全唐诗/poet.song.107000.json','["普賢願海君能續，火聚刀山勿厭登。", "更入人間煩惱海，自然觸處妙相應。"]'),
('2f8346e2-4c3c-4f7d-a505-0bff73b0ff85','素上人爲普賢辦供過溪上需偈予曰與普賢有素不可無詞乃作五偈遺之歸山呈似道人一笑  其二','釋慧空','宋','宋诗','song-poetry','','[]','素公初住峨眉寺，遣化人間要話行。',32,'全唐诗/poet.song.107000.json','["素公初住峨眉寺，遣化人間要話行。", "借問話頭何自得，大都來處要分明。"]'),
('6f9d9325-be3b-467f-a6a7-ff32453f7237','素上人爲普賢辦供過溪上需偈予曰與普賢有素不可無詞乃作五偈遺之歸山呈似道人一笑  其三','釋慧空','宋','宋诗','song-poetry','','[]','雞寒上樹鴨下水，舉著今人長努嘴。',32,'全唐诗/poet.song.107000.json','["雞寒上樹鴨下水，舉著今人長努嘴。", "衆生不明顛倒機，祖教從來同一軌。"]'),
('6e00b124-962c-4d9b-878e-60ad423b3875','素上人爲普賢辦供過溪上需偈予曰與普賢有素不可無詞乃作五偈遺之歸山呈似道人一笑  其四','釋慧空','宋','宋诗','song-poetry','','[]','保壽當年作街坊，街頭撞著自家底。',32,'全唐诗/poet.song.107000.json','["保壽當年作街坊，街頭撞著自家底。", "而今豈是有遮藏，撩起清風殊未已。"]'),
('26b860da-2cbf-45fe-a8f8-ea76381d9c57','素上人爲普賢辦供過溪上需偈予曰與普賢有素不可無詞乃作五偈遺之歸山呈似道人一笑  其五','釋慧空','宋','宋诗','song-poetry','','[]','千邪堆裏容開手，萬毒叢中許奪標。',32,'全唐诗/poet.song.107000.json','["千邪堆裏容開手，萬毒叢中許奪標。", "不墮功勳夷險外，前頭寶所即非遙。"]'),
('5ceeb271-073b-489b-9ca6-0be75b572fcd','華光墨梅','釋慧空','宋','宋诗','song-poetry','','[]','隔江遙望白雲村，橫折梅花臥石根。',32,'全唐诗/poet.song.107000.json','["隔江遙望白雲村，橫折梅花臥石根。", "病眼朦朧失端的，淡烟小雨復黄昏。"]'),
('8b6fb285-7c5f-4425-9b90-ee240d34e0fc','石菖蒲','釋慧空','宋','宋诗','song-poetry','','[]','僊裔來何許，羅浮小洞天。',48,'全唐诗/poet.song.107000.json','["僊裔來何許，羅浮小洞天。", "老僧忘百念，相對相翛然。", "水潔情惟潔，石堅心更堅。", "願持青苦節，庶定永君年。"]'),
('f2d88ca8-3c6e-4558-b9ec-e89f27b82230','書定兄宗派圖  其一','釋慧空','宋','宋诗','song-poetry','','[]','虛名驚世刻舟痕，迺祖初無一法傳。',32,'全唐诗/poet.song.107000.json','["虛名驚世刻舟痕，迺祖初無一法傳。", "流出胸襟蓋天地，只今子子與孫孫。"]'),
('2f2095f7-fd90-4015-a8c6-4b8325394211','書定兄宗派圖  其二','釋慧空','宋','宋诗','song-poetry','','[]','筆頭定有鑪槌地，陶冶諸方入正傳。',32,'全唐诗/poet.song.107000.json','["筆頭定有鑪槌地，陶冶諸方入正傳。", "不許南泉誇獨脫，且教雷例作兒孫。"]'),
('a06d4696-9621-4c8b-8913-0b8a7344cfba','觀僧作小字宗派圖  其一','釋慧空','宋','宋诗','song-poetry','','[]','蠅頭細字集爲圖，瓜瓞綿綿走線朱。',32,'全唐诗/poet.song.107000.json','["蠅頭細字集爲圖，瓜瓞綿綿走線朱。", "虎踞龍蟠諸老宿，半窗斜日黑蚍蜉。"]'),
('09821327-0d93-4516-b783-64ae571ca4b7','觀僧作小字宗派圖  其二','釋慧空','宋','宋诗','song-poetry','','[]','寒泉洗眼看新圖，字線岐分黑間朱。',32,'全唐诗/poet.song.107000.json','["寒泉洗眼看新圖，字線岐分黑間朱。", "妙似他方摶棗葉，巧如九曲度蚍蜉。"]'),
('838ba46e-e2d8-4ea6-8ae0-ee39a6b6a81b','戲題淵知客水墨圖','釋慧空','宋','宋诗','song-poetry','','[]','一身隨處得輕安，老入蒼崖疊嶂間。',32,'全唐诗/poet.song.107000.json','["一身隨處得輕安，老入蒼崖疊嶂間。", "真箇溪山看似夢，卻將水墨寫溪山。"]'),
('12c08fae-390d-4065-a770-534df71c70b8','書覺待者空寂會銘後','釋慧空','宋','宋诗','song-poetry','','[]','白首儒生困路岐，殘杯冷炙飽還饑。',32,'全唐诗/poet.song.107000.json','["白首儒生困路岐，殘杯冷炙飽還饑。", "一朝得意春風下，便把驢兒作馬騎。"]'),
('f0f9817f-1a04-492d-b175-59f9bd7aaf70','拄杖銘','釋慧空','宋','宋诗','song-poetry','','[]','黑似漆，清而癯。',95,'全唐诗/poet.song.107000.json','["黑似漆，清而癯。", "龍無角，蛇有鬚。", "契得之，不自扶。", "空老矣，乃用渠。", "穿天台挑衡廬，涵瀛浡，吞江湖。", "山水具，默然無。", "突然出，擬則迂。", "點須彌，爲丘墟。", "指牆壁，爲文殊。", "快薦取，勿躊躇。", "是之外，乃無餘。"]'),
('b45837c0-f675-4a3f-8c79-49cfaa382f8f','跋白鹿寄庵續寒山詩卷後','釋慧空','宋','宋诗','song-poetry','','[]','寒山忍寒哦五字，不爲世間瓜與瓠。',64,'全唐诗/poet.song.107000.json','["寒山忍寒哦五字，不爲世間瓜與瓠。", "寄庵續之則有餘，法燈擬之不相似。", "拾得日暮趁牛歸，豐干天明騎虎去。", "可憐辛苦油澆神，年年打供國清寺。"]'),
('c5a2981a-c1bb-4a06-a888-b32035504454','與曇上人','釋慧空','宋','宋诗','song-poetry','','[]','我今無別語，方便唯一路。',120,'全唐诗/poet.song.107000.json','["我今無別語，方便唯一路。", "古今賢聖人，皆由此得度。", "無爲一加鞭，只貴闊著步。", "力行不中休，理盡即自悟。", "不見新豐老，母在不歸去。", "不見老趙州，蹔歸終不住。", "兩翁僧中龍，千載乃一遇。", "觀其入道初，尚欲一味做。", "況我中下流，日用更多事。", "行行宜念諸，青春易遲暮。"]'),
('0cada674-13dc-455e-913f-2c1751a57849','次韻答靖侍者','釋慧空','宋','宋诗','song-poetry','','[]','一句忽截流，千差俱失路。',120,'全唐诗/poet.song.107000.json','["一句忽截流，千差俱失路。", "誰爲三界師，出生與滅度。", "一念忽到家，大千無跬步。", "誰爲九類生，沈迷及省悟。", "向來先達人，箇箇與麽去。", "只今禪家流，一一如是住。", "求其獨脫者，舉世亦罕遇。", "道人我同參，豈不以此故。", "遺我一使言，言言論何事。", "北鬰打三更，西瞿日未暮。"]'),
('96a531ad-eacb-4c14-81df-33ed4cc594bd','和劉天啟對牡丹歠茶','釋慧空','宋','宋诗','song-poetry','','[]','優曇惟時迺現，餘芳得暖爭抽。',112,'全唐诗/poet.song.107000.json','["優曇惟時迺現，餘芳得暖爭抽。", "誰肯不萌枝上，折來一洗春柔。", "小智勞乎刻畫，鈍根溺在熏修。", "縱是根同體一，皆爲蝶戲蜂游。", "所以南泉一指，頓開陸子雙眸。", "披秀因齋慶讚，東山助出茶甌。", "不是雲居安樂，絕勝黄蘗中洲。", "更看年年二月，扁舟逆上春流。"]'),
('4886e8e7-dd77-4144-b76a-cf154202ea9e','和秀峰  其一','釋慧空','宋','宋诗','song-poetry','','[]','白馬駝經弄玉蹄，雲中歸去不曾迷。',32,'全唐诗/poet.song.107000.json','["白馬駝經弄玉蹄，雲中歸去不曾迷。", "從今大事因緣畢，坐聽河聲流向西。"]'),
('3dcd93b6-3f13-469d-a1e8-d59a9e06ee5f','和秀峰  其二','釋慧空','宋','宋诗','song-poetry','','[]','教意拈來作麽看，唐言梵語不相干。',32,'全唐诗/poet.song.107000.json','["教意拈來作麽看，唐言梵語不相干。", "更將祖意論同別，識取雞寒與鴨寒。"]'),
('491b0c37-ca03-49ff-8a7d-5c53e245665e','才仲出示巨軸佳篇復檔案新詩降嘆不已又似欲置人於苦海中惟恐墮其計而不免次韻奉呈','釋慧空','宋','宋诗','song-poetry','','[]','先生詞源真洶湧，已如鳴鶴聞于天。',113,'全唐诗/poet.song.107000.json','["先生詞源真洶湧，已如鳴鶴聞于天。", "隋珠卻把暗投擲，但覺驚捧蛟槃圓。", "終須負鼎于明主，況其致治如烹鮮。", "伊尹未聘獨耕野，先生是以由居廛。", "古人投筆真不淺，爲有妙技非難捐。", "風流顧愷雖可尚，要之無乃癡爲爲緣。", "願言自信龜手藥，無使小子譏便便。"]'),
('f4a229b4-744b-4e00-8d60-ff9fac9521fb','送鵬上人','釋慧空','宋','宋诗','song-poetry','','[]','生兒墮地要著鞭，無使長居父母前。',96,'全唐诗/poet.song.107000.json','["生兒墮地要著鞭，無使長居父母前。", "既緇其衣童其顛，是欲置之於聖賢。", "聖賢道大非小緣，要當猛斷無遷延。", "九萬鵬程腳下天，一言相契猶未然。", "要中之要玄中玄，千人萬人得一傳。", "東山說罷鵬出門，祝融峰後湘水邊。"]'),
('2dfc6d67-0b87-434b-befa-fb1ff20294aa','送明首座幷簡元故人','釋慧空','宋','宋诗','song-poetry','','[]','目山第一座，江陰道人明。',108,'全唐诗/poet.song.107000.json','["目山第一座，江陰道人明。", "披秀五年住，衆中稱老成。", "龍門吹毛子，甌峰空故人。", "昨聞開定山，問之乃其兄。", "投機雷雨解，操行冰霜清。", "一點皮下血，大千塵中經。", "以公好兄弟，增我朋友情。", "新年拄杖頭，依舊吳山青。", "譚間煩引及，衰病老空生。"]'),
('3ee4f897-d478-48db-b52a-3d372f46af7a','甘泉惠石銚鄭才仲以詩見賞次韻酬之','釋慧空','宋','宋诗','song-poetry','','[]','老空剪茶器惟石，石有何好空乃惜。',64,'全唐诗/poet.song.107000.json','["老空剪茶器惟石，石有何好空乃惜。", "先生嗜好偶然同，我久眼中無此客。", "呼童活火煮山泉，旋破小團分五白。", "不嫌菌蠢賦龍頭，便覺彌明猶在席。"]'),
('5e1027ab-7a08-4030-b46b-a2b1ab368800','和才仲五字韻  其一','釋慧空','宋','宋诗','song-poetry','','[]','豹變惟君子，吾方見一斑。',48,'全唐诗/poet.song.107000.json','["豹變惟君子，吾方見一斑。", "君宜爲世瑞，未用愛僧閑。", "文出東西漢，詩成大小山。", "殷勤五字句，乞我薜蘿間。"]'),
('2173187a-2ec8-43d5-8b37-c3ff958f9d5b','和才仲五字韻  其二','釋慧空','宋','宋诗','song-poetry','','[]','一身走四海，未老髪先斑。',48,'全唐诗/poet.song.107000.json','["一身走四海，未老髪先斑。", "得住從緣住，非閑亦似閑。", "泉鳴堂下石，雲起屋頭山。", "不礙往來者，無人到此間。"]'),
('ea129d5d-c6b9-47e9-a88d-b6438627b95e','漆匠王榮朱法座求頌','釋慧空','宋','宋诗','song-poetry','','[]','大鑑祖師曾指出，拄地撐天黑似漆。',64,'全唐诗/poet.song.107000.json','["大鑑祖師曾指出，拄地撐天黑似漆。", "衆生日用多不知，王榮代代承恩力。", "承恩力，皎如日，擲地金聲更堅密。", "兩手持來付與人，一任高低酬價直。"]'),
('65b6d180-4d43-4057-9899-eeb31f3e6808','與凈上人開行和尚語錄','釋慧空','宋','宋诗','song-poetry','','[]','捏烏巨山爲筆，蘸鄱陽湖作墨。',42,'全唐诗/poet.song.107000.json','["捏烏巨山爲筆，蘸鄱陽湖作墨。", "空中大書六字，薦福和尚語錄。", "若人一覽無遺，山僧與伊臠肉。"]'),
('ca629c36-9b22-4342-a30c-715bd62bbb3b','和無在悼惠書記  其一','釋慧空','宋','宋诗','song-poetry','','[]','惠初不死而言死，空本無情似有情。',32,'全唐诗/poet.song.107000.json','["惠初不死而言死，空本無情似有情。", "手把遺書一揮淚，秦溪三夜雨連明。"]'),
('329b55b6-128b-44ef-80e8-5436ff21a334','和無在悼惠書記  其二','釋慧空','宋','宋诗','song-poetry','','[]','憶昨同渠離汝水，而今先我至天台。',32,'全唐诗/poet.song.107000.json','["憶昨同渠離汝水，而今先我至天台。", "後生乍轉通身句，悔不當初與道來。"]'),
('5c2a35d8-2adf-45b5-8738-5ccc8d6fca45','和無在悼惠書記  其三','釋慧空','宋','宋诗','song-poetry','','[]','全死全生大法王，能醫生死更無方。',32,'全唐诗/poet.song.107000.json','["全死全生大法王，能醫生死更無方。", "乾城影裏封疆闊，石火光中劫數長。"]'),
('94ceb546-a49e-4682-9b1a-677d36534b7d','前日有客陳墨梅者僕因誦高臺所作爲絕至於尋常墨綴處餘人用盡工夫不到不知圓公何從見聞客疑僕能之昨日袖紙相過苦求揮灑不覺令人失笑因戲作少謝盛意是中亦有墨梅請呈本際老必爲指出','釋慧空','宋','宋诗','song-poetry','','[]','高臺仁老今已老，冷藥疏枝餘薄怒。',96,'全唐诗/poet.song.107000.json','["高臺仁老今已老，冷藥疏枝餘薄怒。", "後來塗抹如牛毛，過眼番番泛於土。", "不如十月江南行，長條半落霜冰清。", "冰魂玉骨淡不俗，宛轉自有騷人情。", "惟公好事心尚爾，若愛霜枝橫短紙。", "不因作意寬作程，少待今年冰雪底。"]'),
('eb83f84e-18c8-4800-ab58-566bc121039a','悼覺庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','石人生子便英靈，胎髪未除先老成。',32,'全唐诗/poet.song.107000.json','["石人生子便英靈，胎髪未除先老成。", "不讀五經並十史，一言才出萬人驚。"]'),
('1bd1880a-bc3a-4dfc-9c94-e0e96b3a873c','悼覺庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','有何等語能驚衆，三問渠儂三不知。',32,'全唐诗/poet.song.107000.json','["有何等語能驚衆，三問渠儂三不知。", "是我松齋會心友，或聞或見更無疑。"]'),
('50fbbe0c-91dc-4c3d-948d-834d3a6cae1d','悼覺庵  其三','釋慧空','宋','宋诗','song-poetry','','[]','鳥道玄關方打脫，刀山劍樹又躋攀。',32,'全唐诗/poet.song.107000.json','["鳥道玄關方打脫，刀山劍樹又躋攀。", "老來別得安身法，八面朱門夜不關。"]'),
('fb0ff0a4-01c3-497f-9c9e-1a1539ac9913','南華定兄訪予疏山臨分欲偈作此','釋慧空','宋','宋诗','song-poetry','','[]','一滴曹溪水，千江悉混流。',48,'全唐诗/poet.song.107000.json','["一滴曹溪水，千江悉混流。", "深期能遠到，未可輒中休。", "知識隨方有，禪林在處稠。", "杖頭親探過，歸路卻相求。"]'),
('34109952-037b-416f-9ea1-f7ed8b94f607','送吳居士','釋慧空','宋','宋诗','song-poetry','','[]','化緣架就留香堂，乞飯又飽留香衆。',48,'全唐诗/poet.song.107000.json','["化緣架就留香堂，乞飯又飽留香衆。", "明年入夏便歸來，三日一齋五日供。", "普願雪山立雪徒，聖箭離弦萬鈞重。"]'),
('9d3b9df1-2c0c-4d3c-b4ee-547b02ae9f55','送鑑維那弼侍者之徑山  其一','釋慧空','宋','宋诗','song-poetry','','[]','佛日叢林我弟兄，見來應是問空生。',32,'全唐诗/poet.song.107000.json','["佛日叢林我弟兄，見來應是問空生。", "謂如烏石嶺頭石，送盡行人自不行。"]'),
('e3f64912-4ba7-419f-b8bc-26acec3119da','送鑑維那弼侍者之徑山  其二','釋慧空','宋','宋诗','song-poetry','','[]','弼禪弼禪，緊峭草鞋闊著步。',69,'全唐诗/poet.song.107000.json','["弼禪弼禪，緊峭草鞋闊著步。", "莫似山僧，繩牀角頭立地時。", "徑山老人我知識，橫膝竹篦三尺鐵。", "那吒頂上喫一掣，金剛腳下流出血。", "別別，辰錦砂兮未爲赤。"]'),
('5f0e6a09-6e47-4ccb-b23a-c71f970090f7','送澤監寺出嶺','釋慧空','宋','宋诗','song-poetry','','[]','我自入嶺來，稱鎚落深井。',48,'全唐诗/poet.song.107000.json','["我自入嶺來，稱鎚落深井。", "如君英俊流，當以我爲警。", "摩挲探水杖，透脫飛猿嶺。", "送別無所譚，霜清溪路永。"]'),
('ec1b3665-0d7e-494a-8ca3-c7ec3e486a40','和劉天常見寄','釋慧空','宋','宋诗','song-poetry','','[]','足疾三年只杜門，孤懷如月耿朝昏。',64,'全唐诗/poet.song.107000.json','["足疾三年只杜門，孤懷如月耿朝昏。", "同風不昧古人意，此道當期老者論。", "露地白牛純到角，雪山香草細和根。", "蘇州未解吾家事，夜對高僧無一言。"]'),
('291550a3-da55-4f6b-b0ed-3c32ce36286b','送悟大師重造金剛','釋慧空','宋','宋诗','song-poetry','','[]','八大金剛常住世，護佛正法令久住。',64,'全唐诗/poet.song.107000.json','["八大金剛常住世，護佛正法令久住。", "精藍金剛相先壞，欲令正法住爲難。", "悟禪致力扶正法，故先成此金剛王。", "老僧嘉悟善用心，說偈贊其令速辦。"]'),
('66baedc7-2ee5-4db1-8569-5f41cad5fdeb','送妙修造','釋慧空','宋','宋诗','song-poetry','','[]','昔人架屋著閑漢，同道嗔之不與語。',64,'全唐诗/poet.song.107000.json','["昔人架屋著閑漢，同道嗔之不與語。", "秀峰屋下沒閑人，不是超佛即超祖。", "佛祖至大渠更超，此屋黄金君勿憚。", "下山遍訪檀施門，必有奇人咄嗟辦。"]'),
('2422421a-7f97-404e-92b7-79e84f385c9c','送本書記住保壽','釋慧空','宋','宋诗','song-poetry','','[]','吳山道人真倔強，氣吞佛祖無諸方。',115,'全唐诗/poet.song.107000.json','["吳山道人真倔強，氣吞佛祖無諸方。", "飽參不數古韶偃，操詞不齒今蘇黄。", "獨能以文事圓悟，期於季軟振頹綱。", "緣熟果能符素志，要與乃祖聯遺芳。", "金券揭起益高價，栗蒲突出重耿光。", "弄蹄驢子驥莫及，踢出保壽今開堂。", "三聖休更推僧出，此公毒手難近傍。", "咦！。"]'),
('7872be0c-5e00-4421-8d49-484845ecf603','送忍禪遊方','釋慧空','宋','宋诗','song-poetry','','["\u8861\u5c71"]','人言祖意不可說，未動唇吻先卷舌。',96,'全唐诗/poet.song.107000.json','["人言祖意不可說，未動唇吻先卷舌。", "雖然說著也不妨，道火何曾口邊熱。", "若作說會一重關，不作說會萬重山。", "自家肚皮自家劃，莫被傍人開眼瞞。", "忍禪少年心踴躍，買雙草鞋穿兩腳。", "天台南嶽走一遭，鐵額銅頭須撞著。"]'),
('39e95025-0bb2-48a2-bad3-bdacfc4c1edb','贈寥元飾  其一','釋慧空','宋','宋诗','song-poetry','','[]','十日中林足音絕，陳雲不飛天欲雪。',96,'全唐诗/poet.song.107000.json','["十日中林足音絕，陳雲不飛天欲雪。", "剪剪溪風忽轉霜，天工似與遊人設。", "蹇驢風帽溪上來，眼明一二僧窗開。", "地爐夜話月入屋，竹徑朝行山放梅。", "公家秦溪富山水，碧瓦朱甍空翠裏。", "還家開取虎頭巖，會見丹霞訪居士。"]'),
('bfd8ad42-4b99-401b-b1f7-76ee9ea80185','贈寥元飾  其二','釋慧空','宋','宋诗','song-poetry','','[]','世途湔去利名垢，僧榻來熏知見香。',32,'全唐诗/poet.song.107000.json','["世途湔去利名垢，僧榻來熏知見香。", "昭曠情懷陶靖節，清明風韻孟襄陽。"]'),
('d927863b-47ae-43c2-a4ec-f9d9cde11e52','贈寥元飾  其三','釋慧空','宋','宋诗','song-poetry','','[]','家住秦溪紫翠間，好山終日遶朱闌。',32,'全唐诗/poet.song.107000.json','["家住秦溪紫翠間，好山終日遶朱闌。", "莫如馬上尋山者，到老不知身在山。"]'),
('361f49cf-cc03-4938-b4da-62b2ea515bd8','和劉天啟並留別  其一','釋慧空','宋','宋诗','song-poetry','','[]','崇觀文章獨老蒼，後生猶及見堂堂。',64,'全唐诗/poet.song.107000.json','["崇觀文章獨老蒼，後生猶及見堂堂。", "十年契闊形容改，一日相逢道韻長。", "盡啟軒窗供遠目，莫嫌蔬筍飯家常。", "願陪劉遠焚香在，蓮社風流有耿光。"]'),
('3c2ca0fa-82b0-4a8b-adc0-bad1c63df6e7','和劉天啟並留別  其二','釋慧空','宋','宋诗','song-poetry','','[]','相從無十日，相別又經年。',24,'全唐诗/poet.song.107000.json','["相從無十日，相別又經年。", "爲問南來雁，群飛孰使然。"]'),
('225615f0-568d-4b4a-854a-760944d9c70d','和彥正居士見寄並勉定兄及再和夢石  其一','釋慧空','宋','宋诗','song-poetry','','[]','學道窮年無寸勳，忘機似可置鷗群。',64,'全唐诗/poet.song.107000.json','["學道窮年無寸勳，忘機似可置鷗群。", "謾勞長者開青眼，送與高巖臥白雲。", "機鈍莫酬摩詰問，鼻端終待郢人斤。", "歸來不寐思君語，落澗寒泉深夜聞。"]'),
('e30cd271-f60c-4e1b-a5a9-01fafab8e594','和彥正居士見寄並勉定兄及再和夢石  其二','釋慧空','宋','宋诗','song-poetry','','[]','從容中道絕功勳，野鶴昂藏不類群。',64,'全唐诗/poet.song.107000.json','["從容中道絕功勳，野鶴昂藏不類群。", "雙眼炯如潭底月，一身閑似嶺頭雲。", "撮來大地如粟粒，放去龜毛重九斤。", "三載相依話疇昔，我初無說子無聞。"]'),
('597d0bb8-fe69-423e-a3cc-5deeb186f268','和彥正居士見寄並勉定兄及再和夢石  其三','釋慧空','宋','宋诗','song-poetry','','[]','貧家只有四立壁，分歲那進豪右群。',64,'全唐诗/poet.song.107000.json','["貧家只有四立壁，分歲那進豪右群。", "方辦五言酬絕唱，又傳秀句入深雲。", "應機殺活生譚笑，信手方圓斫斧斤。", "無以險崖多困我，須防官府有新聞。"]'),
('533db5e3-450d-4cf0-92af-8d9173aa08f9','與嶽麓範老','釋慧空','宋','宋诗','song-poetry','','[]','閩蜀限西南，中有同風句。',48,'全唐诗/poet.song.107000.json','["閩蜀限西南，中有同風句。", "今年台雁行，一笑果相遇。", "朝飯靈峰泉，暮宿中巖寺。", "常恐溪漲時，阿師截流去。"]'),
('c97dfc64-da6f-44ab-a111-def2a8af2978','送印禪歸鄉','釋慧空','宋','宋诗','song-poetry','','[]','秦溪青田十日程，自彼到此小行腳。',64,'全唐诗/poet.song.107000.json','["秦溪青田十日程，自彼到此小行腳。", "念來三見楓葉丹，依然又带天平錯。", "問渠去矣再來無，遊客雖好家山樂。", "我亦無家可得歸，去去善爲山路惡。"]'),
('d5b646f5-4bb6-4c77-8cfc-e6d3af12964e','送僧行腳','釋慧空','宋','宋诗','song-poetry','','[]','趙州送人曾有語，有佛無佛俱莫住。',128,'全唐诗/poet.song.107000.json','["趙州送人曾有語，有佛無佛俱莫住。", "若是金毛師子兒，他家自有通霄路。", "因記雪峰行腳時，九上洞山三投子。", "被風墮笠渠不收，蓋天蓋地從此始。", "兩翁從此跡已陳，後世事之如事生。", "道人即是後來秀，千里脩途宜力行。", "勿賢前輩輒自已，當與兩翁爭重輕。", "我如老馬雖伏櫪，喜見此行猶更鳴。"]'),
('b3b4e57b-3b72-4948-b986-af774f1fc461','示澤監寺','釋慧空','宋','宋诗','song-poetry','','[]','雲門山，澤監寺，對空生，出此語。',60,'全唐诗/poet.song.107000.json','["雲門山，澤監寺，對空生，出此語。", "書偈及傳衣，全非衲僧事。", "等閑透出雲門關，赤手要縛南山虎。", "三寸㔢除能再來，凜凜威風驚海宇。"]'),
('0cd91d9d-5866-4624-a203-26acb170eca1','書知微偈後','釋慧空','宋','宋诗','song-poetry','','[]','醯雞負須彌，瞬息九萬里。',48,'全唐诗/poet.song.107000.json','["醯雞負須彌，瞬息九萬里。", "獼猴對秦鏡，一一總沒尾。", "生平五湖心，短笛秋風裏。", "借問魚有無，夜涼天在水。"]'),
('4b18eb82-bf66-4400-bf5a-6a14ab63b773','寄拂柄與知微微不受兼頌附回後有僧請益故答之','釋慧空','宋','宋诗','song-poetry','','[]','火中駑馬變黄牛，不見全身露兩頭。',32,'全唐诗/poet.song.107000.json','["火中駑馬變黄牛，不見全身露兩頭。", "龍樹馬鳴齊卷舌，山僧親爲說來由。"]'),
('2e300b3a-0759-4d73-b9f8-9d3b6965fb1d','送本首座還梅州','釋慧空','宋','宋诗','song-poetry','','[]','病夫獨臥雪山雪，抱渴惟思梅嶺梅。',32,'全唐诗/poet.song.107000.json','["病夫獨臥雪山雪，抱渴惟思梅嶺梅。", "歲晚犯寒宜好去，新年忍死待歸來。"]'),
('ac641a88-b4c6-449e-a2c8-dfe83136ed1a','信道姑見佛日','釋慧空','宋','宋诗','song-poetry','','[]','信是有髪比丘尼，東山不及渠一著。',32,'全唐诗/poet.song.107000.json','["信是有髪比丘尼，東山不及渠一著。", "聞說佛日嶺外還，不起公憑便行腳。"]'),
('2b7c630a-f5c8-440f-9c64-7739b24b6d57','寄信上人','釋慧空','宋','宋诗','song-poetry','','[]','一瓶一鉢且隨緣，此事時時強爲宣。',32,'全唐诗/poet.song.107000.json','["一瓶一鉢且隨緣，此事時時強爲宣。", "知己不來春自老，孤峰皎月對寒泉。"]'),
('c90d349c-60a8-4b52-8268-f89504b8863a','獨宿省堂告友人','釋慧空','宋','宋诗','song-poetry','','[]','秋瘴驚寒卻自平，匡牀獨臥四無聲。',32,'全唐诗/poet.song.107000.json','["秋瘴驚寒卻自平，匡牀獨臥四無聲。", "涅槃堂裏通身句，永夜孤燈一點明。"]'),
('648900d7-d2c3-4e50-816d-c197df425121','懷友  其一','釋慧空','宋','宋诗','song-poetry','','[]','一牛鳴地竹橋西，成趣生涯有菜畦。',32,'全唐诗/poet.song.107000.json','["一牛鳴地竹橋西，成趣生涯有菜畦。", "三度春歸憶君別，亂紅如雨暗前溪。"]'),
('1f7aaf86-03d9-4df9-b4e0-964ba5fd8bf5','懷友  其二','釋慧空','宋','宋诗','song-poetry','','[]','仙翁初不記年華，食罷蟠桃又著花。',32,'全唐诗/poet.song.107000.json','["仙翁初不記年華，食罷蟠桃又著花。", "只在人前人不識，藍溪流水兩三家。"]'),
('7830bcd8-3c67-4788-827f-062c88d71fe5','寄谷堂老','釋慧空','宋','宋诗','song-poetry','','[]','谷堂去我如許久，病起諸峰瘦入天。',32,'全唐诗/poet.song.107000.json','["谷堂去我如許久，病起諸峰瘦入天。", "放髪齊眉寒又至，幾時歸叫老風顛。"]'),
('abe9659a-59e9-4303-9b1b-4d8171ef461f','送光兄之百丈兼呈山中禪師以當書矣  其一','釋慧空','宋','宋诗','song-poetry','','[]','不疑汝未徹，端的若爲分。',24,'全唐诗/poet.song.107000.json','["不疑汝未徹，端的若爲分。", "寶劍寒光動，桃花雲裏春。"]'),
('1cb98768-f3f7-4ead-be73-a9ff29a9b622','送光兄之百丈兼呈山中禪師以當書矣  其二','釋慧空','宋','宋诗','song-poetry','','[]','生涯一物無，坐對方來客。',24,'全唐诗/poet.song.107000.json','["生涯一物無，坐對方來客。", "有問不違伊，向道庭前柏。"]'),
('007d3a03-8d7d-4db5-b2d5-f96725481d73','送善兄還洞山兼呈方丈  其一','釋慧空','宋','宋诗','song-poetry','','[]','洞山好佛貴兼尊，老奯才方得入門。',32,'全唐诗/poet.song.107000.json','["洞山好佛貴兼尊，老奯才方得入門。", "留得中心者些子，而今著力有兒孫。"]'),
('dd24b08d-6719-41fa-8de5-18933c1e022b','送善兄還洞山兼呈方丈  其二','釋慧空','宋','宋诗','song-poetry','','[]','一書遠寄雲中舊，五偈仍觀雪子吟。',32,'全唐诗/poet.song.107000.json','["一書遠寄雲中舊，五偈仍觀雪子吟。", "且喜新豐消息在，南方滿眼是叢林。"]'),
('bd76c1f1-10e9-49e2-9da1-3d5d17adb2fa','謝龐道惠茶','釋慧空','宋','宋诗','song-poetry','','[]','冰雪心腸獨老龐，一枝春信果無雙。',32,'全唐诗/poet.song.107000.json','["冰雪心腸獨老龐，一枝春信果無雙。", "茅堂客散熏爐冷，有味無言日轉窗。"]'),
('cf01490a-d1c9-443c-8e9d-457f0250c734','本老昔住此庵今出世再過山次日出諸偈頌乃和之','釋慧空','宋','宋诗','song-poetry','','[]','舀溪長柄向來杓，瑞世優曇今日花。',32,'全唐诗/poet.song.107000.json','["舀溪長柄向來杓，瑞世優曇今日花。", "到我住庵無此瑞，只將溪水煮山茶。"]'),
('07cf29a0-6218-493e-8112-b644eefa09eb','僧上蜀絹毛段不受以偈謝之','釋慧空','宋','宋诗','song-poetry','','[]','關西毛段蜀川絹，萬里持來恐亦艱。',32,'全唐诗/poet.song.107000.json','["關西毛段蜀川絹，萬里持來恐亦艱。", "謝汝殷勤復歸汝，老僧布衲得遮寒。"]'),
('6674edfa-abb4-4f69-8835-a8b8636e812e','送澤上人','釋慧空','宋','宋诗','song-poetry','','[]','出入叢林成歲月，養成大樹沒根栽。',32,'全唐诗/poet.song.107000.json','["出入叢林成歲月，養成大樹沒根栽。", "東山老矣病且耄，爲蔭爲涼待後來。"]'),
('46e2338c-ee98-40b5-8df1-8b27cecc276a','容茶頭爲本無庵道頭陀求偈','釋慧空','宋','宋诗','song-poetry','','[]','道本無根卻有根，根深枝葉遍乾坤。',32,'全唐诗/poet.song.107000.json','["道本無根卻有根，根深枝葉遍乾坤。", "不知根本深多少，往見頭陀試問看。"]'),
('47a7789b-0b5c-47de-809b-559d066ffed3','與通上人','釋慧空','宋','宋诗','song-poetry','','[]','迷時翻手迷爲悟，悟處存心悟是迷。',32,'全唐诗/poet.song.107000.json','["迷時翻手迷爲悟，悟處存心悟是迷。", "迷悟兩忘歸路盡，皖山深夜老猿啼。"]'),
('d429660d-8695-4b79-91ae-d14e9f02dd45','送僧歸四明','釋慧空','宋','宋诗','song-poetry','','[]','跛鼈三年病，一書千里心。',24,'全唐诗/poet.song.107000.json','["跛鼈三年病，一書千里心。", "冤家容可避，到老也相尋。"]'),
('f066a058-dd6f-44a4-b59c-cc47573c31f7','送曇上人遊方','釋慧空','宋','宋诗','song-poetry','','[]','昔人有言生處樂，東山何勸人行腳。',64,'全唐诗/poet.song.107000.json','["昔人有言生處樂，東山何勸人行腳。", "殊方異域走苦辛，峻嶺重關多險惡。", "東山往昔被賺來，故就于今拔本著。", "問渠端的何處生，一言解卻通身縛。"]'),
('c94a3d8c-47aa-49ea-a13e-83fc1b26b67a','題石室並和澹庵  其一','釋慧空','宋','宋诗','song-poetry','','[]','野桃欹岸竹連雲，石徑縈紆到洞門。',32,'全唐诗/poet.song.107000.json','["野桃欹岸竹連雲，石徑縈紆到洞門。", "花落莫隨流水去，恐人認此是桃源。"]'),
('064de1cc-64b2-4677-8acc-1463b02584e4','題石室並和澹庵  其二','釋慧空','宋','宋诗','song-poetry','','[]','石門有路建隆初，樹老崖荒路欲無。',32,'全唐诗/poet.song.107000.json','["石門有路建隆初，樹老崖荒路欲無。", "我以多生巖下住，到門先記石於菟。"]'),
('9b517489-0d8a-4a56-992d-cc6b7096c2fe','題石室並和澹庵  其三','釋慧空','宋','宋诗','song-poetry','','[]','山日輝輝雲細細，石渠淺淺竹疏疏。',32,'全唐诗/poet.song.107000.json','["山日輝輝雲細細，石渠淺淺竹疏疏。", "珍禽引客飛還住，靈草忽香尋卻無。"]'),
('2247afbf-37fc-495a-b184-13ed550a5905','題石室並和澹庵  其四','釋慧空','宋','宋诗','song-poetry','','[]','百里尋山但宿春，欲留未得去還慵。',32,'全唐诗/poet.song.107000.json','["百里尋山但宿春，欲留未得去還慵。", "東風莫使歸帆飽，放我中流認九峰。"]'),
('f4befb85-6555-447a-9cff-eaa1f3004eb5','題石室並和澹庵  其五','釋慧空','宋','宋诗','song-poetry','','[]','要識停廚第一方，爲空石廩著黄粱。',32,'全唐诗/poet.song.107000.json','["要識停廚第一方，爲空石廩著黄粱。", "明年便入巖中坐，五偈先來作定場。"]'),
('1b01bbb9-e23c-4791-9ab1-784b9c84a958','題石室並和澹庵  其六','釋慧空','宋','宋诗','song-poetry','','[]','住如止水動如雲，去住無拘是我門。',32,'全唐诗/poet.song.107000.json','["住如止水動如雲，去住無拘是我門。", "又舉杖頭千佛剎，來藏海上小桃源。"]'),
('986ae24f-4506-41aa-b853-12446959884a','題石室並和澹庵  其七','釋慧空','宋','宋诗','song-poetry','','[]','驚蛇斷路我來初，鉢掛藤梢物物無。',32,'全唐诗/poet.song.107000.json','["驚蛇斷路我來初，鉢掛藤梢物物無。", "只向無中成活計，譍門童子兩於菟。"]'),
('9fa30885-2785-4d80-b985-13bfbb070f55','題石室並和澹庵  其八','釋慧空','宋','宋诗','song-poetry','','[]','衣雨調階泉淅瀝，青烟遶屋樹扶疏。',32,'全唐诗/poet.song.107000.json','["衣雨調階泉淅瀝，青烟遶屋樹扶疏。", "異時有問碧巖境，舉似酬之莫道無。"]'),
('a065a863-e78e-49ad-8a29-2fdf16963a04','題石室並和澹庵  其九','釋慧空','宋','宋诗','song-poetry','','[]','黄陳五合不勞舂，食罷無營一似慵。',32,'全唐诗/poet.song.107000.json','["黄陳五合不勞舂，食罷無營一似慵。", "麋鹿往還溪上路，白雲開合面前峰。"]'),
('53ae65a7-e8f0-4f2c-82af-29ee4f309892','題石室並和澹庵  其一○','釋慧空','宋','宋诗','song-poetry','','[]','來年四色更多方，憂水憂風憂夏糧。',32,'全唐诗/poet.song.107000.json','["來年四色更多方，憂水憂風憂夏糧。", "未必澹庵能快活，隨身干木便逢場。"]'),
('2a952f60-a7eb-4b70-b9d7-9d2957ce19eb','戒庵主示諸老船子圖偈贊因與之結緣  其一','釋慧空','宋','宋诗','song-poetry','','[]','我笑華亭老，虛舟漾明月。',24,'全唐诗/poet.song.107000.json','["我笑華亭老，虛舟漾明月。", "撞著問津人，萬劫繫驢橛。"]'),
('37ebb548-3643-4f4b-aa20-cc4a1abc78cf','戒庵主示諸老船子圖偈贊因與之結緣  其二','釋慧空','宋','宋诗','song-poetry','','[]','開口贈兩橈，老婆心更切。',24,'全唐诗/poet.song.107000.json','["開口贈兩橈，老婆心更切。", "回首與翻身，亦未爲剿絕。"]'),
('0e70c4b7-e684-422c-a626-b72025bd26f1','戒庵主示諸老船子圖偈贊因與之結緣  其三','釋慧空','宋','宋诗','song-poetry','','[]','那堪钁頭邊，勿令有斷絕。',24,'全唐诗/poet.song.107000.json','["那堪钁頭邊，勿令有斷絕。", "老戒不放伊，攜之入閩粤。"]'),
('892dd2f0-5243-40b1-a8cc-f37a24ebabac','戒庵主示諸老船子圖偈贊因與之結緣  其四','釋慧空','宋','宋诗','song-poetry','','[]','到處出似人，幾箇知時節。',24,'全唐诗/poet.song.107000.json','["到處出似人，幾箇知時節。", "空也心膽麤，戒戒勿漏泄。"]'),
('2aa682c1-5c63-4693-9a1e-50fb569a31d0','離雲居寓九仙寄無住','釋慧空','宋','宋诗','song-poetry','','[]','癡雲翳目不肯散，一雨一風行路迷。',64,'全唐诗/poet.song.107000.json','["癡雲翳目不肯散，一雨一風行路迷。", "好山但自著狐兔，百城孤客其安之。", "朝來喜事遽如許，高空卷雲風掃雨。", "徑須呼我木上座，去探大雄山下虎。"]'),
('5daabeaa-1530-47ea-9c30-927fe4115e9f','和可上人','釋慧空','宋','宋诗','song-poetry','','[]','夢裏身投九澤鄉，共驚日月去堂堂。',64,'全唐诗/poet.song.107000.json','["夢裏身投九澤鄉，共驚日月去堂堂。", "江湖亂後人雖健，鴻雁不來書亦亡。", "訪舊悲涼山起霧，得君譚笑目生光。", "犀牛扇破犀牛在，宜有清風可播揚。"]'),
('eb00b228-2429-4470-bb25-fdc336549bd9','答宜禪頌見謁','釋慧空','宋','宋诗','song-poetry','','[]','宜禪謁老空，先自著便宜。',48,'全唐诗/poet.song.107000.json','["宜禪謁老空，先自著便宜。", "分明金彈子，博得糞球兒。", "把得急拋下，堂堂空手歸。", "前路逢人問，如何舉似伊。"]'),
('02584aed-2971-4716-8243-d27b31d54924','過疏山化士求謁','釋慧空','宋','宋诗','song-poetry','','[]','南來雨宿仍風餐，蠻溪鬼洞三年還。',96,'全唐诗/poet.song.107000.json','["南來雨宿仍風餐，蠻溪鬼洞三年還。", "叢林龍象老衲死，處處鐘鼓空雲山。", "獨聞疏山有尊宿，不減當年矮師叔。", "欲求法雨洗蠻烟，正恐齋廚窘炊玉。", "道人忽從山中來，要乞上方香飯回。", "我方癡坐視屋壁，毛孔要須香七日。"]'),
('a6128b6e-dbb4-4d31-8ff5-22c446ac2ddd','送泐潭化士  其一','釋慧空','宋','宋诗','song-poetry','','[]','大智承當三日聾，丈夫志氣豈雷同。',32,'全唐诗/poet.song.107000.json','["大智承當三日聾，丈夫志氣豈雷同。", "飛鸞渡水急於箭，喝下教伊不敢東。"]'),
('dadbc50d-9a44-45f0-bcf1-f0072c68dec1','送泐潭化士  其二','釋慧空','宋','宋诗','song-poetry','','[]','不道二方遭毒手，更持一鉢訪空生。',32,'全唐诗/poet.song.107000.json','["不道二方遭毒手，更持一鉢訪空生。", "空生亦似把不住，放出瞎驢隨隊行。"]'),
('1c5ab58e-0bd8-4a35-95c5-d775be4a9c2f','送泐潭化士  其三','釋慧空','宋','宋诗','song-poetry','','[]','瞎驢無足尾過頭，蹴踏乾坤勢未休。',32,'全唐诗/poet.song.107000.json','["瞎驢無足尾過頭，蹴踏乾坤勢未休。", "大寂馬駒追莫及，溈山水牯豈同流。"]'),
('f219a2d5-0599-44e3-a930-33a76be9408b','送油頭  其一','釋慧空','宋','宋诗','song-poetry','','[]','十分親近見還遲，放去令渠自發機。',32,'全唐诗/poet.song.107000.json','["十分親近見還遲，放去令渠自發機。", "他日歸來如點著，普天無處不光輝。"]'),
('1f4b73f7-1330-4275-9ff6-76117c739149','送油頭  其二','釋慧空','宋','宋诗','song-poetry','','[]','明星時時出現，衆生日日成道。',28,'全唐诗/poet.song.107000.json','["明星時時出現，衆生日日成道。", "如何空王殿前，多是點時不到。"]'),
('758c9fc3-5e8d-4b7f-aff0-cc0ececd8582','食蕁','釋慧空','宋','宋诗','song-poetry','','[]','朔風吹雪排疏櫺，敲冰汲水淘香秔。',128,'全唐诗/poet.song.107000.json','["朔風吹雪排疏櫺，敲冰汲水淘香秔。", "前村老樵餽法供，深壑病夫精勤誠。", "聃聃黄耳擁秀色，不約春氣鍾柴荆。", "隆隆沙鐺漚起滅，點點釜口風雨爭。", "嚴行禁謁戒俗客，約束從事煩庖丁。", "老饕寓意前具辦，宿衲得路豐頤赬。", "中林雪月皎戶牖，一飽對榻雙眸明。", "五侯之家政自醉，我因欲臥聽松聲。"]'),
('f47e1a20-f178-44ba-89b2-9ed982f130e4','送宜川','釋慧空','宋','宋诗','song-poetry','','[]','一氣萬化之所種，眼處不透花重重。',96,'全唐诗/poet.song.107000.json','["一氣萬化之所種，眼處不透花重重。", "達人於中有大觀，得處何止如雞蟲。", "倒爾鼻息作雷吼，佛祖望之猶縮手。", "擡頭三世才曉昏，過眼千差孰妍醜。", "孤雲爲伴鳥助歌，沙鷗起舞魚吹波。", "世間憂樂如我何，病夫聊示見其多。"]'),
('1980aa85-f4ec-4829-aa6b-e7e6bb466f32','送廣州達珠二化士  其一','釋慧空','宋','宋诗','song-poetry','','[]','凡物不達何施爲，惟其達者深所宜。',96,'全唐诗/poet.song.107000.json','["凡物不達何施爲，惟其達者深所宜。", "如珠走槃自圓轉，影跡不滯孤光隨。", "良由水達舟船通，道路達則車書同。", "心境達則機用活，事理達則人法空。", "至於真達不疑處，鼎鼎舌頭無剩語。", "殺人老賊今放憨，喝聲雷送番禺雨。"]'),
('fc8d6797-7ffb-44da-934f-b3ec91988e97','送廣州達珠二化士  其二','釋慧空','宋','宋诗','song-poetry','','[]','二龍爭珠不必求，頂上之珠何足留。',96,'全唐诗/poet.song.107000.json','["二龍爭珠不必求，頂上之珠何足留。", "摩尼之珠不必識，衣裏之珠何足收。", "廣南自有鎮海珠，白月黑月分形模。", "無求無得珠不露，冏冏璧月生珊瑚。", "而今四海呈珠者，俊快不在仰山下。", "若謂縱橫不犯波，爭奈龍王按劍何。"]'),
('9a9a9ff1-be64-43a5-baf7-64de1381aff2','送廣州達珠二化士  其三','釋慧空','宋','宋诗','song-poetry','','[]','鼈鼻毒蛇橫古路，切忌當頭犯渠怒。',96,'全唐诗/poet.song.107000.json','["鼈鼻毒蛇橫古路，切忌當頭犯渠怒。", "犯時性命俱喪亡，不犯依前無避處。", "更有木蛇隨後來，草中毒氣觸還乖。", "山頭老漢遭一螫，至今負痛聲如雷。", "痛聲撼動大庾嶺，直至海南人猛省。", "面前公案甚分明，莫負東山水上行。"]'),
('30312efa-e187-4ae7-a78a-694d5762947f','送廣州達珠二化士  其四','釋慧空','宋','宋诗','song-poetry','','[]','木球轉處橫身去，按住球時須款步。',96,'全唐诗/poet.song.107000.json','["木球轉處橫身去，按住球時須款步。", "定場戲罷急翻身，莫來攔我球門路。", "五州管內人再來，無球可放莫生猜。", "朝來打鼓普請看，未見當年人斫牌。", "廣南人自有佛性，試攜此語辨邪正。", "巖巖象骨摩蒼穹，凜凜四面生清風。"]'),
('73e31ea9-8842-489c-80ca-fcb82e87e268','東山到溫州僊巖覽安楞嚴姚郎中故事安初讀楞嚴經破句悟道後接姚郎中以梅潭水聲悟道東山拈云大小郎中可惜埋向僊巖山中遂說偈仍贈僊巖監寺  其一','釋慧空','宋','宋诗','song-poetry','','[]','一句渾淪忽擊開，銀山鐵壁絕纖埃。',32,'全唐诗/poet.song.107000.json','["一句渾淪忽擊開，銀山鐵壁絕纖埃。", "至今千尺雷霆水，大與姚郎雪屈來。"]'),
('0a6bc37a-d52f-4ba4-b301-909b48cc5e60','東山到溫州僊巖覽安楞嚴姚郎中故事安初讀楞嚴經破句悟道後接姚郎中以梅潭水聲悟道東山拈云大小郎中可惜埋向僊巖山中遂說偈仍贈僊巖監寺  其二','釋慧空','宋','宋诗','song-poetry','','[]','休於言下覓玄微，去卻人間是與非。',32,'全唐诗/poet.song.107000.json','["休於言下覓玄微，去卻人間是與非。", "得意不從頭上過，摩訶衍出祖師機。"]'),
('f0873bb4-f6fa-41be-a4b8-f14294159955','東山到溫州僊巖覽安楞嚴姚郎中故事安初讀楞嚴經破句悟道後接姚郎中以梅潭水聲悟道東山拈云大小郎中可惜埋向僊巖山中遂說偈仍贈僊巖監寺  其三','釋慧空','宋','宋诗','song-poetry','','[]','港口呼舟載月行，月中回首望巖扃。',32,'全唐诗/poet.song.107000.json','["港口呼舟載月行，月中回首望巖扃。", "直憑懸水通消息，莫作中宵風雨聲。"]'),
('12e6a5b3-b01d-45af-b9a2-c1b8a86ccfce','覽天童示寂偈','釋慧空','宋','宋诗','song-poetry','','[]','太白峰前青海尾，一目秋光彌萬里。',32,'全唐诗/poet.song.107000.json','["太白峰前青海尾，一目秋光彌萬里。", "漁翁醉入蘆花深，白鳥不飛天在水。"]'),
('22481bba-b544-41de-951c-fb4d044783be','答普賢夢石紀夢授觀音偈','釋慧空','宋','宋诗','song-poetry','','[]','補陀大土觀世音，位超灌頂佛長子。',384,'全唐诗/poet.song.107000.json','["補陀大土觀世音，位超灌頂佛長子。", "不取正覺不涅槃，大慈悲等衆生界。", "以如幻智入我夢，示身爲石令我取。", "入手光嚴覺即無，無中度我觀音在。", "俄而夢石一信通，授我大士栴檀像。", "空無定居懶惰久，禮敬供養心常疏。", "云何大士與夢石，不付他人惟付我。", "譬如良醫視患衆，各隨其病授其藥。", "空今病處正在懶，是故二彼用同時。", "慈力欲我如觀音，一身普現一切處。", "辯才欲我如夢石，一法圓成一切義。", "懶無根蔕當處平，道有萌芽隨念長。", "仰觀仁意乃我願，敢不再拜而欽承。", "惟願菩薩大慈悲，受我少分之供養。", "戒品爲香萬行花，勇猛爲幢堅固座。", "願雲定水功德山，慧燈智日清涼月。", "所陳妙樂皆法喜，所列珍羞盡禪悅。", "一一遍滿虛空界，念念出我清凈心。", "心無所住供亦然，是則名爲無盡供。", "普願我等諸佛子，見佛盡作如己想。", "而無彼己同異心，乃至夢中亦如是。", "雖恒觀世間如夢，而能廣作諸佛事。", "雖常觀諸法如幻，而能力轉大法輪。", "當知如夢如幻法，非眼境界惟智境。"]'),
('0d6fb443-6fa2-48d2-a48e-f199c6f5a013','世尊真贊','釋慧空','宋','宋诗','song-poetry','','[]','悉達纔生便自尊，無人剪此葛藤根。',64,'全唐诗/poet.song.107000.json','["悉達纔生便自尊，無人剪此葛藤根。", "指天指地虎投檻，說頓說圓羊觸藩。", "室利逼之輕出手，韶陽打殺略知恩。", "東山門戶大無外，留取提鞋及灌園。"]'),
('3826aad2-75ab-42e0-b2c3-bce3bf2adb05','達磨真贊  其一','釋慧空','宋','宋诗','song-poetry','','[]','香至國王之季子，般若多羅之克家。',64,'全唐诗/poet.song.107000.json','["香至國王之季子，般若多羅之克家。", "六宗既正西乾眼，五葉來開東震花。", "根源直截無文字，皮髓分張有等差。", "卻怕老僧行正令，急攜隻履返流沙。"]'),
('193446b2-d027-4da5-9a3d-98c93d5280b7','達磨真贊  其二','釋慧空','宋','宋诗','song-poetry','','[]','一出南天竺，平欺震旦人。',56,'全唐诗/poet.song.107000.json','["一出南天竺，平欺震旦人。", "九年皮髓盡，冷地忽翻身。", "不思折卻當門齒，更向空棺遺隻履。", "而今腳下無幾何，不是當年留下底。"]'),
('0a0b0008-6132-47f0-b492-047f457c7992','二祖真贊','釋慧空','宋','宋诗','song-poetry','','[]','缺齒老胡不敢說，一夜謾天三尺雪。',60,'全唐诗/poet.song.107000.json','["缺齒老胡不敢說，一夜謾天三尺雪。", "神光初只立齊腰，大地到今寒徹骨。", "寒徹骨，金剛扶起泥人佛。", "樵歌漁唱樂昇平，靈芝瑞草年年出。"]'),
('b319b2ec-9381-4c5e-ab16-2b9f7e66db44','觀音真贊  其一','釋慧空','宋','宋诗','song-poetry','','[]','此菩薩，從聞思修入三摩地，於一身現千手眼。',61,'全唐诗/poet.song.107000.json','["此菩薩，從聞思修入三摩地，於一身現千手眼。", "明乎無所不照，無所不明。", "東山老漢，不免隨泥作佛。", "南無觀世音菩薩，南無大慈悲菩薩。"]'),
('eb2f6018-3743-4620-a0db-414211d8118e','觀音真贊  其二','釋慧空','宋','宋诗','song-poetry','','[]','靜處藏身，動中跳出。',40,'全唐诗/poet.song.107000.json','["靜處藏身，動中跳出。", "全起滅心，爲自在力。", "耳聞不知，眼見不識。", "天下人稱，圓通第一。"]'),
('57b8b35a-4da0-4237-a305-68f3cced493f','觀音真贊  其三','釋慧空','宋','宋诗','song-poetry','','[]','此大開士，願力弘深。',60,'全唐诗/poet.song.107000.json','["此大開士，願力弘深。", "初無自相，隨衆生心。", "或以土木，至於縷線。", "但有少緣，悉皆出現。", "終不自言，我自於誰。", "惟令見者，默爾知歸。"]'),
('31a21df2-8a2b-4194-9ead-21e79bd5b610','觀音真贊  其四','釋慧空','宋','宋诗','song-poetry','','[]','一香一華，惟稱惟讚。',20,'全唐诗/poet.song.107000.json','["一香一華，惟稱惟讚。", "潮落海門，風生彼岸。"]'),
('bc72075e-b80d-48b1-b6eb-250e4082ea9e','龐居士真贊','釋慧空','宋','宋诗','song-poetry','','[]','要識龐家箇老翁，東山壁上之圖是。',64,'全唐诗/poet.song.107000.json','["要識龐家箇老翁，東山壁上之圖是。", "手攜長柄竹漉籬，犯寒曉踏南昌市。", "市心躂倒靈照扶，則川斫額丹霞呼。", "襄陽耆舊風標在，留與禪家作殃害。"]'),
('ff7f651c-bcdc-45ad-a751-f5322968ce84','真覺真贊  其一','釋慧空','宋','宋诗','song-poetry','','[]','一千五百人善知識，大坐當軒取意描。',33,'全唐诗/poet.song.107000.json','["一千五百人善知識，大坐當軒取意描。", "眼上安眉猶不薦，面前球之更相饒。"]'),
('29316d9b-d16c-40ce-a8b8-24038733aafa','真覺真贊  其二','釋慧空','宋','宋诗','song-poetry','','[]','德山師之師，巖頭師之友。',141,'全唐诗/poet.song.107000.json','["德山師之師，巖頭師之友。", "有是師，有是友，而負一千五百人善知識之地，而於法道大成也宜矣。", "至若開雪山，則忠懿閩王爲之檀越。", "辦衆事，則興聖國師爲之服勤。", "定其宗，則有雲門偃。", "正其派，則有玄沙備。", "自餘稜展勁孚，鵝湖鏡清流，皆分光四海，若揭日月。", "嗚呼盛哉，瞻之仰之。", "殺人老賊面前，球子井贜捉獲。"]'),
('f549d37e-f0dc-4f8e-ae9d-120faef6bc4c','草堂真贊','釋慧空','宋','宋诗','song-poetry','','[]','此大和尚，叢林先覺。',54,'全唐诗/poet.song.107000.json','["此大和尚，叢林先覺。", "衲僧性命，出其掌握。", "問北指南，愈病勿藥。", "驚起三聖瞎驢，趯倒趙州略彴，噁，四海緇流爭名邈。"]'),
('d7fcdc4e-d5db-457e-a6b2-e722c235ba99','此庵真贊','釋慧空','宋','宋诗','song-poetry','','[]','此據胡牀捉塵拂老和尚，惡手段不可近傍。',105,'全唐诗/poet.song.107000.json','["此據胡牀捉塵拂老和尚，惡手段不可近傍。", "曾將千五百斤鐵枷，頓在山僧項上。", "而今筆下見之，亦自心驚膽喪。", "得人一尺，還人一丈。", "願以此百億佛剎微塵數不可說劫，爲之壽量。", "於其中間荷負楊歧重擔，倒跨三腳驢兒。", "奔走四海之龍象。"]'),
('061fa5eb-5cc9-47d5-b69a-4ec392d3eb23','球堂真贊','釋慧空','宋','宋诗','song-poetry','','[]','四衆之師，萬星之月。',72,'全唐诗/poet.song.107000.json','["四衆之師，萬星之月。", "爲照爲明，如行如說。", "承其光則器器皆圓，得其心則塵塵無物。", "及其瞎卻衲僧眼，倒握麈尾拂。", "則叢林皆謂有老黄龍之體裁，備頭陀之風骨。"]'),
('2acae2c6-c00f-49cf-8d97-c53f9eea7935','夢石真贊','釋慧空','宋','宋诗','song-poetry','','[]','王母夢中，石佛象骨。',199,'全唐诗/poet.song.107000.json','["王母夢中，石佛象骨。", "峰前鼈鼻，僧藍棋布。", "閩山神秀，盡鐘於是。", "提石蛇，與奪出其掌握。", "居德雲，大千乃其遊戲。", "使著書輔教，則聯珠貫璧，不作道原作佇靈。", "使儼臨萬衆，則雷轟電激，不爲德山爲臨濟。", "天其有意於斯文，則無使袖手雲山，友麋鹿而混吾曹於此世。", "同時出家，先我聞道。", "既爲我友，又爲我兄。", "浮雲會散，初無定蹤。", "晚喜其歸，雪山之東。", "長松片石，相對兩翁。", "遽乘六牙香象，雨後峨嵋掃空。", "冰片滿街留不住，使人不能無所慕。"]'),
('4de2fd69-5721-457a-8283-ef2b840dc566','谷堂真贊  其一','釋慧空','宋','宋诗','song-poetry','','[]','冰出水，玉出石，破獍出窠母遭食。',106,'全唐诗/poet.song.107000.json','["冰出水，玉出石，破獍出窠母遭食。", "宗師得法，佛祖避席。", "正令當行，十方辟易。", "耕者驅其牛，饑者奪其食。", "龍驤虎驟，鐵眼銅睛。", "到繩牀角頭，則不寒而慄。", "有此體裁，具此作略，是真臨濟兒孫，黄龍頭角。", "東山與麽讚之，何曾一字讚著。"]'),
('f4204368-7251-48c2-b577-bf2f44e2a49c','谷堂真贊  其二','釋慧空','宋','宋诗','song-poetry','','[]','予常對人言，谷堂老子，人類精奇，緇流標格。',84,'全唐诗/poet.song.107000.json','["予常對人言，谷堂老子，人類精奇，緇流標格。", "若挽置江湖之上，予則謂之溈山道人慕喆。", "若任其乘桴之能，謂之飛山宗一。", "至於江湖不涉，乘桴不居，予將望洋向若而失，又欲引誰爲等匹。"]'),
('e25e4343-1639-4d56-b3ea-db87f322f2ea','真歇真贊','釋慧空','宋','宋诗','song-poetry','','[]','碎丹霞不傳之印，起洞山已墜之宗。',85,'全唐诗/poet.song.107000.json','["碎丹霞不傳之印，起洞山已墜之宗。", "雷聞一世，奔走四方。", "此大唐國內，家至而戶知，不假東山發揚。", "獨自涅槃後大人之相，又屬其賢子孫之承當。", "東山只得炷香再拜，慶師有子，而洞水流長。"]'),
('099c13d2-49a0-4db3-98a9-1b60f26bd10e','楮庵真贊','釋慧空','宋','宋诗','song-poetry','','[]','橫楖栗據此座者，長蘆夫跳竈之子，天衣懷的骨之孫。',86,'全唐诗/poet.song.107000.json','["橫楖栗據此座者，長蘆夫跳竈之子，天衣懷的骨之孫。", "抽一顧而瞎其正眼，用十無而誑彼後昆。", "說法則雷轟電激乎仰山之上，入滅則霜清月落乎連水之湄。", "是謂楮庵和尚，而般陽老明提耳之師也。"]'),
('24ffc188-4864-4326-ba0c-7aece643115a','凈信道人真贊','釋慧空','宋','宋诗','song-poetry','','[]','入凈信心宗，則無俗不真。',63,'全唐诗/poet.song.107000.json','["入凈信心宗，則無俗不真。", "得幻智法門，而有佛皆子。", "視人間爲忉利天宮，坐平蕪乃臺山路上。", "東山晚識此婆，蓋因其子止庵道人，幽巖和尚。"]'),
('4a52e3ee-42c6-4fa7-aa1a-cf5459af97c5','如一悟空二居士真贊','釋慧空','宋','宋诗','song-poetry','','[]','如一一亦不如，悟空空須得悟。',28,'全唐诗/poet.song.107000.json','["如一一亦不如，悟空空須得悟。", "誰家一對鴛鴦，萬象之中獨露。"]'),
('43cc877a-2d99-4f95-85b1-7a004e64b1af','髑髏贊  其一','釋慧空','宋','宋诗','song-poetry','','[]','皮膚脫落盡，骨節有如許。',60,'全唐诗/poet.song.107000.json','["皮膚脫落盡，骨節有如許。", "未即化泥塵，且更相撐拄。", "一味五味禪，千差萬別語。", "問者如紡車，而今較些子。", "較些子，汝等現前齊聽取。"]'),
('1601856e-e59a-4ec1-a770-da3cbd3089bf','髑髏贊  其二','釋慧空','宋','宋诗','song-poetry','','[]','得些皮肉，大家快活。',58,'全唐诗/poet.song.107000.json','["得些皮肉，大家快活。", "沒些皮肉，一場冷落。", "舜若開顔，那吒發惡。", "萬里神光猶較些，一物長靈渾大錯。", "錯不錯，切忌無繩而自縛。"]'),
('31a9ec3c-9203-4e18-a68d-c387ab653f09','髑髏贊  其三','釋慧空','宋','宋诗','song-poetry','','[]','假以四大，抽之一機。',40,'全唐诗/poet.song.107000.json','["假以四大，抽之一機。", "空無作相，動轉云爲。", "有能曉了，成佛無疑。", "何待如是，然後知非。"]'),
('9cd7aead-8b21-4273-beb3-8e350129afec','終南山入定獼猴贊','釋慧空','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','方得其樹，萬壑千巖。',40,'全唐诗/poet.song.107000.json','["方得其樹，萬壑千巖。", "至令休復，屹若終南。", "呼之六窗，寂爾不譍。", "惟彼呼者，乃出其定。"]'),
('3ea57628-fe58-4c6f-a735-427dad71eb79','入風贊','釋慧空','宋','宋诗','song-poetry','','[]','入風無根當處彰，一爲熱惱一清涼。',64,'全唐诗/poet.song.107000.json','["入風無根當處彰，一爲熱惱一清涼。", "乾城影裏金剛眼，傀儡棚頭古佛場。", "與世推移元不動，隨人憂喜竟無妨。", "可中若有纖豪許，物我相持意未忘。"]'),
('6771a88b-c376-4b62-9c4a-edf0b72b732f','醉中食鱠歌','歐陽澈','宋','宋诗','song-poetry','','[]','君不見秋風未發鱸正肥，張翰思歸心欲飛。',318,'全唐诗/poet.song.107000.json','["君不見秋風未發鱸正肥，張翰思歸心欲飛。", "又不見田文有客歌彈鋏，爲歎無魚聲激烈。", "水晶細鱠落金盤，須信江南味中絕。", "山谷曾名醒酒冰，一筯未嘗延俗客。", "助盤橙橘薦甘酸，入口瓊瑶碎牙頰。", "扶起嵇康頽玉山，滌破樂天醉吟魄。", "烹龍炮鳳未云珍，策勲終是愧霜鱗。", "江湖散人興不淺，爲羡此品常埀綸。", "有時舉竿獲錦鯉，玉屑花中拚爛醉。", "笑他大嚼市廛流，浪說屠門能快意。", "靈運池中蓄頗多，揚鬐鼓鬛戲清波。", "知我平生嗜此癖，霜刀細縷紅玉搓。", "典衣沽酒試轟飲，纈紋入面春風和。", "男兒大抵皆忼慨，功名未必常蹉跎。", "醉來擊劍歌白雪，閒愁萬斛俱消磨。", "杯盤雖冷落，風月輸吟哦。", "逸氣射斗牛，無人識太阿。", "俗態翻雲仍覆雨，世情炙手擾張羅。", "丈夫富貴當自致，恥傍權門効女蘿。", "雄圗自許羞俯仰，請看毫端食鱠歌。"]'),
('73a919e4-4dae-4d65-86f8-f6531d106428','七夕後一日寄陳巨濟','歐陽澈','宋','宋诗','song-poetry','','[]','高樓昨夜西風轉，耿耿銀河雲葉卷。',144,'全唐诗/poet.song.107000.json','["高樓昨夜西風轉，耿耿銀河雲葉卷。", "擎空皎月弄嬋娟，領略溪山堪指點。", "秋光次第磨青銅，一味清凉襲庭院。", "遥知天外鵲橋成，織女牛郎會佳燕。", "凭高翻憶鳳樓人，慇懃乞巧陳芳奠。", "可堪目斷心旌揺，砌成幽恨無人展。", "促樽欣得莫逆交，脈脈閒愁憑理遣。", "清狂舉白話平生，午夜香燃殘寶篆。", "凄凉此際憶年時，爛漫瓊樓興不淺。"]'),
('00b6b05c-2203-4d20-a31e-f95eaf48aca3','重遊寥陽洞有感','歐陽澈','宋','宋诗','song-poetry','','[]','尋真曾到寥陽殿，小立廊腰花影轉。',160,'全唐诗/poet.song.107000.json','["尋真曾到寥陽殿，小立廊腰花影轉。", "飛瓊仙子下瑶臺，綽約雲鬟眼波剪。", "水沈烟斷一簾秋，醉睡海棠紅玉軟。", "武陵歸去探年華，揚州一夢烟波遠。", "重來風物恰依然，愛日融融烟素卷。", "洞門寂歷鎖長春，異木槎枒插天半。", "霞衣冉冉媚東風，綠鎖窗前重識面。", "酒酣春笋理琵琶，曲終依約含幽怨。", "人間名利幾時休，馬行不駐空留戀。", "桃花流水古猶今，囘首碧雲人不見。"]'),
('81d149a1-d9c6-4200-8d32-e3505a02627e','和答德秀長句','歐陽澈','宋','宋诗','song-poetry','','[]','摩雲標格儒林秀，濯濯美如春月柳。',160,'全唐诗/poet.song.107000.json','["摩雲標格儒林秀，濯濯美如春月柳。", "毫顛文陣轟雷槌，字勢龍蛇翻夭矯。", "才名藉甚燭景星，卓然可獨尊南斗。", "締交雲路許攀鱗，談我諄諄不離口。", "層樓長記聳詩肩，吟苦任渠嘲太瘦。", "驚人險語骨毛寒，元白危壇俱壓倒。", "讀之真恐化雄虹，按劍徘徊方敢造。", "六丁收拾富巾箱，貪夫探得人間寶。", "暗中輕擲道塗人，相視誰論瓊玖報。", "强搜斐句答慇懃，當恕人才有能否。"]'),
('dfd78c9c-86f4-4457-abdf-e5dde41f151d','古詩寄游良臣兼簡陳國鎮','歐陽澈','宋','宋诗','song-poetry','','[]','虀鹽興淺知無策，謝絕歸來事清白。',240,'全唐诗/poet.song.107000.json','["虀鹽興淺知無策，謝絕歸來事清白。", "亂絲心緒尚紛如，時對風簷獨捫虱。", "會雖稽古補前愆，赤水遺珠不難索。", "仰公學問又日新，磨礱幸偶謫仙人。", "遥知議論到佳處，眉間喜氣常津津。", "我慚蹤跡浪萍梗，欲親棐几嗟因循。", "飛奴寥落絕問幅，渇心依約生埃塵。", "以膠投漆貴耐久，囘光借燭期知貧。", "情均骨肉非有素，白玉琢成心始固。", "莫學紛紛輕薄兒，世情翻覆成雲雨。", "登雲依舊高嵯峨，指掌江山勝概多。", "佳眠風物未入夢，疑泛靈槎游絳河。", "朅來乘興須一往，飛觴爛醉横秋波。", "膺門况有金閨彦，筆驅麗景森吟哦。", "悠悠此志遂何日，款段相期踏雪過。"]'),
('ef76c8b1-9766-46c2-92a9-ee0c0034f35a','良臣會飲於仙莊話次頗聞俗子譏訶次前韵自觧兼呈國鎮','歐陽澈','宋','宋诗','song-poetry','','[]','鴟夷載酒神仙宅，面作纈紋拚卷白。',240,'全唐诗/poet.song.107000.json','["鴟夷載酒神仙宅，面作纈紋拚卷白。", "飲餘指掌話平生，冷笑濡需同豕虱。", "昆山片玉本無瑕，洗垢瘢痕任人索。", "此中空洞貯天真，何止容卿數百人。", "但見婁公容唾面，未應子路不知津。", "會逢博物爲鑒拔，太阿拂拭寧因循。", "男兒强項不易屈，剪剪羞他拜望塵。", "席門車轍多長者，雖不事事非長貧。", "意詳文贍諸儒慕，紛紛誰復師班固。", "膏唇澤舌獵英華，立涸宛如溝澮雨。", "纓冠門下謾峩峩，魯國真儒自不多。", "何時解榻揮金椀，陶然爛醉奚落河。", "清狂浪語文字飲，不須羅襪襯凌波。", "芙蓉仙人酒量闊，况有詩客相吟哦。", "迎賓掃雪尚如何，乘興扁舟須一過。"]'),
('bee6cb3d-a91c-4ee4-a73d-30dedb052e86','遊岐原有感','歐陽澈','宋','宋诗','song-poetry','','[]','秋光淡薄磨青銅，舞風霜葉魚腮紅。',208,'全唐诗/poet.song.107000.json','["秋光淡薄磨青銅，舞風霜葉魚腮紅。", "鷄窗岑寂興不淺，結客搘笻扣梵宫。", "聨翻步躡孤烟際，隴上凄凉一笛風。", "穿雲裂石聲滿谷，驚飛雁陣横晴空。", "高僧擁衲卧雲久，諸方勘破心玲瓏。", "我來奓户據禪榻，堂堂標格對總公。", "旋烹冰液破我悶，澆腸七椀追盧仝。", "水沈烟斷香透頂，津津喜氣生眉峰。", "傅巖真隠已先去，誰與壯浪吟争雄。", "朱絃縱事奏流水，俚耳知音亦罕逢。", "不禁風物撩詩眼，强作險語慙非工。", "安得湯休占此景，碧雲之句當奇鋒。", "會沽村酒行蓮社，忘歸一任夕陽舂。"]'),
('a0b5d57a-1ece-4081-bc91-8e98db4ffec4','送吳教授古詩','歐陽澈','宋','宋诗','song-poetry','','[]','公不見先朝謫仙李太白，晦迹嵩山號詩客。',390,'全唐诗/poet.song.107000.json','["公不見先朝謫仙李太白，晦迹嵩山號詩客。", "奇禽就掌食無猜，藉藉雄名振京國。", "四明狂客素憐才，解龜換酒稱奇特。", "白衣從此步花磚，秀拔儒林人所則。", "煌煌文焰萬丈長，散落人間伴明月。", "又不見昌黎巨儒韓退之，天才穎脫囊中錐。", "反刓剗僞格以正，取心注手了無疑。", "横經太學明師道，質疑辨惑爲蓍龜。", "一言曲盡教育術，業精於勤荒於嬉。", "赫然千載譽愈尊，太山北斗誰敢欺。", "二公才德冠天下，青史褒名卓難亞。", "讀之毎恨世不同，操篲無由漸德化。", "延陵先生當盛時，卓犖英姿獨繼之。", "萬言倚馬亦何待，睥睨謫仙當並馳。", "觝排異端志不拔，真欲礪行參昌黎。", "筆端綺靡追造化，胸中浩氣蟠蛟螭。", "壯年唾手拾高第，錦綉文章喧帝里。", "飄飄意氣凌碧雲，囘視塵蹤如脫屣。", "龍墀承命來臨川，絳帳談經歷數年。", "微言奥義潛啟發，殘膏賸馥多流傳。", "摳衣幸與諸生列，飫聽緒言疑已决。", "自嗟管見如醯雞，若非先生覆難徹。", "惜哉虚往未實歸，洗心方擬叩精微。", "夫何瓜代忽爾至，征航欲解歸王畿。"]'),
('51eb49a2-40b4-46c8-bcf2-3582b136b890','夢仙謠','歐陽澈','宋','宋诗','song-poetry','','[]','寥陽洞口風烟好，枯木槎牙撐雲島。',384,'全唐诗/poet.song.107000.json','["寥陽洞口風烟好，枯木槎牙撐雲島。", "重重金鎖遶嬋娟，滿地落花常不掃。", "蕭郎聞說已乘鸞，空餘九轉燒丹竈。", "烟霞截斷絕非塵，凡夫蹤跡無由到。", "高陽有客携佳侣，訪異尋幽豁襟抱。", "瓊樓飲散恣歡遊，誤入蓬壺如夢覺。", "雲關初叩閒無人，松梢鶴唳如驚報。", "須臾奓户迎者誰，吳宫女兒面凝脂。", "指點蘭堂篆烟裊，珠箔玲瓏窣地埀。", "高擎翠袖輕輕捲，半露妖嬈素蓮臉。", "嫣然一笑啟檀唇，喚我躋堂語聲軟。", "相隨環坐一軒秋，旋列杯盤供雅宴。", "倚風仙蘂似有情，競吐芳苞噴香遠。", "朝雲一段下陽臺，綽約標容塵世鮮。", "黛眉輕拂遠山青，明眸斜盼秋波剪。", "蘭柔柳弱不禁風，睡起芙蓉香體顫。", "櫻桃緩啟歌貫珠，夕陽花外流鶯囀。", "曲終低語愈含情，自訴芳心猶未展。", "苞藏惟恐泄真香，尋常嬌怯羞鶯燕。", "爲憐坐客俱多才，拚羞試許求相見。", "嫣然若有惜花情，願丐錦章鐫琬琰。", "温柔惠性已無雙，更聽斯言真絕艷。", "放懷卷白不暫停，酷嫌鸚鵡杯中淺。", "醉玉頽山卧綺窗，秋水一床凝角簟。"]'),
('2721ff4b-aca7-4823-aaa7-3c9d2bf70e06','朝宗以詩見贈叙從遊之樂廣其意作古詩謝之並簡敦仁德秀','歐陽澈','宋','宋诗','song-poetry','','[]','延陵有偉人，遺我錦繡篇。',288,'全唐诗/poet.song.107000.json','["延陵有偉人，遺我錦繡篇。", "粲粲蕩醉眼，的的爭春妍。", "卷阿細考覈，字字皆青錢。", "知公太瘦生，苦吟希閬仙。", "丹煅復精鍊，落紙人争傳。", "亦常慕坡翁，汗漫如湧泉。", "有時醉風月，健筆揮雲烟。", "冷飲味古昔，詩話珍盈編。", "嗤點寓深旨，讀之心灑然。", "公才本瑰瑋，那復加雕鐫。", "恥與俗吏偶，杜門宗聖賢。", "豈意闒茸輩，辱公倒屣延。", "傾盖頓忘形，披霧呈青天。", "襟懷未易測，醉中頗逃禪。", "間亦不自揣，效顰西子前。", "驊騮超逸足，駑駘烏能先。", "但欲偷格律，引玉時抛磚。", "毎荷不鄙斥，珠璣貽我偏。", "樽酒結詩社，卓犖俱樊川。", "風流王世子，遠拍貞曜肩。", "食虀腸亦苦，志操不少遷。", "季子金閨彦，高吟常醉眠。", "四明有狂客，解龜須見憐。", "偉我三二友，才名足聨翩。"]'),
('471809c9-6436-46c5-89ed-f820bb156c41','讀掲伯徹舊詩軸','歐陽澈','宋','宋诗','song-poetry','','[]','劍氣光芒射斗牛，劍池風物占清幽。',64,'全唐诗/poet.song.107000.json','["劍氣光芒射斗牛，劍池風物占清幽。", "天教間出英雄士，人獨推尊翰墨流。", "幾爲詩魔生太瘦，常因清聖肆狂遊。", "高吟逸軸成何事，可惜昇平漫白頭。"]'),
('07479a57-1dcf-4938-8371-12dea48aaa4b','寄周居安','歐陽澈','宋','宋诗','song-poetry','','[]','周郎辭氣带烟霞，凛凛秋霜嚼齒牙。',64,'全唐诗/poet.song.107000.json','["周郎辭氣带烟霞，凛凛秋霜嚼齒牙。", "麈尾動思談吐屑，筆頭遥想夢生花。", "三年幸獲從遊款，一别那知歲月賒。", "遠辱飛奴傳翰墨，顔筋柳骨儼秋蛇。"]'),
('ed2fba7b-f4f7-4bc8-87c1-b8a43bf06040','秋試下即事有感寄國鎮','歐陽澈','宋','宋诗','song-poetry','','[]','籬角金英噴異香，杜門岑絕獨持觴。',64,'全唐诗/poet.song.107000.json','["籬角金英噴異香，杜門岑絕獨持觴。", "風掀脫葉横斜舞，雲襯平林淺淡黄。", "塞管有情增哽噎，野花無緒伴凄凉。", "不禁景物撩秋眼，剩與新篇付錦囊。"]'),
('a5c3a4f5-c656-485a-bbc1-cbb5ac659d72','戲促朝宗酒約','歐陽澈','宋','宋诗','song-poetry','','[]','雨收雲海湧金盆，簾捲香絲破篆紋。',64,'全唐诗/poet.song.107000.json','["雨收雲海湧金盆，簾捲香絲破篆紋。", "雙陸無心酬白璧，十千有約醉紅裙。", "哦詩誤許聯師服，載酒真當過子雲。", "待遣秋娘呈妙舞，春衫已把水沈薰。"]'),
('39fbbb1a-2dc5-410b-98f1-e5eaeed1648b','朝宗和復次韵答之','歐陽澈','宋','宋诗','song-poetry','','[]','酷愛傾銀注瓦盆，醉眠蘄簟展波紋。',64,'全唐诗/poet.song.107000.json','["酷愛傾銀注瓦盆，醉眠蘄簟展波紋。", "尋春倦躍青驄馬，訪異同拖白練裙。", "謾記鸞牋塵几格，要看象管掃烟雲。", "錦囊拾得詩無數，一炷沈烟透甲薰。"]'),
('baa7746d-ee58-4254-ae7e-ccd1a6203b42','約吳公美裴季驂同赴會次前韵','歐陽澈','宋','宋诗','song-poetry','','[]','伊誰汲井旋埋盆，喜見荷錢點浪紋。',64,'全唐诗/poet.song.107000.json','["伊誰汲井旋埋盆，喜見荷錢點浪紋。", "小立不妨人解佩，閒眠應有客書裙。", "未饒靈運吟春草，端憶長庚醉暮雲。", "顧我從容尚無躁，韓公何惜爲三薰。"]'),
('e8379083-cfea-4f4e-9526-b5244a3653c9','春日書事','歐陽澈','宋','宋诗','song-poetry','','[]','寂寂園林照日遲，花梢經雨漫臙脂。',64,'全唐诗/poet.song.107000.json','["寂寂園林照日遲，花梢經雨漫臙脂。", "輕烟薄縠籠深塢，細草長茵蘸小池。", "暖力著人添醉聖，韶華入眼逼詩脾。", "賞心不惜千金價，冷笑閭閻數米炊。"]'),
('cdaafbe9-e2ed-4170-8cfb-97b4555dffdd','春霽','歐陽澈','宋','宋诗','song-poetry','','[]','繡出園林霽色新，長郊芳草綠無垠。',64,'全唐诗/poet.song.107000.json','["繡出園林霽色新，長郊芳草綠無垠。", "日籠瑞氣輕浮幌，風掠花芬暗襲人。", "蝶慕竊香争趁暖，鶯思求友競啼春。", "試將何物澆詩膽，活火調湯濺玉塵。"]'),
('511a2617-4b2c-4e38-ab7b-655ba7ed8518','臨溪弱柳','歐陽澈','宋','宋诗','song-poetry','','[]','柳弄嬌黄暖律催，臨溪約略笑殘梅。',64,'全唐诗/poet.song.107000.json','["柳弄嬌黄暖律催，臨溪約略笑殘梅。", "鴨頭春水回環綠，龜甲屏山掩映開。", "媚日依依籠霧閣，揺風裊裊拂烟桅。", "柔絲恨不同攀折，獨立江皋首重回。"]'),
('196bc568-4000-4e83-9bfe-49e2e90e4c87','過般若寺納凉','歐陽澈','宋','宋诗','song-poetry','','[]','火雲亭午欲燒空，避暑聨翩過梵宫。',64,'全唐诗/poet.song.107000.json','["火雲亭午欲燒空，避暑聨翩過梵宫。", "磬韵喚回蝴蝶夢，巾紗立破芰荷風。", "竹林道客欲長往，河朔高人興未窮。", "誰似湯休能處病，索詩吟笑慰相逢。"]'),
('1f6de391-32ac-4ef5-9927-680bb47b5c4c','原上晚步聞笛有感','歐陽澈','宋','宋诗','song-poetry','','[]','一笛誰横透晚空，傷懷真作鳥窺籠。',64,'全唐诗/poet.song.107000.json','["一笛誰横透晚空，傷懷真作鳥窺籠。", "解龜換酒無知已，拾穂行歌喜屢豐。", "沐雨秋山遮眼碧，舞風霜葉點溪紅。", "老農植杖來相問，藉草高談夕照中。"]'),
('b72c0412-c29f-4ae7-afd5-ca7b465b7b47','遣興示子賢','歐陽澈','宋','宋诗','song-poetry','','[]','安貧萬事秖隨緣，羞澁囊空乏一錢。',64,'全唐诗/poet.song.107000.json','["安貧萬事秖隨緣，羞澁囊空乏一錢。", "濁酒難賒應有恨，焦琴屢典已無絃。", "飯盂抄雪唯求飽，茗盌翻濤喜自煎。", "錦里先生有詩卷，破愁時誦兩三篇。"]'),
('e3e900f4-213d-4de6-be64-eb1967faa630','傅巖居士挽詞','歐陽澈','宋','宋诗','song-poetry','','[]','夢寐江湖僅十年，桑榆投老遁林泉。',64,'全唐诗/poet.song.107000.json','["夢寐江湖僅十年，桑榆投老遁林泉。", "知人襟抱藏英鑒，奇我風標喚謫仙。", "妙論粲花今已矣，遺編戛玉尚依然。", "桐焦里巷知音少，幾對雲齋欲斷絃。"]'),
('fee4f154-6f2e-43c0-b00c-ae92c846485d','遊盤龍涉傅巖有感簡朝宗','歐陽澈','宋','宋诗','song-poetry','','[]','招提清曠朅來游，潑墨嵐光眼界幽。',64,'全唐诗/poet.song.107000.json','["招提清曠朅來游，潑墨嵐光眼界幽。", "黄絹碑亡思子禮，碧雲詩好憶湯休。", "風簷目送書空雁，烟塢愁聞喚雨鳩。", "銷鑠睡魔澆茗盌，矮窗拾得一簷秋。"]'),
('e14d54d6-5283-435e-9b76-0b53b2c66aa4','陳欽若時寓盤龍作詩寄之因紀吟咏之美','歐陽澈','宋','宋诗','song-poetry','','[]','凜凜冰霜嚼齒牙，沈沈清夜詠簷花。',64,'全唐诗/poet.song.107000.json','["凜凜冰霜嚼齒牙，沈沈清夜詠簷花。", "摩雲氣逸干星斗，落紙詞妍带綺霞。", "醉掃麝煤奔渇驥，困紆象管引秋蛇。", "擬尋紅樹賡詩社，卻日揮戈不許斜。"]'),
('59e0e0f4-f1fe-4399-96e8-be540bc1f4be','良臣聚飲梅仙莊和多字韵','歐陽澈','宋','宋诗','song-poetry','','[]','牛羊茁處綠駢羅，幾載鴟夷得趣多。',64,'全唐诗/poet.song.107000.json','["牛羊茁處綠駢羅，幾載鴟夷得趣多。", "麈尾談清争嚼麝，筆頭草小換籠鵝。", "杯行自鄙紅裙飲，詠罷人傳白雪歌。", "採摘溪山憑句法，倚風拾得只長哦。"]'),
('c088b5d5-6f90-4d1e-9aee-7ba06ae26b86','讀傅巖居士舊詩軸有感','歐陽澈','宋','宋诗','song-poetry','','[]','黄鵠凌雲不可尋，遺音流落感人心。',64,'全唐诗/poet.song.107000.json','["黄鵠凌雲不可尋，遺音流落感人心。", "朱顔綠髩留難駐，明月清風古到今。", "韞櫝有時驚卞璞，絕絃無地置牙琴。", "傅巖蕭瑟傷心處，一局文楸鎖竹林。"]'),
('b0403e1e-8116-4a84-830f-c54a2f4b922c','諸友乘興拉謁吳朝宗因次韵','歐陽澈','宋','宋诗','song-poetry','','[]','扁舟乘興叩寒門，閉户先生不讓孫。',64,'全唐诗/poet.song.107000.json','["扁舟乘興叩寒門，閉户先生不讓孫。", "白雪郢人親到耳，青天廣客迥披雲。", "吟行牛渚裁佳句，坐對雞窗嗜古文。", "淡泊交情俱耐久，幾多瀟洒寄琴樽。"]'),
('9efa5249-76e6-445e-aa43-9ff9b09e7ec3','朝宗見和復次韵謝之','歐陽澈','宋','宋诗','song-poetry','','[]','拾得佳篇李賀門，鸞箋重錄教諸孫。',64,'全唐诗/poet.song.107000.json','["拾得佳篇李賀門，鸞箋重錄教諸孫。", "清于月夕瀟湘水，淡似清秋太華雲。", "發藥例雖霑賸馥，鈎深應寡與玄文。", "何時紅樹尋詩社，琢句令傾瀲灔樽。"]'),
('eef356af-4aa5-4ce8-afa4-219ddbdf6f7e','歸途遣興借朝宗韵簡敦仁','歐陽澈','宋','宋诗','song-poetry','','[]','緩著歸鞭水石鄉，息鞍箕踞小橋傍。',64,'全唐诗/poet.song.107000.json','["緩著歸鞭水石鄉，息鞍箕踞小橋傍。", "烟滋竹葉雙叢玉，秋著蘆花一岸霜。", "潑眼溪山增爽氣，襲人蘭蕙破幽香。", "擬提吟筆扛洪鼎，反笑蚍蜉不自量。"]'),
('10711eed-7111-4675-ba8a-6f1d6d042870','白鵝橋復用前韵','歐陽澈','宋','宋诗','song-poetry','','[]','旗亭解轡詠江鄉，屬玉雙飛綠澗傍。',64,'全唐诗/poet.song.107000.json','["旗亭解轡詠江鄉，屬玉雙飛綠澗傍。", "水墨園林初過雨，青黄橙橘未經霜。", "鼎烹雲液澆腸爽，甕撥春醅破鼻香。", "囘首漫驚烟水遠，向來清味怯思量。"]'),
('c23f2136-f331-4026-87f9-f0034a8602d4','遊華嚴寺題誠齋','歐陽澈','宋','宋诗','song-poetry','','[]','欲逃三伏叩禪關，浄洗煩襟水石間。',64,'全唐诗/poet.song.107000.json','["欲逃三伏叩禪關，浄洗煩襟水石間。", "熾景碧雲俱掩斷，凉飈綠竹頓招還。", "龍涎一炷香清骨，琥珀盈樽笑解顔。", "預約高僧名遂日，結茅來此伴長閒。"]'),
('5b34cce6-64f9-4c2b-9ab8-a23f5d0697fe','和顯道筠軒有作','歐陽澈','宋','宋诗','song-poetry','','[]','欲引秋聲竹旋移，吟烟時一啓柴扉。',64,'全唐诗/poet.song.107000.json','["欲引秋聲竹旋移，吟烟時一啓柴扉。", "了無俗物迷青眼，毎有輕風襲客衣。", "地僻不知炎暑老，身閒潛覺道心微。", "茫茫塵事俱臧穀，羞偶閭閻較是非。"]'),
('b9469ee6-268b-4862-9512-866cf7094bd1','和顯道借韵書懷','歐陽澈','宋','宋诗','song-poetry','','[]','投老歸休六逸溪，杳無闒茸敢敲扉。',64,'全唐诗/poet.song.107000.json','["投老歸休六逸溪，杳無闒茸敢敲扉。", "紅藤舊策扶危杖，白苧新裁養素衣。", "落紙詩才增綺麗，揮犀禪語愈玄微。", "無心深得烟霞趣，冷笑人間萬種非。"]'),
('b4cc7230-0476-4a2a-9f65-986a9d8f5132','借前韵書懷呈顯道','歐陽澈','宋','宋诗','song-poetry','','[]','結茅高隠倦奔馳，寂寂無人叩竹扉。',64,'全唐诗/poet.song.107000.json','["結茅高隠倦奔馳，寂寂無人叩竹扉。", "快意未能榮駟馬，寧親且爾戲斑衣。", "躡雲騰踏終當隠，釣渭栖遲豈久微。", "洗垢索瘢何足卹，鑠金衆口任人非。"]'),
('07e0c741-51d3-4c03-8202-dcfbf33a6ac4','和世弼醉題顯道筠軒','歐陽澈','宋','宋诗','song-poetry','','[]','北窗高隠傲羲皇，旋種琅玕列砌旁。',64,'全唐诗/poet.song.107000.json','["北窗高隠傲羲皇，旋種琅玕列砌旁。", "端許鸞凰同遁戢，不容燕雀亂翺翔。", "侵床綠蔭宜欹枕，拂袂清風快捧觴。", "好是雨餘良夜午，夢囘添得數分凉。"]'),
('54f74c8b-65dd-45a0-a406-f2c346afa5e0','和世弼蓼花','歐陽澈','宋','宋诗','song-poetry','','[]','粧點千叢蘸碧流，寧甘淡竚對清秋。',64,'全唐诗/poet.song.107000.json','["粧點千叢蘸碧流，寧甘淡竚對清秋。", "白蘋許共揺風細，黄菊欣同占景幽。", "羞泄異香招舞蝶，獨施繁艶伴漁舟。", "懵騰醉眼牽情處，贏得凄凉一段愁。"]'),
('d7c1d9a3-7f8a-47c8-ab21-d8d435f76e33','和世弼雞冠花','歐陽澈','宋','宋诗','song-poetry','','[]','芳名從古號雞冠，赭豔天然恰一般。',64,'全唐诗/poet.song.107000.json','["芳名從古號雞冠，赭豔天然恰一般。", "不語宋窗何足賞，難通西谷漫勞看。", "倚風縱有如丹頂，遇敵應無似錦翰。", "空費栽培污庭砌，到頭不若植芝蘭。"]'),
('c382af41-df24-4273-bb77-d84a1ddb5511','宿世弼書館','歐陽澈','宋','宋诗','song-poetry','','[]','暫向雲齋借榻眠，窗風一線晚秋天。',64,'全唐诗/poet.song.107000.json','["暫向雲齋借榻眠，窗風一線晚秋天。", "淋浪樽酒狂摛句，點閃檠燈伴論禪。", "盤角竹聲時淅瀝，簾旌桂影弄嬋娟。", "話窮依約方成夢，驀聽疏鐘到枕前。"]'),
('eef81732-2c6b-4b90-93f6-d3d829f3274a','謝人惠紫竹杖','歐陽澈','宋','宋诗','song-poetry','','[]','王猷珍重惠龍孫，策險扶危價莫論。',64,'全唐诗/poet.song.107000.json','["王猷珍重惠龍孫，策險扶危價莫論。", "爛醉懸錢遊酒域，狂吟步月打僧門。", "虛心尚有凌雲操，勁節元無染涙痕。", "寄語香山居士道，朱藤從此未爲尊。"]'),
('808c3bc7-444e-416c-99f2-f9e0c7eeb2d3','招顯道世弼飲','歐陽澈','宋','宋诗','song-poetry','','[]','桐圭飄剪近重陽，菊綻籬邊葉葉香。',64,'全唐诗/poet.song.107000.json','["桐圭飄剪近重陽，菊綻籬邊葉葉香。", "雲破晴空書雁字，雨餘沙磧列鴛行。", "賞心擬結東山會，卷白交飛北海觴。", "爛醉眼封多勝概，一時收拾入詩囊。"]'),
('ee5c95ac-ec16-403e-aeca-70ffb2e411f9','顯道辭中以詩示教因和韵復之','歐陽澈','宋','宋诗','song-poetry','','[]','抛磚斐句試相招，遠辱高軒過寂寥。',64,'全唐诗/poet.song.107000.json','["抛磚斐句試相招，遠辱高軒過寂寥。", "教約荷公能發瓿，功名蘄我效題橋。", "談霏玉屑驚人聽，歌和陽春滿坐謠。", "投轄苦留留不住，歸時明月掛璇霄。"]'),
('83a7c3a8-427d-4a29-95da-fb74055901fe','重九日醉中與世弼遊華嚴寺','歐陽澈','宋','宋诗','song-poetry','','[]','撥雲來謁野僧家，刮眼秋光望裏賒。',64,'全唐诗/poet.song.107000.json','["撥雲來謁野僧家，刮眼秋光望裏賒。", "檻菊凋零金蕊碎，庭花裊娜玉冠斜。", "遣懷詩筆摛春錦，破悶茶甌捧雪花。", "卻笑遠公延靖節，何須把盞醉流霞。"]'),
('c2117180-f783-41a2-ad4e-8f854d82e16a','和前韵紀登高醉中景示世弼諸友','歐陽澈','宋','宋诗','song-poetry','','[]','芳晨秋興浩無涯，結客凭高酒旋賒。',64,'全唐诗/poet.song.107000.json','["芳晨秋興浩無涯，結客凭高酒旋賒。", "送目喜觀雲縹緲，狂歌誰顧帽欹斜。", "笑他子美看茱實，要學樊川插菊花。", "競說今年幸逢閏，再期携手躡烟霞。"]'),
('1671d858-1c61-4c6c-8bd8-93247a2bd896','世弼再和見贈又次韵復之其詞皆闢其詩中之語  其一','歐陽澈','宋','宋诗','song-poetry','','[]','功業未能光史册，醉吟且爾會朋遊。',64,'全唐诗/poet.song.107000.json','["功業未能光史册，醉吟且爾會朋遊。", "潛心深造詩書府，摘句蘄驚翰墨流。", "莘野耕烟須釋耒，磻溪釣月暫乘舟。", "風雲一旦逢知已，直取三公位黑頭。"]'),
('cedab04e-31fe-44f3-a5f1-c299460f5eb2','世弼再和見贈又次韵復之其詞皆闢其詩中之語  其二','歐陽澈','宋','宋诗','song-poetry','','[]','三尺絲桐追古意，一牀文史伴閒身。',64,'全唐诗/poet.song.107000.json','["三尺絲桐追古意，一牀文史伴閒身。", "寧甘岑寂配前哲，羞逐紛華溷世人。", "遵轄喜投延上客，萊衣時戲奉偏親。", "由來善惡如冰炭，寄迹於今動擇鄰。"]'),
('08c6c9c0-511b-4d0f-9a16-dab4c851dcc2','世弼和酬因繼韵以贈之  其一','歐陽澈','宋','宋诗','song-poetry','','[]','快意不憂原憲病，翛然常作子長遊。',64,'全唐诗/poet.song.107000.json','["快意不憂原憲病，翛然常作子長遊。", "胸中氣焰摩星斗，筆下辭源倒峽流。", "閔子家風惟啜水，龜蒙活計在漁舟。", "杜陵太瘦多詩苦，白雪無情已滿頭。"]'),
('707a0d14-1429-406b-a721-f2219f17bf64','世弼和酬因繼韵以贈之  其二','歐陽澈','宋','宋诗','song-poetry','','[]','擺除塵網縈纒累，占得壺天放曠身。',64,'全唐诗/poet.song.107000.json','["擺除塵網縈纒累，占得壺天放曠身。", "世業文章俱拔萃，家傳清白恥求人。", "鼓琴顔巷貧而樂，褁飯桑門淡以親。", "聞說甑塵雖屢矣，不甘貸粟向諸鄰。"]'),
('48fb0198-5263-44d7-9c51-4e59313f8154','是日天氣乍晴頗快人意因和韵拉世弼謁傅巖  其一','歐陽澈','宋','宋诗','song-poetry','','[]','風剪梧圭欲晚秋，溪光山色稱懽遊。',64,'全唐诗/poet.song.107000.json','["風剪梧圭欲晚秋，溪光山色稱懽遊。", "聨翩雲水宜搜異，俛首閻閭恥溷流。", "相視悉皆謀按劍，無心誰復似虚舟。", "紫芝眉宇人中瑞，一日常思一聚頭。"]'),
('5d5ca8b7-6440-427d-9fcc-66c9dfec5cdc','是日天氣乍晴頗快人意因和韵拉世弼謁傅巖  其二','歐陽澈','宋','宋诗','song-poetry','','[]','袍襟帽角走紅塵，可笑崎嶇一病身。',64,'全唐诗/poet.song.107000.json','["袍襟帽角走紅塵，可笑崎嶇一病身。", "試拉竹溪山裏侣，去尋廬阜社中人。", "鮑昭俊逸雖難敵，夷甫風流幸許親。", "雞黍尚爲千里會，况兹咫尺接墻鄰。"]'),
('9df03aaf-e294-43a6-a1a0-bfbcae007a95','和子賢對景有感次九日韵','歐陽澈','宋','宋诗','song-poetry','','[]','醉撥春雲一罋香，潛欣積雨破秋陽。',64,'全唐诗/poet.song.107000.json','["醉撥春雲一罋香，潛欣積雨破秋陽。", "燈龕宜入詩書府，錢杖慵吟水石鄉。", "忘慮不斑潘岳鬢，養恬難斷廣平腸。", "賞音誰謂無蕭穎，時綴雄文弔戰場。"]'),
('3a7878dd-669c-4a5b-b908-7eb925b1fa06','建中覓菊於希喆因戯作四韵寄云','歐陽澈','宋','宋诗','song-poetry','','[]','丐菊東籬带晚煙，持觴獨放竹溪仙。',64,'全唐诗/poet.song.107000.json','["丐菊東籬带晚煙，持觴獨放竹溪仙。", "擬携賡唱社中侣，來伴沈酣市上眠。", "清叔能詩曾不速，廣文嗜酒恨無錢。", "倘蒙閉户同轟飲，一斛豪頭也百篇。"]'),
('77f541dd-6400-43a2-b982-c900785db366','和韵戲索建中和詩','歐陽澈','宋','宋诗','song-poetry','','[]','功名未遂冠凌煙，琢句投囊學閬仙。',64,'全唐诗/poet.song.107000.json','["功名未遂冠凌煙，琢句投囊學閬仙。", "韞玉要令神物護，探珠豈待老龍眠。", "賓王頗欠新詩債，子美囘償舊酒錢。", "自古逸才多滌器，醉來宜洒奪袍篇。"]'),
('e0b3ab6c-bbcf-4f69-8a8a-8799872c7816','傅巖小酌於草堂因繼前韵紀贈巖叟  其一','歐陽澈','宋','宋诗','song-poetry','','[]','遁戢雲巖古景幽，烟霞常伴赤松遊。',64,'全唐诗/poet.song.107000.json','["遁戢雲巖古景幽，烟霞常伴赤松遊。", "陶陶經醉窮千古，落落談玄貫九流。", "眷愛猥蒙迎倒屣，追尋常欲棹扁舟。", "絲桐古調無人識，毎辱知音爲點頭。"]'),
('147acaba-b49c-41c5-ada2-ec8b4aaad5bd','傅巖小酌於草堂因繼前韵紀贈巖叟  其二','歐陽澈','宋','宋诗','song-poetry','','[]','磊落胸襟造道真，江湖十載自由身。',64,'全唐诗/poet.song.107000.json','["磊落胸襟造道真，江湖十載自由身。", "雖無偉績留當世，恰有清名異衆人。", "甪里先生常願友，香山居士毎求親。", "摳衣顧我雖幾數，賴得詩翁誘善鄰。"]'),
('51d81314-5bd6-405b-8d3f-cae0e39bc5b8','世弼讀白樂天放言詩倣其體依前韵作數首見寄因和答之亦倣樂天之體  其一','歐陽澈','宋','宋诗','song-poetry','','[]','如簧巧語何須聽，似海侯門豈足游。',64,'全唐诗/poet.song.107000.json','["如簧巧語何須聽，似海侯門豈足游。", "太華崇高無棄土，滄浪合并納纖流。", "未要季子榮親印，已買陶朱佚老舟。", "藏器待時須大用，恥争蝸角與蠅頭。"]'),
('10441dea-68b4-4520-bbb3-7422599e5a57','世弼讀白樂天放言詩倣其體依前韵作數首見寄因和答之亦倣樂天之體  其二','歐陽澈','宋','宋诗','song-poetry','','[]','駟馬華軒終得志，簞瓢捽茹且潛身。',64,'全唐诗/poet.song.107000.json','["駟馬華軒終得志，簞瓢捽茹且潛身。", "隋珠莫彈排空雀，和璧休投按劍人。", "畫史解衣須遇鑑，齊門鼔瑟信難親。", "索瘢洗垢從教謗，澡雪襟懷與道鄰。"]'),
('98234012-77ce-43e4-94a2-3defaf11a42c','世弼讀白樂天放言詩倣其體依前韵作數首見寄因和答之亦倣樂天之體  其三','歐陽澈','宋','宋诗','song-poetry','','[]','摶鵬休笑蓬蒿適，燕雀豈知鴻鵠遊。',64,'全唐诗/poet.song.107000.json','["摶鵬休笑蓬蒿適，燕雀豈知鴻鵠遊。", "顔跖賢愚終莫域，渭涇清濁自殊流。", "綆長方可探深井，水淺安能泛大舟。", "獨愛樂天吟著句，輸贏待看局終頭。"]'),
('f2d0cd44-16af-4f5a-9a81-5c486f9df18f','世弼讀白樂天放言詩倣其體依前韵作數首見寄因和答之亦倣樂天之體  其四','歐陽澈','宋','宋诗','song-poetry','','[]','言行樞機宜慎發，利名韁鎖苦縈身。',64,'全唐诗/poet.song.107000.json','["言行樞機宜慎發，利名韁鎖苦縈身。", "無非入市攫金客，誰似臨畦抱罋人。", "鴻雁弟兄猶列序，虎狼父子尚相親。", "刀錐不用争蝸角，請學當時闕黨鄰。"]'),
('0b4b3056-26ac-453c-a88a-50c7aac9afea','世弼原上晚望和韵見寄因復之  其一','歐陽澈','宋','宋诗','song-poetry','','[]','綠消暮靄滿空秋，念遠凭高隴上游。',64,'全唐诗/poet.song.107000.json','["綠消暮靄滿空秋，念遠凭高隴上游。", "一片孤雲生遠岫，數聲斷雁落寒流。", "風前無緒愁聞笛，天際何人誤識舟。", "步月可尋巖下叟，試將圓玉鎖神頭。"]'),
('04fb9f01-d378-41a4-a5c4-14702890e99f','世弼原上晚望和韵見寄因復之  其二','歐陽澈','宋','宋诗','song-poetry','','[]','鳩杖吟行笑撥雲，我疑賈島是前身。',64,'全唐诗/poet.song.107000.json','["鳩杖吟行笑撥雲，我疑賈島是前身。", "名高鄭谷耕烟叟，樂過嚴灘釣月人。", "俯聽鳴蛩争唧唧，潛窺宿鳥各親親。", "田家有秫俱篘酒，乘興何妨遍訪鄰。"]'),
('c5e65fb6-254a-47ad-a51b-718c4baec925','明堂赦降改名者例許入學世弼和前韵賀余次韵答之  其一','歐陽澈','宋','宋诗','song-poetry','','[]','勅書夜到釋幽囚，朝野歡聲例快游。',64,'全唐诗/poet.song.107000.json','["勅書夜到釋幽囚，朝野歡聲例快游。", "藹藹庶官咸被澤，蹌蹌多士悉承流。", "躡雲思獻安邦策，釣月慵尋泛宅舟。", "寄語淮陰休笑我，乘時指日跨龍頭。"]'),
('1c01133a-0d73-40ec-a6f3-34c5038c4deb','明堂赦降改名者例許入學世弼和前韵賀余次韵答之  其二','歐陽澈','宋','宋诗','song-poetry','','[]','太平聖主就如雲，廣霈殊恩及此身。',64,'全唐诗/poet.song.107000.json','["太平聖主就如雲，廣霈殊恩及此身。", "聲類春雷潛起蟄，光同秋月溥臨人。", "網羅遺逸考求助，旌表門閭奬事親。", "猥辱錦章慰岑寂，借冠終不許鄉鄰。"]'),
('5a174f1b-cd20-441d-8813-f213fe6882c1','顯道和前韵見贈因復之  其一','歐陽澈','宋','宋诗','song-poetry','','[]','咳唾珠璣世所優，執鞭願我幸從游。',64,'全唐诗/poet.song.107000.json','["咳唾珠璣世所優，執鞭願我幸從游。", "瓊枝不棄蒹葭倚，鯨海能容溝瀆流。", "月夜狂吟揮象管，花時爛醉泛蘭舟。", "錦囊辱擲新詩格，高壓唐朝李杜頭。"]'),
('10428995-0210-4b69-bb24-fd074009b084','顯道和前韵見贈因復之  其二','歐陽澈','宋','宋诗','song-poetry','','[]','清名藉甚伯夷倫，抗志孤高不辱身。',64,'全唐诗/poet.song.107000.json','["清名藉甚伯夷倫，抗志孤高不辱身。", "縮手懶陳堯殿策，拂衣歸作傅巖人。", "荷公毎許青雲器，蘄我歸榮白髪親。", "努力會須如所祝，庶令雪恥見南鄰。"]'),
('14c9588e-e9a6-420d-b43d-912dd9e85e52','顯道庭中有白雞冠花爛熳作雲容狀賦庭中瑞氣詩以寄余次韵  其一','歐陽澈','宋','宋诗','song-poetry','','[]','雲湧中庭剪異葩，紛紛郁郁疊輕紗。',64,'全唐诗/poet.song.107000.json','["雲湧中庭剪異葩，紛紛郁郁疊輕紗。", "觀光雖屢經群目，薦瑞由來慶一家。", "雨洗晶熒飄玉葉，烟滋淡竚簇瓊花。", "多應綽約東鄰女，來伴仙翁咀絳霞。"]'),
('dacdfc7e-4b62-45e3-9a76-b4f874f70954','顯道庭中有白雞冠花爛熳作雲容狀賦庭中瑞氣詩以寄余次韵  其二','歐陽澈','宋','宋诗','song-poetry','','[]','裊娜雲容獻瑞葩，曉雲輕罩認籠紗。',64,'全唐诗/poet.song.107000.json','["裊娜雲容獻瑞葩，曉雲輕罩認籠紗。", "喜施繁艶迎詩客，羞寄清香入酒家。", "妙質本能兼五德，芳名今復冠群花。", "可憐一種嬋娟態，醉倚秋風臉有霞。"]'),
('a81db454-ec16-4d12-a0a4-7d4b22cca558','夜讀元容良臣登雲閣上舊軸因走筆作詩以寄二公','歐陽澈','宋','宋诗','song-poetry','','[]','登雲閣上二詩仙，不共凭欄僅一年。',64,'全唐诗/poet.song.107000.json','["登雲閣上二詩仙，不共凭欄僅一年。", "耳冷高談增企仰，目驚健筆憶攀緣。", "挼藍環翠應依舊，轉轂流光已屢遷。", "秖憶醉吟風月處，數竿修竹带輕烟。"]'),
('176a3e2e-6067-4e39-9731-844deab8bb63','寄良臣','歐陽澈','宋','宋诗','song-poetry','','[]','耐久交情古所難，松筠高節實能攀。',64,'全唐诗/poet.song.107000.json','["耐久交情古所難，松筠高節實能攀。", "弗思小怨心懷恚，惟嗜狂吟笑解顔。", "讒口任教華似錦，忠言到底臭如蘭。", "飜慙不識奇男子，窺管徒知見一斑。"]'),
('a1a1491e-d676-4250-b541-e4be5a3cad09','顯道世弼過弊廬小酌醉中顯道以詩見教和謝','歐陽澈','宋','宋诗','song-poetry','','[]','鳩杖先生過草萊，竹林結客笑銜杯。',64,'全唐诗/poet.song.107000.json','["鳩杖先生過草萊，竹林結客笑銜杯。", "盤堆冷炙非珍饌，樽貯香醪旋潑醅。", "玉屑揮犀談綺吐，纈紋入面醉顔開。", "自慙闒茸親餘論，健筆時觀吐鳳才。"]'),
('9b1416b9-c19c-4d87-8ff8-4a00e5b95bcf','州學貴中庭上作','歐陽澈','宋','宋诗','song-poetry','','[]','漠漠陰凝水墨天，雨絲成陣拂窗前。',64,'全唐诗/poet.song.107000.json','["漠漠陰凝水墨天，雨絲成陣拂窗前。", "千層疊巘籠輕靄，一带澄江鎖淡烟。", "歸思似雲空散亂，名蹤如繫尚留連。", "當時錯笑悲風賦，今日閒愁頓黯然。"]'),
('377a5565-f57a-4128-84ca-5c6b65c1bda8','寄題章澤民快軒二首  其一','歐陽澈','宋','宋诗','song-poetry','','[]','寓意標名氣象雄，快哉豈爲一襟風。',64,'全唐诗/poet.song.107000.json','["寓意標名氣象雄，快哉豈爲一襟風。", "端期驥子窮經敏，早向蟾庭射策通。", "奔逸佇當躋捷徑，棲遲暫此寄塵蹤。", "過門大嚼徒虚語，未若芝蘭志不同。"]'),
('a4e2c9b8-a5d1-41c3-9881-896262ae6347','寄題章澤民快軒二首  其二','歐陽澈','宋','宋诗','song-poetry','','[]','快矣標名厥趣高，端能教子振風騷。',64,'全唐诗/poet.song.107000.json','["快矣標名厥趣高，端能教子振風騷。", "麈揮捷辯重馮席，筆洒新詩奪宋袍。", "冷笑三投方鑑玉，雄圗一釣便連鰲。", "行行指點青雲步，烜赫英聲冠譽髦。"]'),
('eb378cfc-4ce1-446e-a63e-23fed2977ff8','讀余逢辰舊唱和詩','歐陽澈','宋','宋诗','song-poetry','','[]','哲匠居鄰劍水傍，筆端疑化劍鋒鋩。',64,'全唐诗/poet.song.107000.json','["哲匠居鄰劍水傍，筆端疑化劍鋒鋩。", "雕鐫麗景春工巧，煅煉佳詞武庫張。", "字字泓澄清妬月，篇篇耿介烈含霜。", "樓成白玉歸天府，擲下珠璣滿錦囊。"]'),
('39378b03-09c4-4b7f-86d2-bc489882f0d5','謁希哲不遇軒上走筆','歐陽澈','宋','宋诗','song-poetry','','[]','一軒虚敞静無塵，笑揖遥岑作主人。',64,'全唐诗/poet.song.107000.json','["一軒虚敞静無塵，笑揖遥岑作主人。", "興似子猷來訪戴，情同荀鶴誤尋真。", "重披藥籙聊忘倦，側聽蟬吟試爽神。", "賴得好風知我意，幽香拂掠襲衣巾。"]'),
('1bf30efd-3357-45f0-be4c-8bd3de287873','和希哲軒上韵與友遊華嚴五雲峰','歐陽澈','宋','宋诗','song-poetry','','[]','劍戟峰攢迥絕塵，捫蘿宜謁社中人。',64,'全唐诗/poet.song.107000.json','["劍戟峰攢迥絕塵，捫蘿宜謁社中人。", "雖無樽酒邀元亮，恰有清談敵季真。", "潄玉泉聲清洗耳，靄雲香縷静頤神。", "支公况是忘形侣，不訝林宗折角巾。"]'),
('97156201-e31a-4cbc-8200-35ca589fc191','題良臣登雲閣  其一','歐陽澈','宋','宋诗','song-poetry','','[]','翬飛高閣勢凌雲，端擬雲衢致此身。',64,'全唐诗/poet.song.107000.json','["翬飛高閣勢凌雲，端擬雲衢致此身。", "直躍魯梯千尺峻，高攀蟾窟一枝春。", "廓然眼界同霞域，快矣襟袍絕點塵。", "髣髴麻姑亭上景，方平應約此相親。"]'),
('f5aed2c6-9856-41d3-b8a2-bd52df8b7cb4','題良臣登雲閣  其二','歐陽澈','宋','宋诗','song-poetry','','[]','丹楹崛起拂雲端，平步危梯入廣寒。',64,'全唐诗/poet.song.107000.json','["丹楹崛起拂雲端，平步危梯入廣寒。", "脫屣佇當騰鶴馭，飛鳬終擬附鵬摶。", "半天風雨凭欄詠，萬里江山指掌看。", "十二樓臺多勝概，慚無詩思剪裁難。"]'),
('5c08fabc-4bb9-4337-aea4-b4f6ece1845a','和人題會仙樓','歐陽澈','宋','宋诗','song-poetry','','[]','朱甍飛峻勢凌烟，卷白樓中悉謫仙。',64,'全唐诗/poet.song.107000.json','["朱甍飛峻勢凌烟，卷白樓中悉謫仙。", "枕麯頓能逃外果，潄醪端欲繼前賢。", "雲屏環列蓬壺境，花錦均鋪水墨天。", "滌濯吟魂强裁句，詩成冷笑滿囊錢。"]'),
('c01cf2c4-644d-40b4-accb-6a6b47a7ed98','秋日山居八事  其一','歐陽澈','宋','宋诗','song-poetry','','[]','謝絕紅塵萬種非，杜門卻掃下書幃。',64,'全唐诗/poet.song.107000.json','["謝絕紅塵萬種非，杜門卻掃下書幃。", "聖賢若許同仁傑，子弟從教詆竇威。", "反復始知經旨遠，沈潛愈覺道心微。", "自慚聞見多迂闊，何幸慈親屢斷機。"]'),
('45b75a87-31f8-4c1b-9156-6fed8d6fa123','秋日山居八事  其二','歐陽澈','宋','宋诗','song-poetry','','[]','親灌蔬畦慕漢陰，不辭抱甕汲泉深。',64,'全唐诗/poet.song.107000.json','["親灌蔬畦慕漢陰，不辭抱甕汲泉深。", "擬爲元亮蕭條處，豈有樊遲貨殖心。", "剔去荆榛俱絕蔓，栽培桃李已成林。", "兔葵燕麥元荒寂，剗地繁華直萬金。"]'),
('f573b8b9-c1e5-4b81-9583-2862c7387a1a','秋日山居八事  其三','歐陽澈','宋','宋诗','song-poetry','','[]','霜刀頓洗碧琅玕，半畆清陰透膽寒。',64,'全唐诗/poet.song.107000.json','["霜刀頓洗碧琅玕，半畆清陰透膽寒。", "爲去殘枝藏毒虺，端留密葉隠鳴鸞。", "荒榛雜揉尤宜剔，直節堅剛豈忍殘。", "擬倩蕭郎揮妙筆，一時收拾畫圗看。"]'),
('bc462b48-aac1-46f2-8753-44eb187f6f77','秋日山居八事  其四','歐陽澈','宋','宋诗','song-poetry','','[]','因傳種法自東坡，潛喜春來活者多。',64,'全唐诗/poet.song.107000.json','["因傳種法自東坡，潛喜春來活者多。", "不遣牛羊殘物性，更資雨露養天和。", "虬枝終擬棲仙鶴，雲葉行看施女蘿。", "縱與蒿萊暫同植，大夫封寵竟輸他。"]'),
('2c7fd85e-23ca-4950-891b-b1360e0f48fe','秋日山居八事  其五','歐陽澈','宋','宋诗','song-poetry','','[]','振衣拂曉啟松扃，月淡風輕酒頓醒。',64,'全唐诗/poet.song.107000.json','["振衣拂曉啟松扃，月淡風輕酒頓醒。", "密竹含烟争滴翠，幽蘭浥露遠聞馨。", "清憐高潔蟬嘶柳，閒羡優游鹿食苹。", "試枕碧流端洗耳，白雲深處誦黄庭。"]'),
('137eb4e0-ad9c-4e92-ab05-13f7b685eb44','秋日山居八事  其六','歐陽澈','宋','宋诗','song-poetry','','[]','一抹輕烟鎖遠山，眼封瀟洒脫塵寰。',64,'全唐诗/poet.song.107000.json','["一抹輕烟鎖遠山，眼封瀟洒脫塵寰。", "投林宿鳥相呼喚，出草飛螢自往還。", "吟擬停杯邀月飲，醉蘄支枕伴雲閒。", "因風拾得新詩句，獨倚高梧笑解顔。"]'),
('e2f3bb4a-1e20-43cf-b533-e518892dae32','秋日山居八事  其七','歐陽澈','宋','宋诗','song-poetry','','[]','洒落風軒枕簟凉，高眠亭午夢何長。',64,'全唐诗/poet.song.107000.json','["洒落風軒枕簟凉，高眠亭午夢何長。", "轉爲蝴蝶徒虚語，游遍華胥秖妄狂。", "喚覺始驚俱幻化，勞生頓悟謾乾忙。", "搔頭斜倚屏山久，熟較無如醉玉漿。"]'),
('3f31266d-cd51-4e69-aea9-7a1daa7ca6af','秋日山居八事  其八','歐陽澈','宋','宋诗','song-poetry','','[]','景鋪萬籟絕紛華，獨泛瑶觴襯臉霞。',64,'全唐诗/poet.song.107000.json','["景鋪萬籟絕紛華，獨泛瑶觴襯臉霞。", "飲罷仰天歌白雪，醉來啟匣拂青蛇。", "伴邀佳客推明月，樂奏清聲有亂蛙。", "欲學廣文事高節，恨無細雨落簷花。"]'),
('e4f2a72b-8056-4610-8ef0-406a43ccc7d4','和友人榴花','歐陽澈','宋','宋诗','song-poetry','','[]','薰風吹綻絳香囊，碧玉叢中巧剪裝。',64,'全唐诗/poet.song.107000.json','["薰風吹綻絳香囊，碧玉叢中巧剪裝。", "剛對炎曦争灼爍，羞同凡卉競芬芳。", "動人來把驪珠吐，照眼潛將蜀錦張。", "詩思爲伊牽引煞，暗隨蝴蝶夢池塘。"]'),
('e9f55a7e-8e08-46ab-b6d7-0e14f408e537','寄良臣','歐陽澈','宋','宋诗','song-poetry','','[]','耳冷清談倐半年，渇心如憶嶺頭泉。',64,'全唐诗/poet.song.107000.json','["耳冷清談倐半年，渇心如憶嶺頭泉。", "自慚託跡多南北，無復從游學聖賢。", "莫謂卑飛同斥鷃，已全高潔慕鳴蟬。", "荒凉不厭幽居趣，假道何妨試著鞭。"]'),
('6a0eb945-f132-433c-b9dc-d2cb8bb3918d','子賢同游岐原','歐陽澈','宋','宋诗','song-poetry','','[]','投閒結客叩禪扃，拾得林間一種清。',64,'全唐诗/poet.song.107000.json','["投閒結客叩禪扃，拾得林間一種清。", "倚杖細聽黄鳥語，捲簾遥指碧雲生。", "清風麈尾驅塵態，春露甌心破宿酲。", "便擬躬耕傅巖下，飜慙沒世未留名。"]'),
('0e4c6d73-0e99-45ec-a888-57a9af6752ac','和友人春日山中即事  其一','歐陽澈','宋','宋诗','song-poetry','','[]','斂翅歸來口欲緘，結茅遁戢寄雲巖。',64,'全唐诗/poet.song.107000.json','["斂翅歸來口欲緘，結茅遁戢寄雲巖。", "𨊵輈聒耳思抛彈，薜荔縈牆未肯芟。", "閒笑蜜蜂空採撲，静聽雛燕語呢喃。", "翛然頓釋人間累，設穽維防餓虎饞。"]'),
('73a3a178-be38-41b0-b1c8-4223d93cb21f','和友人春日山中即事  其二','歐陽澈','宋','宋诗','song-poetry','','[]','杜門卻掃絕機緘，砥節端如萬仞巖。',64,'全唐诗/poet.song.107000.json','["杜門卻掃絕機緘，砥節端如萬仞巖。", "澗底無鼇休擲釣，路傍有草倩誰芟。", "披襟嫩竹敲風細，支枕幽禽鬬語喃。", "底事曉來無挾彈，爲嫌屋上集烏饞。"]'),
('c5739678-e462-4c82-ad5f-420445f59b48','和友人同游普安','歐陽澈','宋','宋诗','song-poetry','','[]','碧雲章句慕湯休，結客來尋物外游。',64,'全唐诗/poet.song.107000.json','["碧雲章句慕湯休，結客來尋物外游。", "茗椀翠濤能破悶，棊枰飛雹共忘憂。", "須泉况味參師正，愛竹襟懷亞子猷。", "好事不須沽酒引，一溪風物自相留。"]'),
('e79e0a09-1616-40cd-9454-1a2a040a527b','拉友人遊普安追和前韵','歐陽澈','宋','宋诗','song-poetry','','[]','炙手權門似可羞，聨翩宜作赤松游。',64,'全唐诗/poet.song.107000.json','["炙手權門似可羞，聨翩宜作赤松游。", "花逢消恨本無恨，草對忘憂自不憂。", "拂榻禪窗蠲俗慮，揮犀虚室論嘉猷。", "支郎况頗能詩話，滌濯吟魂爲少留。"]'),
('3502e6a3-3622-4778-9520-ba1b06f6ec91','督德秀還酒會','歐陽澈','宋','宋诗','song-poetry','','[]','綠鎖窗前聚首時，戲彈圓玉偶輸機。',64,'全唐诗/poet.song.107000.json','["綠鎖窗前聚首時，戲彈圓玉偶輸機。", "侑觴既欲携紅袖，送酒何妨遣白衣。", "酩酊預期歸倒載，從容端約話玄微。", "揮戈直使頽陽卻，不計西風隠半歸。"]'),
('c7fbf256-8058-4502-ba00-ce82ce929dd6','德秀和詩意似有激而云因次韵復之','歐陽澈','宋','宋诗','song-poetry','','[]','困踣紅塵未偶時，醉吟風月且忘機。',64,'全唐诗/poet.song.107000.json','["困踣紅塵未偶時，醉吟風月且忘機。", "囊空不羡千金璧，道在何慙百結衣。", "洗垢任他騰口謗，養恬尤覺道心微。", "孫陽一顧鹽車驥，超逸方驚動中規。"]'),
('d81559c1-ce13-4e53-8b67-eb7cca4f49e0','朝宗雨中醉歸爲娼女竊笑戯作兩絕因繼其韵  其一','歐陽澈','宋','宋诗','song-poetry','','[]','雨裛輕塵步武遲，墊巾歸自武陵溪。',32,'全唐诗/poet.song.107000.json','["雨裛輕塵步武遲，墊巾歸自武陵溪。", "紛紛誰認神仙過，拊掌瓊樓笑女兒。"]'),
('2569b1cc-d076-40af-9ff3-7befdb9d0ff9','朝宗雨中醉歸爲娼女竊笑戯作兩絕因繼其韵  其二','歐陽澈','宋','宋诗','song-poetry','','[]','襟袂龍鍾破雨歸，玉人驚笑若耶溪。',32,'全唐诗/poet.song.107000.json','["襟袂龍鍾破雨歸，玉人驚笑若耶溪。", "恨無款段馳春徑，故故遺鞭盼阿兒。"]'),
('cf65f14e-8880-4950-8dea-8a02925b30ac','臨川戯留友人','歐陽澈','宋','宋诗','song-poetry','','[]','山童澤涸欲金流，小雨廉纖陡變秋。',64,'全唐诗/poet.song.107000.json','["山童澤涸欲金流，小雨廉纖陡變秋。", "河朔飲徒方快意，鱸魚歸興不如休。", "歌姝况有飛瓊侣，結客當爲擲果游。", "一曲陽關腸斷盡，未應聞此不遲留。"]'),
('fa644846-7e14-45d5-af30-c21b544d5157','小生日因與友人作文字飲醉中走筆  其一','歐陽澈','宋','宋诗','song-poetry','','[]','骯髒無聊獨倚門，誰憐跨下有王孫。',64,'全唐诗/poet.song.107000.json','["骯髒無聊獨倚門，誰憐跨下有王孫。", "揚鑣特辱過黄憲，載酒端來醉子雲。", "寫景錦囊同摘句，揺風玉麈細論文。", "共欣賤子當生日，戲祝遐齡倒一樽。"]'),
('093e9f95-e686-4a92-879c-e2b0e3278d71','小生日因與友人作文字飲醉中走筆  其二','歐陽澈','宋','宋诗','song-poetry','','[]','二妙高軒肯過門，共期獻策學公孫。',64,'全唐诗/poet.song.107000.json','["二妙高軒肯過門，共期獻策學公孫。", "因觀佳句題紅葉，陡起歸心望白雲。", "坐上揮犀驚險語，醉中染翰綴雄文。", "相忘豈假投遵轄，待月同傾北海樽。"]'),
('1f5d6994-73cd-4940-92e8-d52d5844b0b5','夜過謝池小酌戯繼前韵示諸友','歐陽澈','宋','宋诗','song-poetry','','[]','爲憶蓮娃夜叩門，恐緣芳草怨王孫。',64,'全唐诗/poet.song.107000.json','["爲憶蓮娃夜叩門，恐緣芳草怨王孫。", "眉彎海嶠初生月，鬢軃巫峰欲墜雲。", "金粟花殘將委燼，香絲篆破不成文。", "朦朧月映人如玉，爾汝忘形共一樽。"]'),
('fa6de4f5-ee2b-432b-8b51-32769194f78f','德秀和韵見酬因復之','歐陽澈','宋','宋诗','song-poetry','','[]','高才卓犖冠儒門，知是延陵幾世孫。',64,'全唐诗/poet.song.107000.json','["高才卓犖冠儒門，知是延陵幾世孫。", "白雪歌詩凌鮑謝，青錢事業壓機雲。", "雄圖未遂羞投筆，賦分甘貧恥賣文。", "已結忘形韓孟友，醉吟常願共開樽。"]'),
('a1db1d70-4f0f-43f4-8100-bf05f1dc4a9d','繼前韵督敦仁和詩','歐陽澈','宋','宋诗','song-poetry','','[]','摳衣幸毎躡膺門，了了慙非孔氏孫。',64,'全唐诗/poet.song.107000.json','["摳衣幸毎躡膺門，了了慙非孔氏孫。", "麈尾既容聞吐屑，毫端合許見摛雲。", "羲皇况已傲彭澤，屈宋安能過廣文。", "白璧一雙如見擲，解貂准擬換融樽。"]'),
('e84ed074-a97d-48aa-8f92-fd3e01c0076a','朝宗久不以詩見教因次前韵索其光和','歐陽澈','宋','宋诗','song-poetry','','[]','慵于蹲踏謁權門，獨洒新詩示從孫。',64,'全唐诗/poet.song.107000.json','["慵于蹲踏謁權門，獨洒新詩示從孫。", "之問已嘗吟奪錦，相如宜共賦凌雲。", "高懷素藴知人鑑，斐句慙非弔古文。", "抵鵲果蒙投卞玉，珍藏何啻獲犧樽。"]'),
('ee2a9636-3959-439a-910c-e62d8a30cd46','八月十四夜建中二三友過我清話因共把盞賞月從容談笑不覺雲容朦朧桂影淡泊端知是夕聚首騷池再諧佳會遂成四韵','歐陽澈','宋','宋诗','song-poetry','','[]','冰輪初訝一分虧，結客傳觴笑語遲。',64,'全唐诗/poet.song.107000.json','["冰輪初訝一分虧，結客傳觴笑語遲。", "雲漢無端藏兔影，金波恨不蘸蟾枝。", "佐樽痛憶飛瓊侣，染翰栽成感鬼詩。", "料得中秋月應朗，習池端約捧瓊巵。"]'),
('1744161a-5993-4238-9b8e-21a92a1dfe53','軒前菊蕊將綻因書四韵示希喆約九日聚飲於此','歐陽澈','宋','宋诗','song-poetry','','[]','菊英裝點近芳辰，風掠清香已襲人。',64,'全唐诗/poet.song.107000.json','["菊英裝點近芳辰，風掠清香已襲人。", "端的樊川携玉液，來同靖節賞金塵。", "藏鬮戲賭杯中物，投轄堅留座上賓。", "惡客不容污我社，摛雲要掃筆鋒神。"]'),
('934ab70e-0296-4322-bbf0-95079697a8d2','述懷寄仲寶','歐陽澈','宋','宋诗','song-poetry','','[]','雞窗俛默謝塵囂，炙手權門懶折腰。',64,'全唐诗/poet.song.107000.json','["雞窗俛默謝塵囂，炙手權門懶折腰。", "節操剛持忠孝礪，胸襟常以古今澆。", "蕭條陋巷閒三徑，牢落生涯寄一瓢。", "何日高軒能我過，竹林清集共逍遥。"]'),
('13961473-1e60-41ca-8dfe-d46a5114459b','過巴川','歐陽澈','宋','宋诗','song-poetry','','[]','凭高因賦遏雲篇，曵屣狂歌放昔賢。',64,'全唐诗/poet.song.107000.json','["凭高因賦遏雲篇，曵屣狂歌放昔賢。", "未遂相如榮駟馬，且尋師正傲清泉。", "悲吟玉未經三獻，羞澁囊空乏一錢。", "典卻春衣常獨酌，從教邸主笑鳶肩。"]'),
('4d57d09c-0168-495f-a596-0df75105dc0a','和子賢借韵書懷','歐陽澈','宋','宋诗','song-poetry','','[]','白雪歌詩數百篇，賡酬樂有父兄賢。',64,'全唐诗/poet.song.107000.json','["白雪歌詩數百篇，賡酬樂有父兄賢。", "要晞靖節栽門柳，須俟參寥夢石泉。", "咳唾幸存三寸舌，文章可媿一囊錢。", "會須重咏高軒過，嘔出蘄攀李賀肩。"]'),
('5d6f13d4-d29a-4265-89ac-1207d3341679','和前韵勉子賢學詩','歐陽澈','宋','宋诗','song-poetry','','[]','雕鐫風月摘佳篇，落筆尤宜法古賢。',64,'全唐诗/poet.song.107000.json','["雕鐫風月摘佳篇，落筆尤宜法古賢。", "淬礪要如礲寶劍，清新蘄似冽寒泉。", "會同白句吟披錦，冷笑邕文賣得錢。", "詩社獲公添一瑞，苦思須拍閬仙肩。"]'),
('fd878c40-aa3b-46e6-8cd2-ae7c23a178b3','子賢和韵見酬次答之','歐陽澈','宋','宋诗','song-poetry','','[]','詩名浪得在盧前，器識慙非叔度賢。',64,'全唐诗/poet.song.107000.json','["詩名浪得在盧前，器識慙非叔度賢。", "捉月笑他吟采石，凌雲端欲賦甘泉。", "發硎喜淬衝牛劍，啟齒羞談使鬼錢。", "平世未應徒爾耳，行藏終與古人肩。"]'),
('8f467f79-41a3-4329-aeba-9be94fb3c750','是日郊亭和晏尚書韵','歐陽澈','宋','宋诗','song-poetry','','[]','關關啼鳥樹交陰，雨過西城野色侵。',64,'全唐诗/poet.song.107000.json','["關關啼鳥樹交陰，雨過西城野色侵。", "避暑誰能陪劇飲，清歌自可滌煩襟。", "稻花欲秀蟬初嘒，菱蔓初長水正深。", "知有江湖杳然意，扁舟應與共追尋。"]'),
('c0eb2603-b7f3-4650-a8b6-d24f6dc7de79','和子賢秋日晚望','歐陽澈','宋','宋诗','song-poetry','','[]','溪山潑墨水雲秋，似綺餘霞次第收。',64,'全唐诗/poet.song.107000.json','["溪山潑墨水雲秋，似綺餘霞次第收。", "燦燦拒霜鋪蓼岸，雙雙屬玉舞蘋洲。", "杳無錦字來憑雁，擬滅機心試狎鷗。", "望裏碧雲還又合，數峰江上忍擡眸。"]'),
('6e39441d-4df5-448b-b451-999ce40af185','朝宗以詩贈行和酬二篇一以留别一以謝詩  其一','歐陽澈','宋','宋诗','song-poetry','','[]','潄醪常共醉淋浪，魚目慙游漲海傍。',64,'全唐诗/poet.song.107000.json','["潄醪常共醉淋浪，魚目慙游漲海傍。", "琴聽雅音彈碧玉，鼎分靈劑煉玄霜。", "纒腸錦綉篇章麗，入室芝蘭燕寢香。", "此别未應徒爾耳，鵬程萬里事難量。"]'),
('f4c25e0a-cd2b-493d-bd12-69c068bdc18f','朝宗以詩贈行和酬二篇一以留别一以謝詩  其二','歐陽澈','宋','宋诗','song-poetry','','[]','鍛鍊新詩摘錦囊，筆驅秀麗汝川傍。',64,'全唐诗/poet.song.107000.json','["鍛鍊新詩摘錦囊，筆驅秀麗汝川傍。", "氣横阿劍疑干斗，韵逸豐鐘必待霜。", "遒勁狂揮毛頴疾，淋漓醉掃麝煤香。", "珠璣喜就鮫人乞，收拾端期百斛量。"]'),
('cc231292-c9d0-475b-95ca-28b6d05d3642','憶朝宗','歐陽澈','宋','宋诗','song-poetry','','[]','飫聆舌鐸向雞窗，深媿葭蒹倚玉傍。',64,'全唐诗/poet.song.107000.json','["飫聆舌鐸向雞窗，深媿葭蒹倚玉傍。", "妙論乍離人吐屑，渇心欣破橘含霜。", "頗多好景撩人笑，獨賞幽叢撲面香。", "數筆江山吟未得，何時對榻細商量。"]'),
('55fbd3e8-64da-4878-8ee5-74e6eb8ae6e9','寄敦仁','歐陽澈','宋','宋诗','song-poetry','','[]','高才松桂振芬芳，桃李根莖媿托傍。',64,'全唐诗/poet.song.107000.json','["高才松桂振芬芳，桃李根莖媿托傍。", "眩目文章舒麗錦，超群節操抗嚴霜。", "快聾未卜聞談綺，補劓期攀靄德香。", "時遣長鬚致雙鯉，新詩無惜屢思量。"]'),
('12dd43c1-2f63-4ae5-bb55-37ed6c5fcfef','建中索子賢酒債戲作一絕','歐陽澈','宋','宋诗','song-poetry','','[]','阿堵物無崔烈臭，孔方兄有少陵羞。',32,'全唐诗/poet.song.107000.json','["阿堵物無崔烈臭，孔方兄有少陵羞。", "一斗酒金償未得，速來相就典貂裘。"]'),
('2dad632b-850e-4d12-a7b5-82536240b928','瓊上人留意學詩惑於多岐未明厥趣作四韵寤之了此一話則能詩三昩不出箇中矣','歐陽澈','宋','宋诗','song-poetry','','[]','襟懷磊落富詩情，琢句端明法頌聲。',64,'全唐诗/poet.song.107000.json','["襟懷磊落富詩情，琢句端明法頌聲。", "格健要除蔬笋氣，語工須带雪霜清。", "碧雲矜式存風雅，黄卷沈潛學老成。", "鍛鍊更能師島可，禪林無患不知名。"]'),
('ac49d45b-be60-454f-b496-a29399395e03','秋香','歐陽澈','宋','宋诗','song-poetry','','[]','拂掠輕風破異香，非蘭非麝味何長。',64,'全唐诗/poet.song.107000.json','["拂掠輕風破異香，非蘭非麝味何長。", "荻篩玉屑飛魚舍，菊碎金塵點醉鄉。", "露裛木犀增馥郁，煙滋菡萏益芬芳。", "佳人惹得盈襟袖，剗地慵拈錦綉囊。"]'),
('dc18f4bb-076d-485c-8cf4-9c1463cbd0da','秋雲','歐陽澈','宋','宋诗','song-poetry','','[]','數片悠揚出遠山，擬爲霖雨霈塵寰。',64,'全唐诗/poet.song.107000.json','["數片悠揚出遠山，擬爲霖雨霈塵寰。", "未乘風雨吹嘘便，驀被曦輪照爍還。", "心在蒼生常欲起，蹤歸深岫暫投閒。", "油然一作施膏澤，始趁嵐烟入帝關。"]'),
('8153de22-aa79-45e5-a223-7b00ea00ef09','秋竹','歐陽澈','宋','宋诗','song-poetry','','[]','森然庭列碧琅玕，瀟洒清陰透膽寒。',64,'全唐诗/poet.song.107000.json','["森然庭列碧琅玕，瀟洒清陰透膽寒。", "落落已成棲鳳實，團團俱是化龍竿。", "夜深篩月疑金碎，曉色籠烟認戟攢。", "勁節剛持君子操，王猷休把等閒看。"]'),
('03c8f56c-aa2d-424e-8939-c074a3c50782','待月','歐陽澈','宋','宋诗','song-poetry','','[]','停杯邀月宴華堂，苦恨山高阻興狂。',64,'全唐诗/poet.song.107000.json','["停杯邀月宴華堂，苦恨山高阻興狂。", "海嶠豈能藏素魄，雲衢終自布寒光。", "須臾簾捲銀蟾影，次第樽浮桂子香。", "正好吹簫恰無月，姮娥應見我恓惶。"]'),
('2b577042-4bbe-4850-9410-d0319469448e','秋月','歐陽澈','宋','宋诗','song-poetry','','[]','碾破鱗雲皓月輪，銀蟾著意露精神。',64,'全唐诗/poet.song.107000.json','["碾破鱗雲皓月輪，銀蟾著意露精神。", "十分素魄高低印，一様寒光遠近均。", "觸目冰壺無點翳，照人水鑑絕纖塵。", "擬携玉斧乘風御，折桂歸榮白髪親。"]'),
('9ff9616d-ebc9-4671-9735-fdda5ad3a916','金鳳花','歐陽澈','宋','宋诗','song-poetry','','[]','巧剪金英似欲飛，恍疑平世鳳來儀。',32,'全唐诗/poet.song.107000.json','["巧剪金英似欲飛，恍疑平世鳳來儀。", "嘉名獨冠群花首，底亊君王尚未知。"]'),
('3f863a68-96e7-41cd-9921-dc8f0a80aed1','秋愁','歐陽澈','宋','宋诗','song-poetry','','[]','層樓夜午轉西風，眉際新愁剗地濃。',32,'全唐诗/poet.song.107000.json','["層樓夜午轉西風，眉際新愁剗地濃。", "怪得當時潘與宋，凄凉尤怯此時逢。"]'),
