('51544034-feb6-4f2f-a65d-fac061f1f928','游春八詠 輕風破暖','歐陽澈','宋','宋诗','song-poetry','','[]','單衣初試輕寒退，嫋嫋軟風經袖袂。',64,'全唐诗/poet.song.107000.json','["單衣初試輕寒退，嫋嫋軟風經袖袂。", "層樓高捲酒旗斜，綺陌亂飄花錦碎。", "多情故把惱人腸，楊柳陰中弄暗香。", "解貂不惜換斗酒，爛醉春光能幾場。"]'),
('9a5fb746-ceb0-4d74-b35e-8fb0cb3f8ec7','游春八詠 宿雨新晴','歐陽澈','宋','宋诗','song-poetry','','[]','濛濛春鎖弄晴雨，花褪殘紅烟淡竚。',64,'全唐诗/poet.song.107000.json','["濛濛春鎖弄晴雨，花褪殘紅烟淡竚。", "潑成濃黛遠山青，秀色輕茸芳草布。", "園林依約清且新，滑唇好鳥相和鳴。", "輕寒不斷微風作，幽花一笑游人醒。"]'),
('37237806-b8c1-406d-a909-1ea5d8eb6097','游春八詠 嬌鶯喚友','歐陽澈','宋','宋诗','song-poetry','','[]','輕烟漠漠籠芳樹，上有黄鸝調巧語。',64,'全唐诗/poet.song.107000.json','["輕烟漠漠籠芳樹，上有黄鸝調巧語。", "分明喚友度柔情，似對東風欲掀舞。", "嗟哉彼鳥非英靈，猶能求友鳴嚶嚶。", "光初隙末輕薄子，洗耳何妨聽此聲。"]'),
('31efd4c6-38c0-4d6d-83da-77d55b748635','游春八詠 杜宇啼紅','歐陽澈','宋','宋诗','song-poetry','','[]','蜜脾香滿青春暮，寂寂空山聞杜宇。',64,'全唐诗/poet.song.107000.json','["蜜脾香滿青春暮，寂寂空山聞杜宇。", "啼紅泣綠怨東風，錦城舊恨懷千古。", "可堪腸斷對樽前，雄圗未遂愁無邊。", "賴有投壺勸我飲，起舞從教落醉船。"]'),
('dc6022ab-1545-40a5-bd13-60b7046d2b8b','游春八詠 狂吟紅樹','歐陽澈','宋','宋诗','song-poetry','','[]','生涯隨分便蕭散，鬬草摴蒲心緒懶。',64,'全唐诗/poet.song.107000.json','["生涯隨分便蕭散，鬬草摴蒲心緒懶。", "尚餘詩僻窮愈工，醉吟跌宕揮金盌。", "愛携佳客懶尋春，殘紅枝下細論文。", "搜羅萬象攢胸臆，筆端掃出春空雲。"]'),
('b04fb05e-69cd-43f7-a43e-13e8ec911020','游春八詠 醉眠芳草','歐陽澈','宋','宋诗','song-poetry','','[]','澆愁沃恨唯憑酒，况值郊原湔錦綉。',64,'全唐诗/poet.song.107000.json','["澆愁沃恨唯憑酒，况值郊原湔錦綉。", "傾囊結客踏青游，競把鴟夷載醇酎。", "爲憐芳草襯殘紅，猛拚醉玉眠春晝。", "覺來游眼頓增明，晚烟約略横疏柳。"]'),
('b8039f02-8d3c-4e4f-9ceb-4727eb68b748','游春八詠 捫松長嘯','歐陽澈','宋','宋诗','song-poetry','','[]','亭亭千尺凌雲表，鐡甲蒼髯材獨妙。',64,'全唐诗/poet.song.107000.json','["亭亭千尺凌雲表，鐡甲蒼髯材獨妙。", "班斤郢斵猶未逢，霧慘烟凄人不要。", "我來感激對殘霞，獨倚虯枝發長嘯。", "試憑匠石親品題，棟梁合自登廊廟。"]'),
('117487c6-7348-42ab-82fb-5c944171d9cb','游春八詠 步日晚歸','歐陽澈','宋','宋诗','song-poetry','','[]','風煙觸處歡無限，倒著接䍦歸去晚。',64,'全唐诗/poet.song.107000.json','["風煙觸處歡無限，倒著接䍦歸去晚。", "林梢璧月弄清輝，鬬插山花笑而莞。", "華堂秉燭競飛觴，浪語清狂勝絃管。", "探囊争出錦段新，燦燦珠璣光溢眼。"]'),
('97629923-3d6f-4c6a-9520-90524d4e7a74','曉發吳城山','歐陽澈','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','風掃陽侯雪陣平，雨摧摩詰畫圖成。',64,'全唐诗/poet.song.107000.json','["風掃陽侯雪陣平，雨摧摩詰畫圖成。", "氣吞浦溆重林盡，秋著江湖去鳥明。", "厚祿故人無一字，長年三老伴餘生。", "會須滿意開懷抱，到眼廬山不世情。"]'),
('8290c57b-82f1-4d8d-9454-884d606b4360','睢陽謁雙廟','朱松','宋','宋诗','song-poetry','','[]','幽陵胡羯殘中原，列城束手天子奔。',192,'全唐诗/poet.song.107000.json','["幽陵胡羯殘中原，列城束手天子奔。", "天留巨孽毒梁宋，賊壘環堞如雲屯。", "凶波滔天不可遏，塞以束薪何足論。", "力憑孤墉阻其怒，不爾薦食無黎元。", "堂堂許張勇且仁，指揮羸卒氣愈振。", "上書行在論賊勢，想見憤色吞妖氛。", "人間貧殘容力避，只有一死由來均。", "二公就此得處所，至今日月名爭新。", "遺祠突兀岸清洛，英氣凜冽橫穹旻。", "尚聞餘蔭福茲土，天假威柄酬忠勤。", "布衣尚懸千古淚，肉食宜鑒當年因。", "焚香再拜三歎息，九原可作從斯人。"]'),
('031f121c-4e52-482f-ae40-c1a5a9405179','謁普照塔','朱松','宋','宋诗','song-poetry','','[]','孤塔鶩霄漢，晴影金碧眩。',192,'全唐诗/poet.song.107000.json','["孤塔鶩霄漢，晴影金碧眩。", "重來得寓目，歸枕尾殘汴。", "緬懷何姓人，哀禱傾淮甸。", "是身如皎月，有水著處現。", "彈指遍大千，何止數鄉縣。", "惟應應緣地，聊爾共流轉。", "顛危悔靳馬，善涉悟覓扇。", "君看悔與悟，只在一轉盼。", "至人獨何心，示此禍福變。", "當知夙緣定，莫作邪道見。", "哀哉衆生愚，積惡稔天譴。", "云何一朝急，頼此香火薦。", "我來適燈夕，寶蠟明邃殿。", "還揩客塵眼，重睹浮壇面。", "朝來塔上鈴，告我風色便。", "平淮一回首，岸草失葱蒨。"]'),
('fc82e756-6282-4fa5-bc58-41aabf6f3acf','曉過吳縣','朱松','宋','宋诗','song-poetry','','[]','舟行有嚴程，越國常曉發。',48,'全唐诗/poet.song.107000.json','["舟行有嚴程，越國常曉發。", "雙櫓兀殘夢，起坐窺落月。", "人家岸野水，霧雨籠邃闥。", "遥憐瑣窗人，欹枕聽甌軋。"]'),
('e19c820f-abbd-4e2c-a688-072135fd4270','陪餘杭張無隅先生飲','朱松','宋','宋诗','song-poetry','','[]','先生結屋在人境，門巷蕭蕭作冰冷。',128,'全唐诗/poet.song.107000.json','["先生結屋在人境，門巷蕭蕭作冰冷。", "紛紛入眼不入意，坐客千言不相領。", "叩關聞我倒屣迎，重解舊榻塵埃生。", "向來妙處久不吐，一挽天漢崑崙傾。", "共說別來經世事，我言所向皆兒戲。", "胸中塊磊不用澆，便有清愁說無地。", "士林師範六十翁，先生合在伯仲中。", "願言終賜指歸處，爲公敬作曾南豐。"]'),
('74c5903f-61cd-4ea4-9511-7153e8f56de5','於潜道中','朱松','宋','宋诗','song-poetry','','[]','山行厭犖确，理策扶欹危。',72,'全唐诗/poet.song.107000.json','["山行厭犖确，理策扶欹危。", "綠野三兩家，一息知可期。", "冉冉晴林端，炊煙裊晴暉。", "其民豐且樂，恐是太古遺。", "那知都邑間，百索困鞭笞。", "繁華今何有，半作道旁羸。"]'),
('086fc621-29e2-4460-9f14-7c4abca17aa1','度芙蓉嶺','朱松','宋','宋诗','song-poetry','','[]','幽泉端爲誰，放溜雜琴筑。',96,'全唐诗/poet.song.107000.json','["幽泉端爲誰，放溜雜琴筑。", "山深春未老，泛泛浪蘂馥。", "娟娟菖蒲花，可玩不可觸。", "靈根盤翠崖，老作蛇蚓蹙。", "褰裳踏下流，濯此塵土足。", "何當餌香節，浄洗心眼肉。", "餘功到方書，萬卷不再讀。", "晚歲窮名山，靈苗縱穿斸。"]'),
('d408877f-9322-493e-97d4-2fad42f121fd','信州禪月臺上','朱松','宋','宋诗','song-poetry','','[]','玉峯點寥廓，霄漢疑可梯。',156,'全唐诗/poet.song.107000.json','["玉峯點寥廓，霄漢疑可梯。", "玉水環城陰，灧灧方拍隄。", "層臺擅二美，吾策一時携。", "何當蠟吾屐，更欲照以犀。", "塵勞不相赦，竟類窮途迷。", "我生麋鹿爾，不羨駕輅驪。", "向來丘壑懷，語發人所詆。", "長安黑頭公，玉勒朝金閨。", "山林出戲言，廣已無端倪。", "誰收遮日手，歸把耕雨犂。", "紛紛塵土中，等是舞甕鷄。", "頗聞山水間，幽子飯藿藜。", "行當踐此語，絕境同攀躋。"]'),
('5a647c88-1d15-4ac6-9fda-6265aca45c9f','送深師住妙香寺元住雲溪','朱松','宋','宋诗','song-poetry','','[]','道人捨幽居，誰管溪上雲。',108,'全唐诗/poet.song.107000.json','["道人捨幽居，誰管溪上雲。", "此身自雲耳，遑暇南北分。", "頗聞妙香山，天花雨繽紛。", "宴坐丈室間，歷亂舊衲紋。", "山前路悠悠，山後水汶汶。", "應觀川途客，念我奔走勤。", "豈無香火緣，他年往相群。", "飽食跛鐺飯，稀摘幽澗芹。", "當令桃花臺，白社掩前薰。"]'),
('ca495dec-99e4-4d0c-8ef1-6c8239859b7c','坐睡','朱松','宋','宋诗','song-poetry','','[]','坐久睡屢兀，手失未了書。',96,'全唐诗/poet.song.107000.json','["坐久睡屢兀，手失未了書。", "清風脫然至，心醒得我娛。", "起看孤隙光，了不移錙銖。", "云何短夢中，萬境生須臾。", "嗟彼市朝子，百巧營其軀。", "安知非夢役，過眼滅無餘。", "至人有達觀，那與世賢愚。", "不須無言子，同上崑崙墟。"]'),
('36010e81-2160-45fc-a1fa-e9f70d912b63','遊山光寺','朱松','宋','宋诗','song-poetry','','[]','寺藏兩山腹，路轉百步陰。',96,'全唐诗/poet.song.107000.json','["寺藏兩山腹，路轉百步陰。", "登高試病脚，掬冷清煩襟。", "敗壁龕石刻，歲月不可尋。", "唯應查公石，俛仰閲古今。", "屋古困枝柱，摧頹力難任。", "何當咄嗟辦，嗣彼鐘梵音。", "興衰豈關吾，得酒且滿斟。", "歸路有溪月，攬之醒吾心。"]'),
('c44df597-1b50-4d6e-b3ed-328bb3bd5ed9','送建州徐生','朱松','宋','宋诗','song-poetry','','[]','人羈天地間，誰非一浮萍。',72,'全唐诗/poet.song.107000.json','["人羈天地間，誰非一浮萍。", "泛然偶相值，便有離合情。", "君家武夷下，歸路塵眼明。", "我生愛山者，夢寐秀色橫。", "秋風送客去，把手更心傾。", "亦逢山中人，爲我寄此聲。"]'),
('e4f89736-0d83-4aa0-a5a9-742a3d877a56','贈覺師','朱松','宋','宋诗','song-poetry','','[]','覺師儒門秀，脫屣世故早。',132,'全唐诗/poet.song.107000.json','["覺師儒門秀，脫屣世故早。", "那知軒冕味，夙悟心已槁。", "唯餘章句習，心境時相惱。", "如人生於齊，而即楚鄉老。", "雖遭楚人咻，微音或清好。", "固無益生死，亦未妨至道。", "家山亦何有，骯髒衣間寶。", "叢林選佛場，一擲想盆倒。", "云何戀故居，俛仰待華皓。", "他年空手歸，子語吾爲老。", "幸分曹溪水，萬劫付一澡。"]'),
('9dfb389c-6ca8-4311-b787-01cc0e3a847d','休寧村落間有奇石如彈子渦所出者宜養石菖蒲程德藻許以餽我以詩督之','朱松','宋','宋诗','song-poetry','','[]','君家綠溪上，岸曲溪成渦。',84,'全唐诗/poet.song.107000.json','["君家綠溪上，岸曲溪成渦。", "渦間石無數，水蹙相蕩磨。", "誰嘗掬而戲，一一印指螺。", "我欲往取之，擁此菖蒲窠。", "石罌注新汲，幽姿發清哦。", "夫子許餉我，往督書已多。", "願言速寄與，起此泉石痾。"]'),
('299b7874-8791-4002-a683-221e8f137601','效淵明','朱松','宋','宋诗','song-poetry','','[]','人生本無事，况我麋鹿姿。',96,'全唐诗/poet.song.107000.json','["人生本無事，况我麋鹿姿。", "一墮世網中，永與林壑辭。", "此行獨何事，豈不爲寒饑。", "弱歲慕古人，頗覺世好卑。", "那知齒髮邁，終然此心違。", "春風到山澤，魚鳥亦知時。", "吾行何日休，流目瞻長岐。", "且用陶翁言，一觴聊可揮。"]'),
('848dc072-0797-48e2-82c8-543187a9f7f6','酬馮退翁見示之什','朱松','宋','宋诗','song-poetry','','[]','我家大江左，江水日夜東。',132,'全唐诗/poet.song.107000.json','["我家大江左，江水日夜東。", "遥瞻發源處，廼在西南窮。", "相望邈異境，正北一水通。", "故令我與子，迹遠心自同。", "我生寡所諧，强顔紅塵中。", "倦飛矯歸翮，饑吟咽寒蛩。", "獨欣得吾子，萬慮一笑空。", "時時出秀句，醒我如風松。", "當知山澤臞，不鄙犀角豐。", "彈冠實伊始，此生各飛蓬。", "卜鄰固未必，即事聊從容。"]'),
('44534fc3-e129-42ae-b6b8-ff48f3cce240','戲答胡汝能','朱松','宋','宋诗','song-poetry','','[]','我生苦中狹，與世枘鑿乖。',132,'全唐诗/poet.song.107000.json','["我生苦中狹，與世枘鑿乖。", "平生素心人，耿耿不滿懷。", "汝能伯始後，遊世如嬰孩。", "相逢握手語，便作塤箎諧。", "時時笑謂我，如子患未涯。", "執古以規今，求合誠難哉。", "涉世幸未遠，子車尚可回。", "我介足怨忌，君通絕嫌猜。", "不見山巨源，雍容居鼎台。", "不見嵇中散，絕交自可哀。", "賢愚心自了，短韻共一咍。"]'),
('c1f9b4ab-25fd-4f30-9e2c-d62e1e6be820','謁吳公路許借論衡復留一日戲作','朱松','宋','宋诗','song-poetry','','[]','幽獨不自得，駕言款齋廬。',72,'全唐诗/poet.song.107000.json','["幽獨不自得，駕言款齋廬。", "殷勤主人情，投轄恐回車。", "轄亦不須投，此去將焉如。", "唯憂酒錢盡，使我詩腸枯。", "會合曾幾何，可復自作疏。", "更當留一夕，帳中搜異書。"]'),
('ef8d1e2b-dd4b-41ca-94da-0aabf36567df','新秋','朱松','宋','宋诗','song-poetry','','[]','幽人無與娛，耳冷百不聞。',48,'全唐诗/poet.song.107000.json','["幽人無與娛，耳冷百不聞。", "新米熟未知，但覺市酒醇。", "滄洲散秋色，山水逾清新。", "一醉不忍獨，念我存故人。"]'),
('76f02dd1-4842-43d1-8da5-ad997b507bc7','道中得雨','朱松','宋','宋诗','song-poetry','','[]','我行野田間，吁嗟連數村。',48,'全唐诗/poet.song.107000.json','["我行野田間，吁嗟連數村。", "千山收宿雨，谿作黄梅渾。", "漸看風葉底，一洗龜拆痕。", "餘功被行客，稍壓旱塵昏。"]'),
('21a83170-8792-434a-bec0-44d2a8ece70e','道中','朱松','宋','宋诗','song-poetry','','[]','驕陽久自殺，一雨蕩龜拆。',144,'全唐诗/poet.song.107000.json','["驕陽久自殺，一雨蕩龜拆。", "田夫夢亦好，翻隴已幽咽。", "朝來喜相語，一飽心已决。", "翻翻風葉亂，嫋嫋露芒白。", "去年禾欲秀，積潦滿秋澤。", "今年豈堪旱，束手就溝壑。", "我生拙謀口，藜藿甘如蜜。", "向來真過計，憂民豈吾職。", "赤子天可憐，嗟人獨何力。", "何須事兒戲，合沓來賀客。", "稍欣新稻熟，社酒行可覓。", "當同扶路翁，醉歸舞南陌。"]'),
('15d129ef-a6bd-41db-b53a-6e0c8d0d0639','陳伯辨爲張氏求醉賓軒詩','朱松','宋','宋诗','song-poetry','','[]','前年谿上秋風時，主人酒熟烹黄雞。',128,'全唐诗/poet.song.107000.json','["前年谿上秋風時，主人酒熟烹黄雞。", "歸來醉倒睡便著，父老喚起牛羊蹊。", "此生一醉寧易得，未辨身爲貴人客。", "征西將軍爾何人，那用尊前驚墮幘。", "朅來閩越再經秋，聞道軒名涎已流。", "懸知得酒推不去，此客有轄何須投。", "今我正爲奔走役，空想題詩滿高壁。", "若逢落魄姓回人，爲問何時定相覓。"]'),
('5e2f5dcc-265b-4b38-b48b-312949814367','書窗對月','朱松','宋','宋诗','song-poetry','','[]','天公自厭雨，一夕開寒晴。',96,'全唐诗/poet.song.107000.json','["天公自厭雨，一夕開寒晴。", "霜風凈曠野，洪落有餘聲。", "饑鴉得林靜，霽月縈窗生。", "熨開睡眼色，一洗空花橫。", "故人千里餘，壺濁誰與傾。", "遥知勸影盃，共此通夕情。", "今冬有奇事，三見非玉英。", "明年谿上路，誰餉雨中耕。"]'),
('4a63401f-77fe-4976-93c4-a2361012f705','宿野人家','朱松','宋','宋诗','song-poetry','','[]','夢裏滄波摇一葉，覺來正受肩輿兀。',64,'全唐诗/poet.song.107000.json','["夢裏滄波摇一葉，覺來正受肩輿兀。", "人家一宿晚可投，新席槁梧香更滑。", "霜前䆉䅉收百畝，稚子新能牧鵞鴨。", "我生本是箇中人，挾策久矣猶能說。"]'),
('d8a94e88-7976-4e6f-9593-25ad76747ba4','度石棟嶺','朱松','宋','宋诗','song-poetry','','[]','我行欲安適，束馬踰山樊。',96,'全唐诗/poet.song.107000.json','["我行欲安適，束馬踰山樊。", "谷深不可瞬，危磴爭猱猿。", "坡坨兩山間，寂歷三家村。", "茅簷青裙婦，蓬髮薪烟昏。", "敲冷那可飲，分我一掬溫。", "郎樵晚未歸，客至不與言。", "不奉沙頭巵，肯投柳下門。", "作詩配國風，行者式其藩。"]'),
('cc4f3e0d-9c3a-4212-91c8-fa86d24632d5','用退之韻賦新霽','朱松','宋','宋诗','song-poetry','','[]','春泥窘幽步，苔上屐痕少。',72,'全唐诗/poet.song.107000.json','["春泥窘幽步，苔上屐痕少。", "新晴一褰衣，綠葉藏啼鳥。", "方塘灧宿漲，古鏡窺清曉。", "華顛忽自笑，綵羽墮驚矯。", "瞻言雲中耕，縹緲穹脊繞。", "歸把東臯犂，此念何日了。"]'),
('fbb910ea-189b-4a30-9a25-259c34210e86','送金確然歸弋陽','朱松','宋','宋诗','song-poetry','','[]','昔我雲溪居，送子雲溪濆。',120,'全唐诗/poet.song.107000.json','["昔我雲溪居，送子雲溪濆。", "重來問何時，笑指谿上雲。", "一別四周星，坐此世故紛。", "衰顔兩非昔，華髮粲可耘。", "我纏風樹悲，終日無一欣。", "子乃水菽憂，尚此奔走勤。", "對牀語未終，懸知便離分。", "霜風吹客袂，別意如絲棼。", "子歸葛陂上，去路接鄉枌。", "歸夢尚隨子，何當歎離群。"]'),
('6c96cf08-2313-41a1-8a18-7f813e477c0b','至節日建州會詹士元','朱松','宋','宋诗','song-poetry','','[]','嗟予身百憂，佳節過倥傯。',120,'全唐诗/poet.song.107000.json','["嗟予身百憂，佳節過倥傯。", "客愁隨綫增，歸思與灰動。", "當年從子日，未覺百慮重。", "高堂遶牀呼，一擲有餘勇。", "那知客天涯，相對寒骨聳。", "歲月曾幾何，鬢絲今種種。", "忍饑山藥煮，附煖地爐擁。", "深藏斷還往，衰病脫拜拱。", "興言望鄉關，雲物方鬰滃。", "空餘相屬意，盃酒久不捧。"]'),
('4ed27d83-54f7-42d1-a6f4-ce0871bbc270','用前韻答翁子靜','朱松','宋','宋诗','song-poetry','','[]','客心既岑寂，節物亦倥傯。',120,'全唐诗/poet.song.107000.json','["客心既岑寂，節物亦倥傯。", "幽籬菊初暗，深壑梅已動。", "古人傲尺璧，顧謂寸陰重。", "欲從夫子遊，掣肘愧不勇。", "松高節磊砢，鶴老格清聳。", "當知山澤臞，誰羨將相種。", "一官戲人間，叢書以自擁。", "微言聞緒餘，三歎手輒拱。", "青天本寥廓，不受雲霧滃。", "願言瞻清明，茗碗不辭捧。"]'),
('fc586027-30da-44b9-84e9-f565d9891dd1','微雨','朱松','宋','宋诗','song-poetry','','[]','端居身百憂，况乃貧病俱。',72,'全唐诗/poet.song.107000.json','["端居身百憂，况乃貧病俱。", "天公頗相哀，雨我蔬藥區。", "曉晴新青勻，日薄生意蘇。", "衛生固未必，一飽行可圖。", "故園天一涯，茅荆誰爲鋤。", "崢嶸歲云晚，此念當何如。"]'),
('4e909ad7-a712-4c1b-9bca-28bae57566e9','寄題叔父池亭','朱松','宋','宋诗','song-poetry','','[]','一壑久藏勝，數椽忽開亭。',120,'全唐诗/poet.song.107000.json','["一壑久藏勝，數椽忽開亭。", "方塘蔭瓦影，凈見魴鯉行。", "主人有嘉招，轉柁失高城。", "不知幾摇兀，杙舟上崢嶸。", "尊酒酌芳淥，園蔬煮柔青。", "翩翩射鴨弓，一笑翻綵翎。", "那知海陬姪，斗粟忘歸耕。", "餘生信萍梗，歸夢識林坰。", "漲水有回波，故鄉豈無情。", "一醉會有日，因之濯塵纓。"]'),
('a0db3d34-9615-4ef0-a4ed-524c150f4626','贈謝彥翔建安人九歲異人與藥至今不食建安有梅子真升仙處','朱松','宋','宋诗','song-poetry','','[]','我本世味薄，寸田足自營。',120,'全唐诗/poet.song.107000.json','["我本世味薄，寸田足自營。", "年來荆棘盡，稍有梨棗萌。", "但恐骨相凡，未敢希長生。", "陳留達人後，未齓犀角盈。", "舊遊記三山，幽夢徹九清。", "爾來三十年，但覺膏粱腥。", "幽尋飯綠髓，默卧誦黄庭。", "顧我塵土中，深慰夙心傾。", "仙人吳門卒，解后煩寄聲。", "相期朝金闕，鶴馭何時征。"]'),
('c33f29c2-67c3-49d7-bb26-fe043c4c7999','考亭陳國器以家釀餉吾友人卓民表民表以飲予香味色皆清絕不可名狀因爲製名曰武夷仙露仍賦一首','朱松','宋','宋诗','song-poetry','','[]','二年飲水閩中村，忽見玉醴傾蠻尊。',160,'全唐诗/poet.song.107000.json','["二年飲水閩中村，忽見玉醴傾蠻尊。", "涓涓醍醐灌熱惱，耿耿沆瀣明朝暾。", "旱塵久漲城市暗，渴夢欲挽江湖吞。", "何人遠致雙鯉信，知我來扣羅雀門。", "不須邀月已清絕，尚恐熨齒當微溫。", "要從華池汲真液，豈獨玄鬢薅愁根。", "微芒已識投轄客，娬媚似返當壚魂。", "奇功誰續伯倫頌，妙意要與淵明論。", "胸中我自有涇渭，筆下君已傾崑崙。", "詩成寄與約他日，飲君與我空瓶盆。"]'),
('206b5524-1b2f-4038-a0a6-3b9f80a69fc8','久旱新歲乃雨','朱松','宋','宋诗','song-poetry','','[]','高田土可篩，下田不受犂。',144,'全唐诗/poet.song.107000.json','["高田土可篩，下田不受犂。", "遺蝗憂插啄，况乃麥未齊。", "赤子天自憐，溝壑忍見擠。", "雨逐新歲來，停雲忽凄凄。", "莫辭三日霖，爲作一尺泥。", "汪汪既沒膝，灧灧仍拍隄。", "漸看簑笠出，笑語喧畛畦。", "我欲與寓目，父老同攀躋。", "此身群萬生，擾擾舞甕雞。", "曾亦無幾求，脫粟配羹藜。", "永言故隴耕，老眼路凄迷。", "好收歛版手，鋤耰歸自携。"]'),
('d45617ab-29b4-4373-b340-d336287c68af','春日與卓民表陳國器步出北郊','朱松','宋','宋诗','song-poetry','','[]','灼灼桃吐華，濯濯柳垂縷。',96,'全唐诗/poet.song.107000.json','["灼灼桃吐華，濯濯柳垂縷。", "芳菲挽人出，春力乃如許。", "嗟予閉門客，佳節過不數。", "不因可人呼，那得幽步舉。", "客如山陰勝，詩作斜川語。", "誰言一尊酒，妙處合千古。", "歸來讀殘書，耿耿霜月苦。", "空餘流落心，三歎非吾土。"]'),
('56c0c017-b13a-4b77-a57f-26f969bd5697','蔬飯','朱松','宋','宋诗','song-poetry','','[]','蕨拳嬰兒手，笋解籜龍蛻。',120,'全唐诗/poet.song.107000.json','["蕨拳嬰兒手，笋解籜龍蛻。", "薦羞杞菊開，采斸烟雨外。", "嗟予飯藜藿，咽塞舟泝瀨。", "朝來二美兼，一飽良已泰。", "充腸我誠足，染指客應慨。", "平生食肉相，蕭瑟何足頼。", "王郎催牛炙，韓老憶鯨鱠。", "俠氣信雄夸，戲語亦狡獪。", "我師魯顔子，陋巷翳蓬艾。", "執瓢不可從，一取清泉酹。"]'),
('e313cb28-0041-4824-8055-ed2cd7ba53cd','戲贈吳知伯','朱松','宋','宋诗','song-poetry','','[]','條侯得劇孟，吳楚坐可馘。',168,'全唐诗/poet.song.107000.json','["條侯得劇孟，吳楚坐可馘。", "我知無能爲，失此一敵國。", "偉哉奇男子，俠氣橫八極。", "書生復何者，骯髒老筆墨。", "刺口論安危，事往竟何益。", "匹夫嘯空野，驚塵一方塞。", "區區空有意，浩蕩洗鋒鏑。", "何如吳王孫，語輒面浮赤。", "交游得朱亥，負販鄙膠鬲。", "腰間鐵絲箭，上鏃紫塞翮。", "笑指蛇豕區，滅此而後食。", "諸公未備知，欲薦恨無力。", "明日我過君，烹牛呼社客。", "當書游俠傳，令子姓名白。"]'),
('dc6c23df-3c98-4193-9319-81ccc51ae61d','送僧','朱松','宋','宋诗','song-poetry','','[]','空中世界紛河沙，不知底處爲天涯。',128,'全唐诗/poet.song.107000.json','["空中世界紛河沙，不知底處爲天涯。", "乾坤百億在指掌，觸處與子同一家。", "云何猶作去來想，千里一跌毫釐差。", "坐令契闊費星紀，嶺雲欲寄山川遐。", "撥眉相對此何日，丈室凈掃餘天花。", "詩豪辨舌久投閣，萬竅寂歷風無譁。", "爲君遊戲出三昧，妙處那復相聱牙。", "往將妙響應空谷，一任飛錫凌蒼霞。"]'),
('8feed899-d161-443b-b33c-79484553eb91','招民表','朱松','宋','宋诗','song-poetry','','[]','清眠有味日方永，褦襶妨人推不省。',176,'全唐诗/poet.song.107000.json','["清眠有味日方永，褦襶妨人推不省。", "疾草尺書招故人，一水未濟豈非命。", "此身何啻千金直，天下未可兩臂等。", "垂堂之戒其敢忘，晚識風波失前猛。", "天憐我輩少如意，曉起屋梁飛倒景。", "側身鳥行溪上路，遥知倚筇喚烟艇。", "信眉相對真夢寐，豈不惜此一笑傾。", "莫談世事令舌强，快讀新詩頻首肯。", "與君好惡真磁鐵，失足塵途若爲騁。", "北窗風月夜吞吐，持此邀君共幽屏。", "浄洗多生內熱塵，更有僧廬千尺井。"]'),
('70ccf5e6-f77e-446e-8c96-60af06487468','秋懷十首  其一','朱松','宋','宋诗','song-poetry','','[]','秋風來幾日，我髮白已多。',48,'全唐诗/poet.song.107000.json','["秋風來幾日，我髮白已多。", "千林了未覺，奈此一葉何。", "宴坐閲流光，一盼寄庭柯。", "寒蟲獨何者，唧唧夜自歌。"]'),
('afd58330-5c49-4f76-9489-688771290796','秋懷十首  其二','朱松','宋','宋诗','song-poetry','','[]','塵埃地上臣，天闕無力補。',48,'全唐诗/poet.song.107000.json','["塵埃地上臣，天闕無力補。", "夜叉呵九關，嘗膽真自苦。", "寄牋東南風，儻得蜚廉許。", "尚當求妙斲，君氏無乃魯。"]'),
('c8dac9a5-740e-4bb3-a422-96d0903fc075','秋懷十首  其三','朱松','宋','宋诗','song-poetry','','[]','蒔蘭西窗下，蕭艾病其根。',48,'全唐诗/poet.song.107000.json','["蒔蘭西窗下，蕭艾病其根。", "白露墮秋夕，美惡兩不存。", "寂寂芳畹空，離離幽佩昏。", "物各信所遭，此意誰與論。"]'),
('c7791a3f-ce14-44c6-9e23-46848092c18d','秋懷十首  其四','朱松','宋','宋诗','song-poetry','','[]','月林疏愈明，露草浄可拭。',72,'全唐诗/poet.song.107000.json','["月林疏愈明，露草浄可拭。", "飛飛螢遞照，軋軋蟲自織。", "移燈檢書讀，千載如經夕。", "微言契夙心，妙解失陳迹。", "文章事雕琢，回視真兒劇。", "世無揚子雲，此理誰見直。"]'),
('7be5e903-85ea-4a29-a49c-ab5134741306','秋懷十首  其五','朱松','宋','宋诗','song-poetry','','[]','宴坐自觀我，中深抱天機。',48,'全唐诗/poet.song.107000.json','["宴坐自觀我，中深抱天機。", "從知月勝火，胥失兔與蹄。", "大虛同一如，浮雲渺何依。", "悠然淵明心，千載與我期。"]');
